-- Part 5 (200 recipes)
insert into public.recipes (id, doc, status) values ('eggplant_parmesan_bake', '{"id":"eggplant_parmesan_bake","name":"Skillet-to-Oven Eggplant Parmesan","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":75,"servings":4,"ing":[{"f":"eggplant","q":2},{"f":"flour","q":60},{"f":"eggs","q":2},{"f":"bread","q":2},{"f":"olive_oil","q":60},{"f":"crushed_tomatoes","q":500},{"f":"mozzarella","q":200},{"f":"parmesan","q":40},{"f":"garlic","q":0.3},{"f":"basil","q":0.5},{"f":"oregano","q":2},{"f":"salt","q":6},{"f":"black_pepper","q":1}],"steps":["Slice the eggplants into 1-centimeter rounds, salt them on both sides, and let them weep on a rack for 20 minutes before blotting dry; toast the bread until brittle and blitz or crush it into fine crumbs.","Simmer the crushed tomatoes with the minced garlic and oregano for 10 minutes until slightly thickened, then heat the oven to 200C.","Dredge each eggplant round in flour, dip in beaten egg, press into the breadcrumbs, and shallow-fry in olive oil over medium heat for 3 minutes per side until deeply golden and crisp at the edges.","Layer a baking dish with sauce, eggplant, torn basil, mozzarella, and parmesan, repeating until everything is used and finishing with a snowy cheese layer.","Bake for 25 minutes until the top is blistered and bronzed and the sauce bubbles up the sides, then rest 10 minutes so the layers set instead of sliding."],"tip":"Salting the eggplant is the difference between silky layers and a dish that tastes like a wet sponge with ambitions."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_baked_penne', '{"id":"turkey_baked_penne","name":"Baked Penne with Turkey and Ricotta","emoji":"🧀","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":55,"servings":4,"ing":[{"f":"ground_turkey","q":450},{"f":"penne","q":280},{"f":"crushed_tomatoes","q":600},{"f":"ricotta","q":200},{"f":"mozzarella","q":125},{"f":"parmesan","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":15},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 190C and set a big pot of salted water to boil for the penne, cooking it 2 full minutes short of the package time so it stays sturdy through the bake.","Brown the ground turkey in olive oil over medium-high heat for 6 minutes, then add the diced onion and garlic and cook until soft and sweet-smelling, about 4 minutes more.","Stir in the crushed tomatoes, oregano, salt, and pepper and simmer 10 minutes until the sauce turns a deep brick red.","Fold the drained penne into the sauce along with dollops of ricotta, leaving visible creamy pockets rather than stirring them smooth.","Scrape into a baking dish, top with mozzarella and parmesan, and bake 20 minutes until the cheese is molten with browned freckles; scatter torn basil over the top before serving."],"tip":"Undercooked pasta going into the oven is correct pasta — it finishes cooking in the sauce instead of turning to mush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_pizzaiola', '{"id":"pork_pizzaiola","name":"Pork Pizzaiola","emoji":"🍅","cuisine":"Italian","meal":["dinner"],"diets":["high-protein","low-carb","gluten-free","dairy-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"crushed_tomatoes","q":300},{"f":"olives","q":40},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Slice the pork loin into 4 thin cutlets, pound them gently to even thickness, and season both sides with salt and pepper.","Sear the cutlets in olive oil over high heat for 2 minutes per side until golden at the edges but not cooked through, then move them to a plate.","Soften the sliced onion in the same pan for 3 minutes, add the garlic and oregano for 30 seconds, then pour in the crushed tomatoes and the olives and scrape up the browned bits.","Simmer the sauce 8 minutes until it thickens and turns glossy, then slide the pork back in with its juices and braise gently for 4 minutes, just until the cutlets are cooked through but still juicy.","Spoon the herby red sauce over the top and finish with torn basil."],"tip":"Thin cutlets overcook in the time it takes to find your phone, so pull them the moment they lose their blush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_white_bean_pomodoro', '{"id":"tuscan_white_bean_pomodoro","name":"Tuscan White Beans in Tomato Sugo","emoji":"🫘","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":4,"ing":[{"f":"white_beans","q":700},{"f":"crushed_tomatoes","q":500},{"f":"kale","q":0.8},{"f":"carrots","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"oregano","q":3},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a heavy pot over medium heat and sweat the diced onion and carrots with a pinch of salt for 8 minutes, until soft and just beginning to color.","Add the sliced garlic and oregano and stir for 1 minute until the oil smells like an Italian grandmother''s kitchen.","Pour in the crushed tomatoes plus a splash of water, bring to a lazy simmer, and cook 10 minutes so the sauce loses its metallic edge and sweetens.","Stir in the white beans and stripped, torn kale and simmer 8 minutes more, mashing a spoonful of beans against the pot wall to thicken the broth to a creamy, stew-like body.","Season boldly with salt and pepper and finish each bowl with a defiant extra drizzle of olive oil."],"tip":"Mashing a few beans is free thickener — no cream, no flour, no regrets."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spaghetti_puttanesca', '{"id":"spaghetti_puttanesca","name":"Pantry Spaghetti Puttanesca","emoji":"🫒","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":160},{"f":"crushed_tomatoes","q":350},{"f":"olives","q":80},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"chili_powder","q":2},{"f":"oregano","q":2},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Set the spaghetti boiling in aggressively salted water while you build the sauce, since this dish moves fast.","Warm the olive oil with the sliced garlic and chili powder in a wide pan over medium heat for 2 minutes, until the garlic turns pale gold and the oil is stained brick red.","Add the roughly chopped olives and oregano, sizzle 1 minute, then pour in the crushed tomatoes and simmer 8 minutes until the sauce is thick, briny, and unapologetic.","Drag the spaghetti from its pot straight into the pan a minute early, add a ladle of pasta water, and toss vigorously over the heat until the strands are lacquered.","Shower with chopped parsley, grind over black pepper, and serve immediately while it still steams."],"tip":"Taste before salting — the olives arrived at this party pre-seasoned and they are not shy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('classic_chicken_parmesan', '{"id":"classic_chicken_parmesan","name":"Crispy Chicken Parmesan","emoji":"🍽️","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"chicken_breast","q":400},{"f":"flour","q":40},{"f":"eggs","q":1},{"f":"bread","q":2},{"f":"olive_oil","q":30},{"f":"crushed_tomatoes","q":300},{"f":"mozzarella","q":80},{"f":"parmesan","q":30},{"f":"garlic","q":0.2},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Toast the bread until dry and shatter it into fine crumbs, mixing in half the parmesan; halve each chicken breast horizontally and pound to an even 1-centimeter thickness.","Simmer the crushed tomatoes with minced garlic and oregano for 10 minutes while you set up a dredging line of seasoned flour, beaten egg, and the cheesy crumbs.","Coat each cutlet fully — flour, egg, crumbs, pressing firmly — then pan-fry in olive oil over medium-high heat for 3 minutes per side until the crust is deep golden and audibly crisp.","Top each cutlet with a spoonful of sauce, the mozzarella, and remaining parmesan, then slide under a hot broiler for 3 minutes until the cheese bubbles and browns in spots.","Serve on a pool of the remaining sauce with torn basil, cutting in to hear that crunch give way to juicy chicken."],"tip":"Sauce goes on in a modest stripe, not a flood — drowned breading is a crime the Italians prosecute vigorously."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lentil_bolognese_spaghetti', '{"id":"lentil_bolognese_spaghetti","name":"Lentil Bolognese with Spaghetti","emoji":"🌱","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","high-protein"],"allergens":["gluten"],"time":50,"servings":4,"ing":[{"f":"lentils_dry","q":250},{"f":"spaghetti","q":300},{"f":"crushed_tomatoes","q":500},{"f":"carrots","q":100},{"f":"celery","q":60},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":30},{"f":"oregano","q":3},{"f":"basil","q":0.3},{"f":"salt","q":6},{"f":"black_pepper","q":2}],"steps":["Finely dice the onion, carrots, and celery and sweat them in olive oil over medium heat for 10 minutes, until soft, sweet, and lightly golden — this soffritto is the soul of the sauce, so do not rush it.","Stir in the minced garlic and oregano for 1 minute, then add the rinsed lentils, crushed tomatoes, and 700 milliliters of water.","Simmer uncovered over low heat for 30 minutes, stirring occasionally, until the lentils are tender and the sauce has thickened to a proper ragu that mounds on a spoon.","Cook the spaghetti in salted boiling water until al dente, reserving a cup of the starchy water before draining.","Toss the pasta with the lentil bolognese and enough pasta water to make it glossy, season assertively, and top with torn basil."],"tip":"Lentils drink salt like they have been lost in the desert, so season at the end and taste twice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_polpette_al_sugo', '{"id":"beef_polpette_al_sugo","name":"Beef Polpette in Sunday Sauce","emoji":"🥩","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"eggs","q":1},{"f":"bread","q":1},{"f":"parmesan","q":25},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"oregano","q":2},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Soak the torn bread in a splash of water until soggy, squeeze it out, and knead it gently with the beef, egg, parmesan, half the parsley, a little minced garlic, salt, and pepper — stop the moment it comes together.","Roll the mixture into 8 golf-ball meatballs with damp hands and brown them in olive oil over medium-high heat for about 6 minutes, turning until crusted on most sides but still raw inside.","Push the meatballs aside, soften the diced onion and remaining garlic in the drippings for 3 minutes, then pour in the crushed tomatoes and oregano.","Cover partially and simmer over low heat for 20 minutes, turning the meatballs once, until they are tender all the way through and the sauce has thickened and gone brick red.","Rest 5 minutes off the heat, then serve the polpette blanketed in sauce with the rest of the parsley on top."],"tip":"Overworked meatballs bounce; mix like you are folding laundry you actually care about."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggs_in_purgatory', '{"id":"eggs_in_purgatory","name":"Eggs in Purgatory","emoji":"🍳","cuisine":"Italian","meal":["breakfast","dinner"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"crushed_tomatoes","q":400},{"f":"bread","q":2},{"f":"parmesan","q":20},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"chili_powder","q":3},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a skillet over medium heat and soften the diced onion for 4 minutes, then add the sliced garlic, chili powder, and oregano and stir until the oil turns rusty and fragrant.","Pour in the crushed tomatoes with a pinch of salt and simmer 8 minutes, until the sauce thickens enough that a spoon leaves a brief trail.","Make four wells in the sauce with the back of the spoon and crack an egg into each, seasoning the yolks with salt and pepper.","Cover and cook over low heat for 5 to 7 minutes, until the whites are just set but the yolks still shimmy when you shake the pan.","Shower with parmesan and torn basil and serve with thick toasted bread for dragging through the fiery sauce."],"tip":"The pan-shake wobble test beats any timer — set whites, liquid gold yolks, no exceptions."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tomato_basil_risotto', '{"id":"tomato_basil_risotto","name":"Tomato-Basil Risotto","emoji":"🍚","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"rice","q":180},{"f":"crushed_tomatoes","q":300},{"f":"butter","q":25},{"f":"parmesan","q":40},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"basil","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":1}],"steps":["Keep a kettle of about 1 liter of hot salted water at the ready, and warm the crushed tomatoes in a small pan so nothing cold shocks the rice.","Sweat the finely diced onion in olive oil over medium heat for 4 minutes until translucent, then stir in the garlic and the rice and toast 2 minutes until the grains turn pearly and click against the pan.","Add the warm tomatoes and stir until absorbed, then begin adding hot water one ladle at a time, stirring often and waiting until each addition is nearly drunk up before the next — about 18 to 20 minutes total.","Taste at the 18-minute mark: the rice should be tender with a faint chalky whisper at the center and the whole pot should flow like slow lava.","Off the heat, beat in the butter and parmesan hard for 30 seconds until the risotto turns glossy and creamy, then fold in torn basil and serve immediately in warm bowls."],"tip":"Risotto waits for no one — call everyone to the table before the final stir, not after."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ricotta_gnudi_lemon_butter', '{"id":"ricotta_gnudi_lemon_butter","name":"Ricotta Gnudi with Lemon-Basil Butter","emoji":"🥟","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["dairy","gluten","eggs"],"time":40,"servings":2,"ing":[{"f":"ricotta","q":350},{"f":"parmesan","q":50},{"f":"flour","q":60},{"f":"eggs","q":1},{"f":"butter","q":40},{"f":"spinach","q":100},{"f":"lemon","q":1},{"f":"basil","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Spread the ricotta on a paper-towel-lined plate for 10 minutes to wick away moisture, because wet ricotta makes gummy gnudi.","Stir the drained ricotta with the egg, grated parmesan, a pinch of salt, and just enough flour to form a soft, barely-holds-itself dough, then roll it into 16 walnut-sized balls with floured hands.","Slide the gnudi into a wide pot of gently simmering salted water and poach for 3 to 4 minutes, scooping them out with a slotted spoon about 30 seconds after they bob to the surface.","Meanwhile, melt the butter in a large skillet over medium heat and let it foam and turn hazelnut-brown and nutty-smelling, about 3 minutes, then wilt in the spinach and torn basil.","Tumble the gnudi into the brown butter, add a squeeze of lemon juice and a little grated zest, and swirl the pan until each dumpling is glossy.","Serve immediately with black pepper and the remaining parmesan showered over the top."],"tip":"If your first test gnudi dissolves in the water, add a spoonful more flour to the dough and forgive yourself."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_ricotta_asparagus_spaghetti', '{"id":"lemon_ricotta_asparagus_spaghetti","name":"Lemon Ricotta Spaghetti with Asparagus","emoji":"🍝","cuisine":"Italian","meal":["lunch","dinner"],"diets":["vegetarian","high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":180},{"f":"ricotta","q":200},{"f":"parmesan","q":40},{"f":"asparagus","q":250},{"f":"olive_oil","q":20},{"f":"garlic","q":0.2},{"f":"lemon","q":1},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Boil the spaghetti in aggressively salted water until just shy of al dente, about 9 minutes, and reserve a full cup of the starchy cooking water before draining.","While the pasta cooks, snap the woody ends off the asparagus, slice the spears on the bias into bite-sized pieces, and sizzle them in olive oil with the sliced garlic over medium-high heat until crisp-tender and lightly blistered, 3 to 4 minutes.","In a large bowl, whisk the ricotta with most of the parmesan, the lemon zest, half the lemon''s juice, and enough hot pasta water to loosen it into a silky, pourable cream.","Add the drained spaghetti and asparagus to the bowl and toss vigorously, adding splashes of pasta water until the sauce clings to every strand like a light satin robe.","Taste for salt and lemon, then plate with the remaining parmesan and a heavy grind of black pepper."],"tip":"The ricotta sauce tightens as it sits, so keep that pasta water within arm''s reach like a fire extinguisher."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_ricotta_polpette_marinara', '{"id":"turkey_ricotta_polpette_marinara","name":"Turkey-Ricotta Polpette in Marinara","emoji":"🧆","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":2,"ing":[{"f":"ground_turkey","q":300},{"f":"ricotta","q":80},{"f":"parmesan","q":25},{"f":"eggs","q":1},{"f":"bread","q":1},{"f":"milk","q":40},{"f":"spaghetti","q":120},{"f":"crushed_tomatoes","q":400},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"basil","q":0.3},{"f":"oregano","q":1},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Tear the bread into bits, soak it in the milk for 5 minutes, then mash it to a paste with a fork.","Gently combine the turkey, ricotta, egg, parmesan, bread paste, half the minced garlic, oregano, salt, and pepper, mixing only until it just comes together, then roll into 10 plump meatballs with damp hands.","Brown the polpette in olive oil in a wide skillet over medium-high heat until deeply golden on two sides, about 5 minutes total, then move them to a plate.","Soften the diced onion and remaining garlic in the same skillet, pour in the crushed tomatoes, and simmer for 5 minutes before nestling the meatballs back in to finish cooking gently, covered, for 12 minutes.","Boil the spaghetti in salted water until al dente, drain, and toss it with a few spoonfuls of the sauce so the strands turn rosy.","Pile the polpette and remaining sauce over the pasta and finish with torn basil and a final dusting of parmesan."],"tip":"The ricotta keeps lean turkey from turning into hockey pucks, so resist the urge to overmix the meat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('parmesan_shrimp_pea_risotto', '{"id":"parmesan_shrimp_pea_risotto","name":"Parmesan Risotto with Shrimp and Peas","emoji":"🦐","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"rice","q":180},{"f":"shrimp","q":250},{"f":"parmesan","q":40},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"broth","q":900},{"f":"peas_frozen","q":100},{"f":"lemon","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Warm the broth in a saucepan and keep it at a bare steam on a back burner; cold broth shocks risotto into stubbornness.","Sweat the finely diced onion in olive oil and half the butter in a heavy pot over medium heat until translucent, about 4 minutes, then stir in the garlic and rice and toast until the grains turn pearly at the edges and smell faintly nutty.","Add the hot broth a ladleful at a time, stirring often and waiting until each addition is nearly absorbed before the next, about 20 minutes, until the rice is creamy but still has a whisper of bite at its center.","Stir in the peas and the shrimp for the final 4 minutes, cooking just until the shrimp curl into loose commas and turn opaque pink.","Pull the pot off the heat and beat in the remaining butter, the parmesan, and a squeeze of lemon until the risotto ripples like slow lava when you shake the pot.","Season, then serve immediately in warm shallow bowls with black pepper."],"tip":"Risotto waits for no one — call everyone to the table before you stir in the parmesan, not after."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_ricotta_crespelle', '{"id":"spinach_ricotta_crespelle","name":"Spinach and Ricotta Crespelle","emoji":"🥞","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","high-protein"],"allergens":["dairy","gluten","eggs"],"time":50,"servings":2,"ing":[{"f":"flour","q":80},{"f":"eggs","q":2},{"f":"milk","q":200},{"f":"butter","q":15},{"f":"ricotta","q":250},{"f":"spinach","q":200},{"f":"parmesan","q":40},{"f":"mozzarella","q":40},{"f":"crushed_tomatoes","q":200},{"f":"garlic","q":0.2},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Whisk the flour, eggs, milk, and a pinch of salt into a thin, lump-free batter and let it rest for 15 minutes while you make the filling.","Wilt the spinach with the garlic in a knob of the butter over medium heat, squeeze it bone-dry once cool, chop it, and fold it into the ricotta with half the parmesan, salt, and pepper.","Swirl a little butter in a nonstick skillet over medium heat and cook the batter into 6 thin crepes, about 1 minute per side, until freckled gold and floppy.","Heat the oven to 200C, spread a spoonful of crushed tomatoes over a baking dish, then roll each crespella around a generous ribbon of filling and lay them seam-side down in a snug row.","Spoon the remaining tomatoes over the top, scatter with mozzarella and the last of the parmesan, and bake for 15 minutes until the cheese bubbles and the edges crisp.","Rest for 5 minutes before serving so the filling settles from molten to merely luxurious."],"tip":"Your first crepe is legally the cook''s snack, so budget the batter accordingly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_ricotta_frittata', '{"id":"mushroom_ricotta_frittata","name":"Mushroom and Ricotta Frittata","emoji":"🍳","cuisine":"Italian","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"ricotta","q":120},{"f":"parmesan","q":30},{"f":"mushrooms","q":250},{"f":"spinach","q":100},{"f":"olive_oil","q":15},{"f":"scallions","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven''s broiler and set a rack in the upper third while you sear the sliced mushrooms in olive oil in a 25cm ovenproof skillet over high heat until their water evaporates and they turn deeply browned, about 7 minutes.","Lower the heat to medium, wilt in the spinach and sliced scallions, and season everything with salt and pepper.","Whisk the eggs with the parmesan and pour them over the vegetables, tilting the pan so the egg flows into every gap, then cook undisturbed until the edges set, about 3 minutes.","Dot the surface with spoonfuls of ricotta, pushing them halfway into the custardy top like little snowdrifts.","Slide the skillet under the broiler for 2 to 3 minutes until the frittata puffs proudly and the ricotta caps turn golden at their peaks.","Let it sit for a couple of minutes, then cut into wedges straight from the pan."],"tip":"A frittata that jiggles slightly in the center when it leaves the oven will be perfect by the time you find the plates."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_parmesan_chicken_ricotta_penne', '{"id":"creamy_parmesan_chicken_ricotta_penne","name":"Creamy Parmesan Chicken Penne","emoji":"🍗","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"penne","q":160},{"f":"chicken_breast","q":300},{"f":"ricotta","q":120},{"f":"parmesan","q":40},{"f":"olive_oil","q":15},{"f":"garlic","q":0.3},{"f":"spinach","q":100},{"f":"broth","q":120},{"f":"lemon","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Drop the penne into boiling salted water and cook until al dente, about 10 minutes, reserving a cup of pasta water before draining.","While it boils, cut the chicken into bite-sized pieces, season with salt and pepper, and sear in olive oil in a large skillet over medium-high heat until golden at the edges and just cooked through, 6 to 7 minutes.","Add the sliced garlic for the last minute until fragrant, then pour in the broth and scrape up the browned bits stuck to the pan — that fond is free flavor.","Reduce the heat to low and stir in the ricotta and parmesan with a splash of pasta water, whisking until the sauce turns pale, glossy, and smooth.","Fold in the spinach and drained penne, tossing until the leaves collapse and the sauce coats each tube, loosening with more pasta water as needed.","Brighten with a squeeze of lemon and serve with extra parmesan and black pepper."],"tip":"Keep the heat gentle once the ricotta goes in, because a boiled cheese sauce breaks faster than a New Year''s resolution."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('white_bean_parmesan_zuppa', '{"id":"white_bean_parmesan_zuppa","name":"White Bean and Parmesan Zuppa","emoji":"🍲","cuisine":"Italian","meal":["lunch","dinner"],"diets":["gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"white_beans","q":600},{"f":"broth","q":1200},{"f":"parmesan","q":60},{"f":"ricotta","q":120},{"f":"olive_oil","q":40},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.3},{"f":"kale","q":0.5},{"f":"crushed_tomatoes","q":200},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Sweat the diced onion, carrots, and celery in half the olive oil in a soup pot over medium heat until soft and sweet-smelling, about 8 minutes, then stir in the minced garlic and oregano for one fragrant minute.","Add the crushed tomatoes, white beans, and broth, bring everything to a lively simmer, and cook uncovered for 15 minutes so the flavors get acquainted.","Ladle out a cup of the soup, mash or blend it smooth, and stir it back in to give the broth a creamy, clinging body without a drop of cream.","Stir in the stripped and torn kale along with most of the grated parmesan and simmer 5 more minutes until the greens are silky but still forest-green.","Season boldly with salt and pepper, then serve each bowl crowned with a fat spoonful of ricotta, a drizzle of the remaining olive oil, and the last of the parmesan."],"tip":"The ricotta dollop melts into the hot soup as you eat, so stir it in slowly and pretend you planned the drama."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_lemon_ricotta_skillet', '{"id":"salmon_lemon_ricotta_skillet","name":"Seared Salmon with Lemon-Ricotta Cream and Green Beans","emoji":"🐟","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["fish","dairy"],"time":25,"servings":2,"ing":[{"f":"salmon","q":320},{"f":"green_beans","q":300},{"f":"ricotta","q":100},{"f":"parmesan","q":20},{"f":"lemon","q":1},{"f":"olive_oil","q":15},{"f":"butter","q":10},{"f":"garlic","q":0.2},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Pat the salmon fillets thoroughly dry, season with salt and pepper, and lay them skin-side down in hot olive oil in a heavy skillet over medium-high heat, pressing gently for 10 seconds so the skin doesn''t buckle.","Cook without moving for 5 to 6 minutes until the skin releases easily and crisps like a cracker, then flip and cook 2 minutes more before resting the fillets on a warm plate.","Add the butter, garlic, and trimmed green beans to the same skillet and saute over medium heat until the beans blister in spots but keep their snap, about 5 minutes.","Whisk the ricotta with the parmesan, lemon zest, half the lemon''s juice, a pinch of salt, and a spoonful of warm water until it loosens into a smooth, pourable cream.","Swoosh the lemon-ricotta cream across two plates, pile on the green beans, and perch the salmon on top, crispy skin skyward.","Shower with chopped parsley and finish with the remaining lemon in wedges."],"tip":"If the salmon resists when you try to flip it, it''s not stuck, it''s just not ready — give it another minute."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_ricotta_involtini', '{"id":"eggplant_ricotta_involtini","name":"Eggplant Involtini with Ricotta","emoji":"🍆","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":55,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"ricotta","q":300},{"f":"parmesan","q":40},{"f":"mozzarella","q":60},{"f":"eggs","q":1},{"f":"crushed_tomatoes","q":400},{"f":"olive_oil","q":30},{"f":"garlic","q":0.3},{"f":"basil","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 220C, slice the eggplant lengthwise into 8 thin planks, brush both sides with olive oil, season with salt, and roast on a sheet pan for 15 minutes until floppy and golden at the edges.","While the eggplant roasts, simmer the crushed tomatoes with the sliced garlic, a glug of olive oil, and a pinch of salt for 10 minutes until slightly thickened and sweet.","Stir the ricotta with the egg, most of the parmesan, torn basil, salt, and plenty of black pepper until fluffy.","Lower the oven to 190C, spread half the tomato sauce in a baking dish, then place a fat spoonful of filling at the wide end of each eggplant plank and roll it up like a sleeping bag, nestling each roll seam-side down in the sauce.","Spoon the remaining sauce over the involtini, top with torn mozzarella and the last parmesan, and bake for 20 minutes until the sauce bubbles at the edges and the cheese turns molten and spotted bronze.","Rest for 5 minutes and serve with more basil scattered over the top."],"tip":"Thin eggplant slices roll; thick ones crack and file complaints, so channel your inner deli slicer."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_ricotta_ragu_penne', '{"id":"beef_ricotta_ragu_penne","name":"Beef Ragu Penne with Ricotta","emoji":"🥩","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"penne","q":140},{"f":"crushed_tomatoes","q":300},{"f":"ricotta","q":80},{"f":"parmesan","q":30},{"f":"olive_oil","q":10},{"f":"onion","q":0.5},{"f":"carrots","q":60},{"f":"garlic","q":0.2},{"f":"oregano","q":1},{"f":"basil","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Brown the ground beef in olive oil in a wide skillet over medium-high heat, breaking it into rubble and leaving it alone long enough to develop crusty, caramelized patches, about 6 minutes.","Add the finely diced onion and carrot and cook until softened, 5 minutes, then stir in the minced garlic and oregano until fragrant.","Pour in the crushed tomatoes with a splash of water, season with salt and pepper, and simmer gently for 15 minutes until the ragu thickens enough to hold a trail when you drag a spoon through it.","Meanwhile, boil the penne in salted water until al dente, reserving a half cup of pasta water before draining.","Toss the penne through the ragu with the parmesan and enough pasta water to make everything cling, then divide between bowls.","Crown each serving with spoonfuls of cold ricotta and torn basil, letting the cheese melt lazily into the hot sauce."],"tip":"Cold ricotta on hot ragu is the poor man''s burrata, and honestly nobody at the table will investigate."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cauliflower_parmesan_ricotta_gratin', '{"id":"cauliflower_parmesan_ricotta_gratin","name":"Cauliflower Gratin with Ricotta and Parmesan","emoji":"🧀","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":45,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"ricotta","q":200},{"f":"parmesan","q":60},{"f":"milk","q":100},{"f":"eggs","q":1},{"f":"butter","q":15},{"f":"garlic","q":0.2},{"f":"parsley","q":0.3},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200C and boil the cauliflower florets in well-salted water for 5 minutes until a knife slides in with slight resistance, then drain them thoroughly — soggy florets make a weepy gratin.","Whisk the ricotta with the egg, milk, minced garlic, two-thirds of the parmesan, salt, and a generous grind of black pepper into a loose, creamy custard.","Butter a baking dish, tumble in the cauliflower in a single crowded layer, and pour the ricotta mixture over so it seeps into every crevice.","Dot the surface with the remaining butter and scatter the last of the parmesan evenly over the top.","Bake for 25 minutes until the edges bubble furiously and the top blisters into golden-brown patches that smell like toasted cheese.","Rest 5 minutes, then shower with chopped parsley and serve straight from the dish."],"tip":"The crispy corner pieces are the currency of this dish, so serve yourself first."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_parmesan_mushroom_skillet', '{"id":"pork_parmesan_mushroom_skillet","name":"Pork Medallions in Parmesan-Mushroom Cream","emoji":"🍄","cuisine":"Italian","meal":["dinner"],"diets":["gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"mushrooms","q":250},{"f":"ricotta","q":100},{"f":"parmesan","q":30},{"f":"butter","q":15},{"f":"olive_oil","q":10},{"f":"broth","q":100},{"f":"garlic","q":0.2},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Slice the pork loin into medallions about 2cm thick, pat dry, season with salt and pepper, and sear in olive oil in a hot skillet over medium-high heat for 3 minutes per side until burnished gold with a blush of pink inside, then set aside under foil.","Melt the butter in the same skillet and cook the sliced mushrooms without stirring for 3 minutes, then toss and cook 4 minutes more until browned and squeaking against the spoon.","Add the minced garlic for 30 seconds, then pour in the broth and scrape up every browned bit as it steams and reduces by half.","Lower the heat and whisk in the ricotta and parmesan until the sauce turns pale, creamy, and just thick enough to coat the mushrooms.","Return the medallions and their resting juices to the pan and warm them gently in the sauce for 2 minutes without letting it boil.","Scatter with chopped parsley and serve hot from the skillet."],"tip":"Those juices pooling under the resting pork are the sauce''s missing ingredient, not a mess to wipe up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moussaka_style_beef_eggplant_bake', '{"id":"moussaka_style_beef_eggplant_bake","name":"Weeknight Moussaka Bake","emoji":"🍆","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy","eggs"],"time":75,"servings":2,"ing":[{"f":"ground_beef","q":280},{"f":"eggplant","q":1},{"f":"potatoes","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"crushed_tomatoes","q":250},{"f":"olive_oil","q":25},{"f":"greek_yogurt","q":120},{"f":"eggs","q":1},{"f":"parmesan","q":25},{"f":"oregano","q":2},{"f":"cinnamon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 425°F, slice the eggplant and potatoes into 1/2-inch rounds, and roast them on an oiled sheet pan for 20 minutes until golden at the edges and tender in the middle.","Meanwhile, brown the ground beef with the diced onion in a skillet over medium-high heat until deeply crusty, about 8 minutes, then stir in the garlic, oregano, cinnamon, salt, and pepper until fragrant.","Pour in the crushed tomatoes and simmer 10 minutes until the sauce thickens enough that a spoon dragged through it leaves a clear trail.","Layer the potatoes, then the meat sauce, then the eggplant in a small baking dish, pressing each layer down gently.","Whisk the yogurt with the egg and most of the parmesan, spread it over the top, and bake at 400°F for 20 minutes until the topping is puffed and bronzed in spots.","Rest 10 minutes before cutting so the layers set instead of sliding apart on the plate."],"tip":"The 10-minute rest is not optional unless you enjoy eating moussaka soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('fakes_greek_lentil_soup', '{"id":"fakes_greek_lentil_soup","name":"Fakes (Greek Lentil Soup)","emoji":"🥣","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":200},{"f":"olive_oil","q":45},{"f":"balsamic_vinegar","q":20},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Warm half the olive oil in a soup pot over medium heat and sweat the diced onion, carrots, and celery for 6 to 8 minutes until soft and sweet-smelling.","Stir in the sliced garlic and oregano and cook 1 minute until the kitchen smells like a Greek grandmother''s apartment.","Add the rinsed lentils, crushed tomatoes, and about 1.2 liters of water, bring to a boil, then drop to a lazy simmer.","Cook uncovered for 30 to 35 minutes, stirring occasionally, until the lentils are creamy-tender and the broth has thickened to a spoon-coating body.","Season with salt and pepper, then finish off the heat with the remaining olive oil and the vinegar, stirring until the surface turns glossy.","Taste and add another splash of vinegar if it needs brightness; ladle into bowls while steaming."],"tip":"The vinegar at the end is the whole personality of this soup — do not skip it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('fasolada_white_bean_soup', '{"id":"fasolada_white_bean_soup","name":"Fasolada White Bean Soup","emoji":"🫘","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"white_beans","q":800},{"f":"onion","q":1},{"f":"carrots","q":200},{"f":"celery","q":150},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":300},{"f":"olive_oil","q":60},{"f":"lemon","q":1},{"f":"parsley","q":0.5},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat half the olive oil in a heavy pot over medium and cook the chopped onion, carrots, and celery for 8 minutes until the edges turn translucent and lightly golden.","Add the minced garlic and oregano, stir for 30 seconds, then pour in the crushed tomatoes and let them sizzle and darken for 3 minutes.","Tip in the beans with about 800 ml of water, season with salt and pepper, and simmer gently for 20 minutes so the flavors marry.","Mash a ladleful of beans against the side of the pot and stir it back in until the broth turns silky and slightly creamy.","Off the heat, stir in the remaining olive oil, a big squeeze of lemon, and the chopped parsley, tasting until it snaps into balance.","Serve hot with extra lemon wedges on the side for the acid-obsessed."],"tip":"This is the national dish of Greece, so resist the urge to add anything fancy — the olive oil does the talking."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pork_souvlaki_pita_wraps_2', '{"id":"pork_souvlaki_pita_wraps_2","name":"Pork Souvlaki Pitas with Tzatziki","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":40,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"pita","q":2},{"f":"greek_yogurt","q":150},{"f":"cucumber","q":0.5},{"f":"garlic","q":0.3},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"oregano","q":3},{"f":"tomato","q":1},{"f":"onion","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Cube the pork into 1-inch pieces and toss with the olive oil, half the lemon juice, oregano, one minced garlic clove, salt, and pepper; let it sit 15 minutes while you make the sauce.","Grate the cucumber, squeeze it hard in your fist until it stops dripping, and stir it into the yogurt with the remaining garlic and a squeeze of lemon for a quick tzatziki.","Thread the pork onto skewers or scatter it straight into a screaming-hot skillet and cook 3 to 4 minutes per side until charred at the corners and just cooked through.","Warm the pitas in the empty pan for 30 seconds a side until soft and blistered.","Pile each pita with tzatziki, pork, sliced tomato, and thin half-moons of onion, then roll it up tight and eat over a plate — the drips are part of the experience."],"tip":"Squeeze that cucumber like it owes you money, or your tzatziki becomes tza-tsunami."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_kapama_cinnamon_braise', '{"id":"chicken_kapama_cinnamon_braise","name":"Chicken Kapama over Spaghetti","emoji":"🍗","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":55,"servings":2,"ing":[{"f":"chicken_thigh","q":350},{"f":"spaghetti","q":140},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"cinnamon","q":2},{"f":"oregano","q":2},{"f":"olive_oil","q":20},{"f":"parmesan","q":30},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Season the chicken thighs with salt and pepper and sear them in the olive oil over medium-high heat for 4 minutes per side until deeply golden; set them aside.","In the same pot, soften the diced onion in the chicken drippings for 5 minutes, then add the garlic, cinnamon, and oregano and toast until the spices bloom and smell warm and sweet.","Pour in the crushed tomatoes with a splash of water, scrape up the browned bits, and nestle the chicken back in.","Cover and braise at a gentle bubble for 25 minutes until the chicken is fork-tender and the sauce has turned brick-red and thick.","Boil the spaghetti in well-salted water until just shy of al dente, then finish it for a minute in the kapama sauce so every strand gets stained red.","Plate the pasta, top with chicken, and shower generously with grated parmesan."],"tip":"Cinnamon in tomato sauce sounds like a dare, but it''s the secret handshake of Greek home cooking."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_tomato_feta_rice', '{"id":"shrimp_tomato_feta_rice","name":"Shrimp with Tomato, Feta and Rice","emoji":"🦐","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["shellfish","dairy"],"time":40,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"rice","q":150},{"f":"crushed_tomatoes","q":300},{"f":"feta","q":80},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"broth","q":350},{"f":"oregano","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.5},{"f":"black_pepper","q":2}],"steps":["Soften the diced onion in olive oil in a wide skillet over medium heat for 5 minutes, then add the garlic and oregano and cook until fragrant.","Stir in the rice to coat every grain in oil, pour in the crushed tomatoes and broth, and simmer covered for 15 minutes until the rice is nearly tender and the liquid mostly absorbed.","Season the shrimp with black pepper and tuck them into the rice in a single layer, pushing them halfway down into the sauce.","Crumble the feta over everything, cover, and cook 4 to 5 minutes more until the shrimp curl into loose commas and turn opaque pink.","Kill the heat, squeeze the lemon over the pan, and scatter with chopped parsley before bringing the whole skillet to the table."],"tip":"Shrimp go from perfect to pencil erasers in about 90 seconds, so hover accordingly."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('strapatsada_tomato_feta_eggs', '{"id":"strapatsada_tomato_feta_eggs","name":"Strapatsada (Greek Tomato Eggs)","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","high-protein"],"allergens":["eggs","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tomato","q":4},{"f":"feta","q":80},{"f":"olive_oil","q":25},{"f":"pita","q":2},{"f":"garlic","q":0.2},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Grate the tomatoes on the coarse side of a box grater, discarding the skins, so you end up with a bowl of fresh pulp.","Warm the olive oil with the sliced garlic in a nonstick skillet over medium heat until it just sizzles, then pour in the tomato pulp with the oregano and a pinch of salt.","Simmer 8 to 10 minutes, stirring now and then, until the tomato reduces to a thick jammy sauce and the oil pools at the edges.","Beat the eggs, pour them into the pan, and fold slowly with a spatula in big lazy strokes until they set into soft, glossy curds — pull them off the heat while they still look slightly underdone.","Crumble the feta over the top, grind on black pepper, and serve straight from the pan with warm pita for scooping."],"tip":"The eggs finish cooking on the walk to the table, so bail out early or accept rubber."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gemista_rice_stuffed_peppers', '{"id":"gemista_rice_stuffed_peppers","name":"Gemista (Rice-Stuffed Peppers)","emoji":"🫑","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"bell_pepper","q":4},{"f":"rice","q":140},{"f":"tomato","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":45},{"f":"potatoes","q":200},{"f":"parsley","q":0.5},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 375°F, slice the tops off the peppers, and pull out the seeds and ribs, saving the tops as little lids.","Grate the tomatoes into a bowl and stir in the rice, finely diced onion, minced garlic, chopped parsley, oregano, salt, pepper, and two-thirds of the olive oil.","Spoon the filling into the peppers only three-quarters full — the rice swells as it cooks — and cap them with their tops.","Stand the peppers in a baking dish, tuck potato wedges into the gaps, drizzle everything with the remaining oil, and pour a half cup of water into the bottom of the dish.","Cover with foil and bake 40 minutes, then uncover and bake 15 more until the peppers slump and blister and the rice is tender all the way through.","Let them rest 10 minutes; gemista is famously better warm than hot, and better still tomorrow."],"tip":"Underfill the peppers or the rice will stage a jailbreak all over your oven floor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('briam_roasted_summer_vegetables', '{"id":"briam_roasted_summer_vegetables","name":"Briam (Greek Roasted Vegetables)","emoji":"🥔","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":75,"servings":2,"ing":[{"f":"potatoes","q":350},{"f":"zucchini","q":2},{"f":"eggplant","q":1},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":60},{"f":"oregano","q":3},{"f":"parsley","q":0.5},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 400°F and slice the potatoes, zucchini, and eggplant into 1/4-inch rounds and the onion into thin half-moons.","Grate two of the tomatoes into a large bowl, add all the vegetables, sliced garlic, oregano, salt, pepper, and the olive oil, and toss until every slice glistens.","Layer everything into a wide baking dish, shingling the rounds loosely, and top with the last tomato cut into thin slices.","Roast uncovered for 50 to 60 minutes, stirring once halfway, until the potatoes are tender to a knife tip and the top layer is caramelized and crinkled at the edges.","Rest 10 minutes, shower with chopped parsley, and serve warm with the pan juices spooned over each plate."],"tip":"That amount of olive oil is not a typo — briam is a vegetable delivery vehicle for olive oil, and Greece is correct."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('horiatiki_village_salad_plate', '{"id":"horiatiki_village_salad_plate","name":"Horiatiki Village Salad with Toasted Pita","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"tomato","q":4},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"bell_pepper","q":1},{"f":"olives","q":80},{"f":"feta","q":150},{"f":"olive_oil","q":45},{"f":"pita","q":2},{"f":"oregano","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Cut the tomatoes into fat irregular wedges, the cucumber into thick half-moons, and the bell pepper into rings; slice the onion paper-thin.","Pile everything into a wide bowl with the olives, season with salt, and toss gently just once or twice — this salad hates being fussed over.","Lay the feta over the top in two big slabs rather than crumbling it, the way every taverna in the Cyclades does.","Drizzle generously with the olive oil, dust with oregano, and grind over black pepper.","Toast the pitas in a dry skillet until spotted and warm, cut into wedges, and use them to chase the salty, tomato-stained oil at the bottom of the bowl."],"tip":"No lettuce ever, and no vinegar needed — ripe tomatoes bring their own acid to the party."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_keftedes_yogurt_dip', '{"id":"turkey_keftedes_yogurt_dip","name":"Turkey Keftedes with Lemon Yogurt","emoji":"🧆","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","high-protein"],"allergens":["eggs","dairy"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"parsley","q":0.5},{"f":"oregano","q":2},{"f":"eggs","q":1},{"f":"oats","q":30},{"f":"olive_oil","q":30},{"f":"greek_yogurt","q":200},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Grate the onion straight into a bowl with the turkey, then add the minced garlic, chopped parsley, oregano, egg, oats, salt, and pepper.","Knead the mixture briefly with damp hands and let it rest 10 minutes so the oats drink up the moisture and the meatballs hold together.","Roll into golf-ball-sized keftedes and flatten each slightly into a plump patty.","Pan-fry in the olive oil over medium heat for 3 to 4 minutes per side until mahogany-crusted and cooked to 165°F in the center.","While they sizzle, stir the yogurt with grated squeezed cucumber, a pinch of salt, and half the lemon''s juice for a bright dipping sauce.","Serve the keftedes hot with the yogurt sauce and the remaining lemon in wedges for squeezing."],"tip":"Grated onion instead of chopped means juicy meatballs and zero crunchy onion surprises."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salmon_plaki_tomato_bake', '{"id":"salmon_plaki_tomato_bake","name":"Salmon Plaki with Potatoes","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":55,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"potatoes","q":300},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"oregano","q":2},{"f":"parsley","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 400°F and slice the potatoes into thin rounds, the onion into half-moons, and the tomatoes into slices.","Toss the potatoes and onion with two-thirds of the olive oil, salt, and pepper, spread them in a baking dish, and roast 25 minutes until the edges start to color.","Season the salmon with salt, pepper, and oregano, lay it over the potatoes, and shingle the tomato and lemon slices on top with the sliced garlic scattered between.","Drizzle with the remaining oil and bake 12 to 15 minutes until the salmon flakes at the thick end but still looks glossy inside.","Scatter with chopped parsley and spoon the lemony, tomato-slicked pan juices over everything before serving."],"tip":"Pull the salmon when it flakes reluctantly, not eagerly — carryover heat handles the rest."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('yiaourti_me_meli_breakfast_bowls', '{"id":"yiaourti_me_meli_breakfast_bowls","name":"Yogurt with Honey, Walnuts and Berries","emoji":"🍯","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"greek_yogurt","q":450},{"f":"honey","q":50},{"f":"walnuts","q":50},{"f":"oats","q":40},{"f":"berries","q":200},{"f":"cinnamon","q":1}],"steps":["Toast the oats and roughly chopped walnuts in a dry skillet over medium heat for 3 to 4 minutes, shaking often, until they smell nutty and turn a shade darker.","Divide the cold yogurt between two bowls and smooth the tops with the back of a spoon like frosting.","Scatter the berries over the yogurt, then rain down the warm toasted oats and walnuts so they crackle against the cold.","Drizzle the honey over each bowl in slow ribbons and finish with a whisper of cinnamon.","Eat immediately, while the contrast between warm crunch and cool cream is at its peak."],"tip":"Warm honey pours in elegant ribbons; cold honey pours in one embarrassing glob — 10 seconds in warm water fixes it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_paprika_chicken_rice_skillet', '{"id":"spanish_paprika_chicken_rice_skillet","name":"Spanish Paprika Chicken & Rice Skillet","emoji":"🥘","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":45,"servings":2,"ing":[{"f":"chicken_thigh","q":300},{"f":"rice","q":150},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"bell_pepper","q":1},{"f":"crushed_tomatoes","q":100},{"f":"peas_frozen","q":100},{"f":"broth","q":500},{"f":"paprika","q":4},{"f":"turmeric","q":2},{"f":"salt","q":4},{"f":"black_pepper","q":1},{"f":"lemon","q":1}],"steps":["Season the chicken thighs with salt, pepper, and half the paprika, then sear them in olive oil in a wide skillet over medium-high heat for 4 minutes per side until deeply golden; set them aside on a plate.","Lower the heat to medium and soften the diced onion and bell pepper in the same pan for 5 minutes, scraping up the browned bits, then stir in the minced garlic, remaining paprika, and turmeric until fragrant, about 30 seconds.","Add the crushed tomatoes and cook 2 minutes until they darken and thicken, then stir in the rice so every grain is slicked and stained brick-red.","Pour in the broth, nestle the chicken back on top, and simmer uncovered without stirring for 18 to 20 minutes, until the rice is tender and the liquid has vanished into it.","Scatter the peas over the surface for the last 3 minutes, then pull the pan off the heat, cover, and rest 5 minutes so a light crust forms on the bottom.","Squeeze lemon wedges over everything at the table and serve straight from the skillet."],"tip":"Resist the urge to stir once the broth goes in — the crusty bottom layer is the prize, not a mistake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_olive_lemon_tagine_couscous', '{"id":"chicken_olive_lemon_tagine_couscous","name":"Chicken, Olive & Lemon Tagine with Couscous","emoji":"🍋","cuisine":"Mediterranean","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten"],"time":55,"servings":4,"ing":[{"f":"chicken_thigh","q":600},{"f":"olive_oil","q":25},{"f":"onion","q":1.5},{"f":"garlic","q":0.4},{"f":"lemon","q":1.5},{"f":"olives","q":100},{"f":"broth","q":350},{"f":"paprika","q":5},{"f":"cumin","q":5},{"f":"turmeric","q":3},{"f":"cinnamon","q":1},{"f":"parsley","q":0.5},{"f":"couscous","q":200},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Toss the chicken thighs with cumin, paprika, turmeric, cinnamon, salt, and pepper, then brown them in olive oil in a Dutch oven over medium-high heat until the spices smell toasty and the edges are burnished, about 3 minutes per side.","Push the chicken aside and slide in the sliced onions, cooking them down for 6 to 8 minutes until silky and golden, then stir in the minced garlic for a final minute.","Pour in the broth, add the zest and juice of one lemon plus the olives, and scrape the bottom of the pot clean before covering and simmering gently for 25 minutes, until the chicken yields easily to a fork.","Meanwhile, pour 250 milliliters of boiling water over the couscous with a pinch of salt, cover for 5 minutes, then rake it fluffy with a fork.","Uncover the pot and simmer 5 more minutes to thicken the sauce to a glossy, spoon-coating consistency, tasting for salt and brightening with the remaining lemon juice.","Mound the couscous on a platter, spoon the chicken, olives, and sauce over the top, and shower generously with chopped parsley."],"tip":"Zest the lemon before you juice it — nobody has ever successfully zested a squeezed-out lemon husk with their dignity intact."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gambas_garlic_paprika_shrimp_tapas', '{"id":"gambas_garlic_paprika_shrimp_tapas","name":"Sizzling Garlic-Paprika Shrimp with Crusty Bread","emoji":"🍤","cuisine":"Mediterranean","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","gluten"],"time":20,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"olive_oil","q":45},{"f":"garlic","q":0.6},{"f":"paprika","q":4},{"f":"chili_powder","q":1},{"f":"lemon","q":0.5},{"f":"parsley","q":0.5},{"f":"bread","q":4},{"f":"salt","q":3}],"steps":["Pat the shrimp bone-dry with paper towels and season with salt — wet shrimp steam instead of sizzle, and sizzle is the whole point here.","Warm the olive oil in a heavy skillet over medium-low heat with the thinly sliced garlic, letting it bubble lazily for 2 to 3 minutes until the slices turn pale gold and the kitchen smells like a Sevilla tapas bar.","Stir in the paprika and chili powder, then immediately raise the heat to medium-high and add the shrimp in a single layer, cooking 90 seconds per side until they curl into loose commas and blush pink.","Pull the pan off the heat, squeeze in the lemon juice, and shower with chopped parsley, swirling so the juices and oil emulsify into a rusty, garlicky slick.","Toast the bread until crackling and serve the shrimp straight from the hot pan, with every last drop of oil for dunking."],"tip":"The garlic oil is the dish and the shrimp are the garnish — anyone who skips the bread-dunking has missed the assignment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('kefta_meatball_egg_tagine', '{"id":"kefta_meatball_egg_tagine","name":"Moroccan Kefta Meatball Tagine with Poached Eggs","emoji":"🍳","cuisine":"Mediterranean","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["eggs","gluten"],"time":50,"servings":4,"ing":[{"f":"ground_beef","q":500},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"cumin","q":6},{"f":"paprika","q":6},{"f":"cinnamon","q":1},{"f":"parsley","q":0.5},{"f":"crushed_tomatoes","q":600},{"f":"olive_oil","q":15},{"f":"eggs","q":4},{"f":"pita","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Knead the ground beef with half the grated onion, half the cumin and paprika, the cinnamon, a fistful of chopped parsley, salt, and pepper, then roll it into walnut-sized meatballs with lightly oiled hands.","Brown the meatballs in olive oil in a deep skillet over medium-high heat for about 5 minutes, turning until crusted on all sides but still rare inside, then transfer to a plate.","Soften the remaining onion in the same pan for 4 minutes, add the minced garlic and remaining spices for 30 seconds, then pour in the crushed tomatoes and simmer 10 minutes until the sauce turns deep brick-red and slightly sweet.","Return the meatballs and simmer gently, partially covered, for 10 minutes so they finish cooking and the sauce reduces to a lazy blup-blup thickness.","Crack the eggs into wells in the sauce, cover, and cook 4 to 6 minutes until the whites set but the yolks still shimmy when you shake the pan.","Finish with more parsley and serve blazing hot with warm pita torn into scoops."],"tip":"Set a timer for the eggs — the line between molten yolk and sad rubber ball is about ninety seconds wide."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_smoky_lentil_bacon_potage', '{"id":"spanish_smoky_lentil_bacon_potage","name":"Smoky Spanish Lentil & Bacon Potage","emoji":"🍲","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free"],"allergens":[],"time":55,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"bacon","q":120},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"carrots","q":150},{"f":"celery","q":80},{"f":"potatoes","q":300},{"f":"paprika","q":8},{"f":"crushed_tomatoes","q":200},{"f":"broth","q":1000},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Render the chopped bacon in olive oil in a soup pot over medium heat for 5 minutes, until the fat runs and the pieces crisp at the edges, then scoop out half for garnish.","Tumble in the diced onion, carrots, and celery and sweat them in the smoky fat for 6 minutes until softened, then stir in the garlic, paprika, and oregano just until the paprika blooms and stains everything rust-orange — do not let it scorch.","Add the crushed tomatoes, rinsed lentils, cubed potatoes, and broth, bring to a boil, then drop to a lazy simmer and cook partially covered for 30 to 35 minutes, until the lentils are creamy and the potatoes yield to a spoon.","Mash a few potato chunks against the side of the pot to thicken the broth to a velvety, stew-like body, then season boldly with salt and black pepper.","Ladle into bowls, crown with the reserved crispy bacon, and let it sit 5 minutes — this potage, like most Spaniards, refuses to be rushed."],"tip":"It tastes even better the next day, so make it tonight and take credit for tomorrow''s lunch twice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_seven_vegetable_chickpea_tagine', '{"id":"moroccan_seven_vegetable_chickpea_tagine","name":"Moroccan Vegetable & Chickpea Tagine over Couscous","emoji":"🥕","cuisine":"Mediterranean","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":45,"servings":4,"ing":[{"f":"chickpeas","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"carrots","q":250},{"f":"zucchini","q":1},{"f":"sweet_potatoes","q":350},{"f":"crushed_tomatoes","q":300},{"f":"olive_oil","q":30},{"f":"cumin","q":6},{"f":"paprika","q":6},{"f":"cinnamon","q":2},{"f":"turmeric","q":2},{"f":"cilantro","q":0.5},{"f":"couscous","q":250},{"f":"salt","q":5}],"steps":["Sweat the sliced onion in olive oil in a wide pot over medium heat for 5 minutes until translucent, then stir in the garlic, cumin, paprika, cinnamon, and turmeric and toast 45 seconds until the spices smell warm and bakery-sweet.","Add the crushed tomatoes, chunked carrots, and cubed sweet potatoes with 400 milliliters of water and a good pinch of salt, cover, and simmer 15 minutes until the roots are halfway tender.","Slide in the thick zucchini half-moons and the chickpeas and simmer uncovered 12 to 15 minutes more, until every vegetable is tender and the sauce has reduced to a glossy, spiced gravy.","While the pot burbles, pour 300 milliliters of boiling water over the couscous with a pinch of salt and a drizzle of olive oil, cover 5 minutes, then fluff with a fork into a fine golden heap.","Taste the tagine and adjust the salt — sweet potatoes drink seasoning greedily — then ladle it over the couscous and finish with a flurry of chopped cilantro."],"tip":"Cut the vegetables chunky and confident; a tagine full of timid little dice cooks to mush before the flavors get acquainted."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('espinacas_spinach_chickpea_saute', '{"id":"espinacas_spinach_chickpea_saute","name":"Andalusian Spinach & Chickpeas with Fried Bread","emoji":"🥬","cuisine":"Mediterranean","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":25,"servings":2,"ing":[{"f":"chickpeas","q":350},{"f":"spinach","q":200},{"f":"olive_oil","q":30},{"f":"garlic","q":0.4},{"f":"cumin","q":4},{"f":"paprika","q":4},{"f":"bread","q":2},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Tear the bread into rough chunks and fry it in half the olive oil over medium heat with the sliced garlic until both are deeply golden and crunchy, about 4 minutes, then transfer to a mortar or small food processor.","Pound or pulse the fried bread and garlic with the cumin, paprika, and a splash of water into a coarse, rust-colored paste — this is the old Moorish trick that thickens the whole dish.","Wilt the spinach in the remaining oil in the same skillet over medium-high heat, handfuls at a time, until it collapses and its water evaporates, about 3 minutes.","Stir in the chickpeas and the bread paste with another splash of water and simmer 5 minutes, until everything binds into a creamy, spoonable tangle that smells of smoke and cumin.","Season with salt and black pepper, hit it with a squeeze of lemon, and serve hot in shallow bowls with a final thread of olive oil."],"tip":"The bread paste looks like a strange move until you taste it — trust six centuries of Sevillian bartenders over your instincts."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_potato_onion_tortilla', '{"id":"spanish_potato_onion_tortilla","name":"Classic Spanish Potato & Onion Tortilla","emoji":"🥔","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"potatoes","q":450},{"f":"onion","q":1},{"f":"olive_oil","q":50},{"f":"salt","q":4},{"f":"tomato","q":1}],"steps":["Slice the potatoes into thin coins and the onion into half-moons, then poach them gently in the olive oil in a 20-centimeter nonstick skillet over medium-low heat for 15 to 18 minutes — they should soften and turn sweet without ever browning.","Drain the potatoes and onions in a colander set over a bowl, reserving the fragrant oil, and let them cool for a few minutes so they don''t scramble the eggs on contact.","Whisk the eggs with a generous pinch of salt, fold in the warm potatoes, and let the mixture rest 5 minutes so the eggs seep into every layer.","Heat a tablespoon of the reserved oil in the skillet over medium heat, pour in the mixture, and cook 4 to 5 minutes, shaking occasionally, until the edges set but the center still wobbles like a custard.","Clap a plate over the pan, flip with conviction, slide the tortilla back in raw-side down, and cook 2 to 3 minutes more — the middle should stay just barely juicy.","Rest 5 minutes, then cut into wedges and serve warm or room temperature with sliced tomato."],"tip":"The flip is 90 percent confidence and 10 percent physics; hesitate mid-air and you will be renaming the dish ''Spanish scramble''."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('paprika_salmon_almond_romesco', '{"id":"paprika_salmon_almond_romesco","name":"Paprika-Seared Salmon with Almond Romesco","emoji":"🐟","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":["fish","nuts"],"time":30,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"roasted_red_peppers","q":150},{"f":"almonds","q":30},{"f":"garlic","q":0.2},{"f":"olive_oil","q":25},{"f":"balsamic_vinegar","q":10},{"f":"paprika","q":3},{"f":"green_beans","q":250},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Toast the almonds in a dry skillet over medium heat for 3 minutes, shaking until they smell nutty and take on golden freckles, then tip them into a blender.","Add the roasted red peppers, garlic, balsamic vinegar, a third of the olive oil, half the paprika, and a pinch of salt, and blitz into a coarse, brick-orange romesco with a little pleasing grit left in it.","Pat the salmon dry, season with the remaining paprika, salt, and pepper, and sear skin-side down in olive oil over medium-high heat for 4 minutes without touching it, until the skin crackles and releases on its own.","Flip and cook 2 to 3 minutes more, until the flesh flakes at the thickest point but still glistens rosy in the center.","Meanwhile, blister the green beans in the hot pan alongside or after the fish for 4 minutes, until spotty-charred but still squeaky-crisp.","Spoon a generous swoosh of romesco onto each plate and perch the salmon and beans on top."],"tip":"Make a double batch of romesco — it improves everything it touches and disappears from the fridge with suspicious speed."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_carrot_olive_couscous_salad', '{"id":"moroccan_carrot_olive_couscous_salad","name":"Moroccan Couscous Salad with Carrots, Olives & Feta","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":20,"servings":2,"ing":[{"f":"couscous","q":150},{"f":"olives","q":60},{"f":"cherry_tomatoes","q":150},{"f":"cucumber","q":0.5},{"f":"carrots","q":100},{"f":"feta","q":80},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"cumin","q":3},{"f":"paprika","q":2},{"f":"parsley","q":0.5},{"f":"salt","q":3}],"steps":["Pour 180 milliliters of boiling water over the couscous with a pinch of salt, cover the bowl tightly, and walk away for 5 minutes before fluffing it into light, separate grains with a fork.","Whisk the lemon juice with the olive oil, cumin, paprika, and salt into a dressing that tastes a touch too punchy on its own — the couscous will mellow it.","Halve the cherry tomatoes, dice the cucumber, and grate the carrots coarsely, then fold them through the warm couscous so the grains drink up their juices.","Add the halved olives and most of the dressing, tossing until every grain glistens amber, then taste and add the rest if it needs more brightness.","Crumble the feta over the top in craggy chunks, scatter with a storm of chopped parsley, and serve at room temperature, when the flavors are loudest."],"tip":"Dress the couscous while it is still warm — cold couscous accepts a dressing the way a cat accepts a bath."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('pinchos_morunos_pork_skewers', '{"id":"pinchos_morunos_pork_skewers","name":"Pinchos Morunos: Cumin-Paprika Pork Skewers","emoji":"🍢","cuisine":"Mediterranean","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"olive_oil","q":20},{"f":"garlic","q":0.3},{"f":"paprika","q":5},{"f":"cumin","q":5},{"f":"oregano","q":2},{"f":"lemon","q":1},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"tomato","q":1},{"f":"cucumber","q":0.5},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Cut the pork loin into 3-centimeter cubes and massage them with olive oil, minced garlic, paprika, cumin, oregano, salt, pepper, and the juice of half the lemon; let the meat marinate at least 15 minutes while you prep the rest.","Thread the pork onto skewers alternating with chunks of bell pepper and onion, packing them snugly so the meat stays juicy.","Get a grill pan or heavy skillet screaming hot over high heat, then cook the skewers 2 to 3 minutes per side, turning a quarter-turn at a time, until the spice crust darkens to mahogany and the pork is just cooked through with a blush of char.","Rest the skewers 5 minutes under loose foil — cutting early lets all those cumin-scented juices escape to the plate instead of your mouth.","Toss the diced tomato and cucumber with a pinch of salt and the remaining lemon juice, and serve the skewers over this cool, crunchy salad with lemon wedges alongside."],"tip":"A screaming-hot pan and dry meat are non-negotiable — a lukewarm skillet turns these tapas-bar legends into gray cafeteria cubes."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_loubia_white_bean_stew', '{"id":"moroccan_loubia_white_bean_stew","name":"Loubia: Moroccan Stewed White Beans in Spiced Tomato","emoji":"🫘","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":4,"ing":[{"f":"white_beans","q":700},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"crushed_tomatoes","q":500},{"f":"olive_oil","q":40},{"f":"cumin","q":8},{"f":"paprika","q":8},{"f":"chili_powder","q":2},{"f":"cilantro","q":0.5},{"f":"carrots","q":150},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Sweat the grated onion and finely diced carrots in olive oil in a heavy pot over medium heat for 6 minutes, until the onion melts into the oil and turns pale gold.","Add the minced garlic, cumin, paprika, and chili powder and stir for a full minute, until the oil turns deep red and the spices smell rich rather than raw.","Pour in the crushed tomatoes and 300 milliliters of water, bring to a simmer, and cook 10 minutes so the sauce loses its tinny edge and sweetens.","Tip in the white beans and simmer uncovered for 15 to 20 minutes, mashing a spoonful against the pot wall to thicken the broth until it clings to the beans like a spiced velvet coat.","Season assertively with salt and black pepper, stir in most of the chopped cilantro, and rest the pot 5 minutes off the heat.","Serve in deep bowls with a final swirl of olive oil and the remaining cilantro scattered on top."],"tip":"Loubia is street food that thinks it is a hug — make extra, because it thickens overnight into something you will fight your family for."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('moroccan_spiced_tuna_couscous_bowl', '{"id":"moroccan_spiced_tuna_couscous_bowl","name":"Spiced Tuna & Couscous Bowl with Olives and Peppers","emoji":"🥙","cuisine":"Mediterranean","meal":["lunch"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten"],"time":20,"servings":2,"ing":[{"f":"tuna_canned","q":240},{"f":"couscous","q":140},{"f":"olives","q":50},{"f":"roasted_red_peppers","q":100},{"f":"cucumber","q":0.5},{"f":"lemon","q":1},{"f":"olive_oil","q":25},{"f":"cumin","q":3},{"f":"paprika","q":2},{"f":"parsley","q":0.5},{"f":"scallions","q":0.5},{"f":"salt","q":3}],"steps":["Steep the couscous in 170 milliliters of boiling water with a pinch of salt under a tight lid for 5 minutes, then fluff it with a fork until every grain stands apart.","Whisk the olive oil with the lemon juice, cumin, paprika, and salt into a smoky-bright dressing, and fold half of it through the warm couscous.","Drain the tuna well and break it into big, plush flakes — crumbling it to dust makes the bowl taste like sad desk lunch, and we are better than that.","Slice the roasted red peppers into ribbons, dice the cucumber, halve the olives, and thinly slice the scallions.","Pile the couscous into two bowls, arrange the tuna and vegetables in generous stripes on top, and spoon over the remaining dressing.","Finish with chopped parsley and an extra crack of lemon just before eating."],"tip":"Buy the best oil-packed tuna you can afford — it is the difference between a Marrakech café and a vending machine."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('butter_chicken_simmer', '{"id":"butter_chicken_simmer","name":"Weeknight Butter Chicken","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","high-protein"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"chicken_breast","q":500},{"f":"butter","q":30},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":4},{"f":"greek_yogurt","q":150},{"f":"rice","q":130}],"steps":["Toss bite-size chunks of chicken with half the yogurt, a pinch of salt, and a teaspoon each of garam masala and turmeric, then let it sit while you start the rice in double its volume of salted water.","Melt the butter in a wide skillet over medium heat and cook the diced onion for 6 to 8 minutes until deeply golden at the edges, then stir in the minced garlic for 30 fragrant seconds.","Add the chopped tomatoes with a teaspoon of paprika and simmer 10 minutes, mashing occasionally, until the sauce thickens and the butter pools orange at the edges.","Nestle in the marinated chicken and simmer gently for 10 to 12 minutes until the pieces are opaque all the way through and register 165F.","Pull the pan off the heat, swirl in the remaining yogurt until the sauce turns silky and blush-colored, and taste for salt.","Spoon over the fluffy rice and let everything sit 2 minutes so the sauce clings."],"tip":"Add the yogurt off the heat unless you enjoy sauce with the texture of scrambled regret."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_tikka_pepper_skillet', '{"id":"chicken_tikka_pepper_skillet","name":"Chicken Tikka Pepper Skillet","emoji":"🍗","cuisine":"Indian","meal":["dinner","lunch"],"diets":["gluten-free","high-protein","low-carb"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":450},{"f":"greek_yogurt","q":100},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20}],"steps":["Stir the yogurt with minced garlic, a teaspoon of garam masala, half a teaspoon of paprika, and a good pinch of salt, then coat the chicken chunks and marinate 15 minutes at room temperature.","Heat the olive oil in a heavy skillet over medium-high until it shimmers, then lay the chicken in a single layer and leave it alone for 3 minutes to build charred, tikka-style edges.","Flip the pieces, push them to one side, and add the thick-sliced peppers and onion wedges, tossing until they blister and soften but keep a little crunch, about 5 minutes.","Toss everything together and cook 2 to 3 minutes more until the chicken hits 165F and the yogurt crust turns burnished and spotty brown.","Finish with a squeeze of lemon if you have one and a shower of black pepper straight from the pan."],"tip":"Crowd the pan and you will steam your tikka into sadness — give every piece its personal space."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mulligatawny_chicken_soup', '{"id":"mulligatawny_chicken_soup","name":"Mulligatawny Chicken and Lentil Soup","emoji":"🥣","cuisine":"Indian","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"chicken_breast","q":450},{"f":"lentils_dry","q":150},{"f":"carrots","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"broth","q":1000},{"f":"coconut_milk","q":200},{"f":"olive_oil","q":15},{"f":"rice","q":80}],"steps":["Warm the olive oil in a soup pot over medium heat and sweat the diced onion, sliced carrots, and garlic with a tablespoon of curry powder for 5 minutes until the kitchen smells like a spice shop.","Pour in the broth, add the rinsed lentils and rice, and bring to a lively simmer, skimming any foam that rises.","Slide in the whole chicken breasts, drop the heat to low, and simmer gently for 18 to 20 minutes until the chicken is just cooked and the lentils have collapsed into creaminess.","Lift out the chicken, shred it with two forks, and return it to the pot along with the coconut milk.","Simmer 5 more minutes until the soup is thick enough to coat a spoon, then season assertively with salt and a crack of black pepper."],"tip":"This soup thickens overnight like it is trying to become a curry — thin tomorrow''s bowl with a splash of water."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('goan_shrimp_coconut_curry', '{"id":"goan_shrimp_coconut_curry","name":"Goan-Style Shrimp Coconut Curry","emoji":"🍤","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["shellfish"],"time":35,"servings":2,"ing":[{"f":"shrimp","q":450},{"f":"coconut_milk","q":250},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":2},{"f":"olive_oil","q":15},{"f":"rice","q":120}],"steps":["Start the rice simmering in salted water, then heat the oil in a deep skillet over medium and cook the finely chopped onion for 5 to 6 minutes until soft and lightly bronzed.","Stir in the minced garlic, a teaspoon of turmeric, a teaspoon of ground coriander, and a pinch of cayenne, toasting for 30 seconds until the spices darken a shade.","Add the chopped tomatoes and cook 4 minutes until they slump, then pour in the coconut milk and simmer 8 minutes until the sauce reduces slightly and turns a sunset orange.","Season the shrimp with salt, slip them into the sauce, and poach at a bare simmer for 3 to 4 minutes until they curl into loose commas and turn pink.","Brighten with a splash of vinegar or lemon if handy, taste for salt, and ladle generously over the rice."],"tip":"A shrimp curled into a tight O is overcooked — pull them at the C stage and let carryover do the rest."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tawa_shrimp_masala_skillet', '{"id":"tawa_shrimp_masala_skillet","name":"Tawa Shrimp Masala Skillet","emoji":"🌶️","cuisine":"Indian","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein","low-carb"],"allergens":["shellfish"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"bell_pepper","q":2},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25}],"steps":["Pat the shrimp bone-dry and toss with salt, half a teaspoon of turmeric, and a teaspoon of garam masala so the spices form a thin rusty jacket.","Get the olive oil rippling-hot in your widest skillet over high heat, sear the shrimp 90 seconds per side until blistered pink, and set them aside on a plate.","In the same pan, char the sliced onion and peppers for 4 to 5 minutes, letting them catch dark spots before you stir, then add the garlic and chopped tomatoes.","Cook 3 minutes more until the tomatoes break down into a rough, clingy masala that coats the vegetables.","Return the shrimp with any juices, toss for one final minute over the heat, and serve straight from the skillet while everything still sizzles."],"tip":"Wet shrimp steam and sulk; dry shrimp sear and sing, so pat them like you mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chana_masala_classic', '{"id":"chana_masala_classic","name":"Chana Masala with Steamed Rice","emoji":"🫘","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"tomato","q":4},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":25},{"f":"rice","q":130}],"steps":["Set the rice simmering, then heat the oil in a deep skillet over medium and fry the finely diced onion for 8 to 10 minutes until it turns a deep caramel brown — this color is the backbone of the dish, so do not rush it.","Add the minced garlic with a tablespoon of ground cumin and coriander plus half a teaspoon of turmeric, and toast 30 seconds until the oil stains gold.","Tip in the chopped tomatoes and cook 8 minutes, mashing with your spoon, until they melt into a thick paste that pulls away from the pan.","Stir in the drained chickpeas with a splash of water, crushing a handful against the pan wall to thicken the gravy, and simmer 10 minutes uncovered.","Finish with a pinch of garam masala and a squeeze of lemon if available, then pile onto the rice."],"tip":"Mash a few chickpeas on purpose — that is the difference between gravy and chickpeas floating in tomato water."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_red_lentil_dal_2', '{"id":"coconut_red_lentil_dal_2","name":"Creamy Coconut Red Lentil Dal","emoji":"🍲","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"tomato","q":2},{"f":"coconut_milk","q":250},{"f":"spinach","q":100},{"f":"olive_oil","q":20}],"steps":["Rinse the lentils until the water runs mostly clear, then simmer them in 900 ml of salted water for 15 minutes, skimming foam, until they slump and lose their shape.","Meanwhile, heat the oil in a small skillet over medium and fry the diced onion for 6 minutes until golden, then add the garlic, a teaspoon of cumin, and half a teaspoon of turmeric for 30 seconds.","Add the chopped tomatoes to the skillet and cook 5 minutes until jammy, then scrape this tadka into the pot of lentils.","Pour in the coconut milk and simmer everything together for 8 to 10 minutes until the dal is thick enough to mound softly on a spoon.","Stir in the spinach off the heat until it wilts glossy and green, then season boldly with salt — dal is shy without it."],"tip":"Dal has two settings, underseasoned and glorious, and the only dial between them is salt."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('aloo_gobi_dry_curry', '{"id":"aloo_gobi_dry_curry","name":"Aloo Gobi Dry-Fried Curry","emoji":"🥔","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"cauliflower","q":0.8},{"f":"potatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":2},{"f":"olive_oil","q":30}],"steps":["Cut the potatoes into 2 cm cubes and the cauliflower into floret halves so they cook at the same pace, then heat the oil in your largest lidded skillet over medium-high.","Fry the potatoes for 5 minutes until their edges pick up golden crusts, then add the cauliflower, a teaspoon of turmeric, a teaspoon of cumin seeds if you have them, and a solid pinch of salt.","Stir to stain everything yellow, add the diced onion and garlic, then cover and cook 10 to 12 minutes, lifting the lid to toss every few minutes so nothing scorches.","When a knife slides through the potatoes without resistance, add the chopped tomatoes and cook uncovered 5 minutes until they melt into a rough coating rather than a sauce.","Finish with half a teaspoon of garam masala and let the pan sit off heat for 2 minutes so the flavors settle in."],"tip":"Stir aloo gobi with a flip of the wrist, not a spoon-lashing — mushy cauliflower has ended friendships."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('saag_tofu_curry', '{"id":"saag_tofu_curry","name":"Saag Tofu in Spiced Spinach Gravy","emoji":"🥬","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","gluten-free","dairy-free","low-carb"],"allergens":["soy"],"time":40,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"spinach","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"coconut_milk","q":200},{"f":"olive_oil","q":25}],"steps":["Press the tofu between paper towels for 10 minutes, cube it, then pan-fry in half the oil over medium-high for 8 minutes, turning until every face is crisp and deeply golden; set aside.","Wilt the spinach in the same pan with a splash of water for 2 minutes, then blitz it in a blender with the coconut milk into a rough, vividly green puree.","Add the remaining oil to the pan and cook the diced onion for 6 minutes until soft and browning, then stir in the garlic, a teaspoon of garam masala, and half a teaspoon of cumin for 30 seconds.","Pour the spinach puree back in and simmer 5 minutes until it thickens from soup to gravy and turns a shade darker.","Fold in the crisp tofu, simmer 3 minutes so the cubes drink up the sauce, and season with salt to taste."],"tip":"Crisp the tofu like it owes you money — soft tofu vanishes into saag without a trace."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('vegetable_korma_cashew', '{"id":"vegetable_korma_cashew","name":"Cashew Vegetable Korma","emoji":"🥕","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","nuts"],"time":50,"servings":2,"ing":[{"f":"carrots","q":3},{"f":"potatoes","q":300},{"f":"cashews","q":50},{"f":"greek_yogurt","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"rice","q":120}],"steps":["Soak the cashews in hot water for 15 minutes while the rice cooks, then blend them with the soaking water into a smooth, pourable cream.","Heat the oil in a deep pan over medium and cook the sliced onion for 7 to 8 minutes until pale gold, then add the garlic, a teaspoon of ground coriander, and half a teaspoon each of turmeric and cinnamon.","Add the carrot coins and potato cubes with 250 ml of water, cover, and simmer 15 minutes until a fork slides in easily.","Stir in the cashew cream and simmer gently 5 minutes until the sauce turns ivory and thick enough to nap the vegetables.","Off the heat, whisk in the yogurt one spoonful at a time so it stays silky, season with salt, and serve over the rice."],"tip":"Korma is a low-and-slow diplomat — boil the yogurt and the peace talks collapse into curds."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('punjabi_egg_curry', '{"id":"punjabi_egg_curry","name":"Punjabi-Style Egg Curry","emoji":"🥚","cuisine":"Indian","meal":["dinner","breakfast"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"coconut_milk","q":200},{"f":"olive_oil","q":20},{"f":"rice","q":120}],"steps":["Boil the eggs for 9 minutes, plunge them into cold water, peel, and score each one lightly so the gravy can sneak inside; start the rice at the same time.","Heat the oil in a skillet over medium and brown the finely diced onion for 8 minutes until it reaches a deep amber — pale onions make a flat curry.","Add the garlic, a teaspoon of cumin, a teaspoon of garam masala, and a pinch of cayenne, toast 30 seconds, then add the chopped tomatoes and cook 7 to 8 minutes into a thick, rust-colored masala.","Pour in the coconut milk, simmer 5 minutes until the sauce coats the back of a spoon, and season with salt.","Roll the eggs in the gravy, cut them in half so the yolks face up like little suns, and simmer 2 final minutes before spooning over rice."],"tip":"Score the egg whites before saucing — an unslit boiled egg repels curry like a raincoat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_spinach_coconut_curry', '{"id":"sweet_potato_spinach_coconut_curry","name":"Sweet Potato and Spinach Coconut Curry","emoji":"🍠","cuisine":"Indian","meal":["dinner","lunch"],"diets":["vegan","vegetarian","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"spinach","q":200},{"f":"coconut_milk","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"olive_oil","q":20}],"steps":["Heat the oil in a deep pot over medium and soften the diced onion for 5 to 6 minutes until translucent with golden edges.","Stir in the minced garlic with a tablespoon of curry powder and a pinch of red pepper flakes, toasting 30 seconds until the spices bloom and smell toasty rather than raw.","Add the sweet potatoes in 2 cm cubes, pour in the coconut milk plus 150 ml of water, and simmer covered for 15 to 18 minutes until a fork slides through without a fight.","Mash a few cubes against the pot wall to thicken the sauce into something spoon-coating and orange as a monsoon sunset.","Fold in the spinach by the handful until it collapses glossy and dark, then season with salt and serve steaming."],"tip":"Cube the sweet potatoes evenly or you will be serving a curry of mush and rocks in the same bowl."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bengali_salmon_tomato_curry', '{"id":"bengali_salmon_tomato_curry","name":"Bengali-Inspired Salmon Curry","emoji":"🐟","cuisine":"Indian","meal":["dinner"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish"],"time":35,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"coconut_milk","q":150},{"f":"olive_oil","q":15},{"f":"rice","q":110}],"steps":["Rub the salmon chunks with salt and half a teaspoon of turmeric and let them sit while the rice simmers — this quick cure firms the fish and stains it a beautiful gold.","Heat the oil in a wide pan over medium-high and sear the salmon 1 minute per side, just to set the outside, then move it to a plate.","Lower the heat, cook the sliced onion for 5 to 6 minutes until soft and browning, then add the garlic, a teaspoon of cumin, and a pinch of cayenne for 30 seconds.","Add the chopped tomatoes and simmer 6 to 7 minutes until they collapse into a loose gravy, then stir in the coconut milk and season with salt.","Return the salmon and poach at a gentle burble for 4 to 5 minutes until it flakes at the nudge of a spoon, then serve over rice without stirring — the fish is delicate and deserves dignity."],"tip":"Once the salmon goes back in, retire your spoon to shaking-the-pan duty or you will be eating salmon crumble."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_cashew_rice', '{"id":"lemon_cashew_rice","name":"Lemon Cashew Rice","emoji":"🍋","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":35,"servings":2,"ing":[{"f":"rice","q":180},{"f":"cashews","q":50},{"f":"peas_frozen","q":100},{"f":"olive_oil","q":25},{"f":"lemon","q":1},{"f":"ginger","q":10},{"f":"turmeric","q":3},{"f":"cumin","q":3},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Rinse the rice until the water runs clear, then simmer it covered with 350ml water and half the salt for 15 minutes; let it steam off the heat for 5 more so the grains stay separate.","Meanwhile, heat the olive oil in a wide skillet over medium and fry the cashews for 2 to 3 minutes, stirring constantly, until they turn deep golden and smell toasty.","Add the cumin and minced ginger to the same oil and sizzle for 30 seconds, then stir in the turmeric and peas and cook 2 minutes until the peas are bright green.","Tip in the cooked rice and toss gently with a fork until every grain is stained sunshine yellow and coated in the fragrant oil.","Pull the pan off the heat, squeeze in the lemon juice, season with the remaining salt, and shower with chopped cilantro before serving warm."],"tip":"Add the lemon juice off the heat or its bright zing cooks away into bitterness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tomato_chickpea_masala_rice', '{"id":"tomato_chickpea_masala_rice","name":"Tomato Chickpea Masala Rice","emoji":"🍅","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"rice","q":180},{"f":"chickpeas","q":240},{"f":"tomato","q":3},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"olive_oil","q":25},{"f":"garam_masala","q":4},{"f":"cumin","q":3},{"f":"turmeric","q":2},{"f":"chili_powder","q":2},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Heat the olive oil in a deep pot over medium and sizzle the cumin for 30 seconds until it crackles and perfumes the kitchen.","Add the sliced onion with a pinch of salt and cook 6 to 8 minutes until the edges brown, then stir in the minced garlic for 1 minute more.","Add the chopped tomatoes, turmeric, chili powder, and garam masala and cook 5 minutes, mashing occasionally, until the tomatoes collapse into a thick, glossy masala that pulls away from the pot.","Stir in the rinsed rice and chickpeas to coat every grain in the spiced paste, then pour in 375ml water and the remaining salt.","Bring to a boil, cover, and simmer on low for 15 minutes, then rest off the heat 5 minutes before fluffing with a fork and finishing with chopped cilantro."],"tip":"Let the tomatoes fry until the oil pools at the edges; rushing the masala is how bland rice happens."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_tempered_curd_rice', '{"id":"ginger_tempered_curd_rice","name":"Ginger-Tempered Curd Rice","emoji":"🍚","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":30,"servings":2,"ing":[{"f":"rice","q":160},{"f":"greek_yogurt","q":300},{"f":"milk","q":100},{"f":"cucumber","q":0.5},{"f":"ginger","q":12},{"f":"olive_oil","q":15},{"f":"cumin","q":3},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Simmer the rice in 400ml water for 18 minutes until slightly overcooked and soft — curd rice should be creamy, not fluffy — then mash it lightly with a spoon.","Let the rice cool until just warm to the touch, about 10 minutes, then fold in the yogurt, milk, and salt until it looks like loose risotto.","Stir in the finely diced cucumber and half the minced ginger for cool crunch against the creamy rice.","Heat the olive oil in a small pan over medium-high, add the cumin and remaining ginger, and fry 45 seconds until the seeds pop and the ginger frizzles golden.","Pour the sizzling tempering over the rice, scatter with cilantro, and serve at room temperature or lightly chilled."],"tip":"Mix the yogurt into warm, not hot, rice unless you enjoy grainy, split curd."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('anda_masala_fried_rice', '{"id":"anda_masala_fried_rice","name":"Anda Masala Fried Rice","emoji":"🍳","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free","gluten-free"],"allergens":["eggs"],"time":30,"servings":2,"ing":[{"f":"rice","q":160},{"f":"eggs","q":4},{"f":"peas_frozen","q":100},{"f":"carrots","q":100},{"f":"onion","q":1},{"f":"ginger","q":10},{"f":"olive_oil","q":25},{"f":"garam_masala","q":3},{"f":"turmeric","q":2},{"f":"scallions","q":0.5},{"f":"salt","q":4}],"steps":["Cook the rice in 350ml water for 15 minutes, then spread it on a plate to cool and dry out — slightly stale-feeling rice fries far better than steamy fresh grains.","Heat half the oil in your largest skillet over high, pour in the beaten eggs with a pinch of salt, and scramble 1 minute into large soft curds; scoop them out just before they look done.","Add the remaining oil, then stir-fry the diced onion, carrots, and ginger for 3 to 4 minutes until the onion picks up brown spots at the edges.","Add the peas, turmeric, and garam masala and toss 1 minute until the pan smells warmly spiced, then add the rice and press it flat to sear for 30-second stretches.","Return the eggs, season with the remaining salt, toss everything twice more, and serve topped with sliced scallions."],"tip":"Pull the eggs while they still glisten; they finish cooking when they rejoin the hot rice."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('masala_omelette', '{"id":"masala_omelette","name":"Masala Omelette","emoji":"🥚","cuisine":"Indian","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["eggs"],"time":15,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"onion","q":0.5},{"f":"tomato","q":1},{"f":"cilantro","q":0.5},{"f":"chili_powder","q":2},{"f":"turmeric","q":1},{"f":"olive_oil","q":25},{"f":"salt","q":3}],"steps":["Whisk the eggs hard for a full minute with the salt, chili powder, and turmeric until pale and slightly frothy — the air is what makes a street-stall omelette puff.","Fold in the finely diced onion, deseeded chopped tomato, and most of the cilantro so every bite carries crunch and spice.","Heat half the oil in a nonstick skillet over medium until it shimmers, then pour in half the egg mixture and swirl to the edges.","Cook 2 to 3 minutes until the underside is lacy and golden brown and the top is barely set, then fold in half and slide onto a plate; repeat with the remaining oil and eggs.","Scatter the last of the cilantro over both omelettes and serve immediately, while the edges are still crisp."],"tip":"Dice the onion truly fine — big chunks weep water and turn your omelette into a sad puddle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('street_style_masala_egg_toast', '{"id":"street_style_masala_egg_toast","name":"Street-Style Masala Egg Toast","emoji":"🍞","cuisine":"Indian","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["gluten","eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"bread","q":4},{"f":"cheddar","q":60},{"f":"butter","q":20},{"f":"scallions","q":1},{"f":"chili_powder","q":2},{"f":"black_pepper","q":1},{"f":"cilantro","q":0.3},{"f":"salt","q":2}],"steps":["Whisk the eggs with the salt, half the chili powder, and most of the sliced scallions until evenly combined.","Melt half the butter in a wide skillet over medium and toast the bread slices 2 minutes per side until golden; set them aside on plates.","Add the remaining butter, pour in the eggs, and scramble slowly for 2 to 3 minutes, dragging a spatula through as soft, custardy folds form — stop while they still shine.","Pile the eggs onto the toasts, top with grated cheddar, and cover the pan lidded over low heat for 1 minute so the cheese slumps and melts.","Finish with black pepper, the remaining chili powder, cilantro, and the last scallions, and eat while the cheese still stretches."],"tip":"Low and slow on the scramble — brown eggs belong in nobody''s street food memories."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baingan_bharta', '{"id":"baingan_bharta","name":"Baingan Bharta","emoji":"🍆","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":[],"time":50,"servings":2,"ing":[{"f":"eggplant","q":1},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.4},{"f":"ginger","q":10},{"f":"olive_oil","q":45},{"f":"cumin","q":4},{"f":"garam_masala","q":3},{"f":"chili_powder","q":2},{"f":"peas_frozen","q":100},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Prick the eggplant all over with a fork, rub with a spoonful of the oil, and roast at 230C for 30 to 35 minutes, turning once, until the skin is blackened and the flesh collapses when pressed.","Let it cool 5 minutes, then peel away the charred skin and roughly mash the smoky flesh with a fork, saving every drop of juice.","Heat the remaining oil in a skillet over medium, crackle the cumin for 30 seconds, then cook the diced onion 7 to 8 minutes until deeply golden before adding the garlic and ginger for 1 minute.","Add the chopped tomatoes, chili powder, and salt and fry 5 minutes until the masala thickens and the oil separates at the edges.","Stir in the mashed eggplant and peas and cook 5 minutes more, stirring often, until everything melds into a rustic, smoky mash; finish with garam masala and a big handful of cilantro."],"tip":"The blacker the eggplant skin, the smokier the bharta — cowardly roasting yields baby food."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('jeera_aloo', '{"id":"jeera_aloo","name":"Jeera Aloo","emoji":"🥔","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"potatoes","q":650},{"f":"olive_oil","q":45},{"f":"cumin","q":6},{"f":"turmeric","q":3},{"f":"chili_powder","q":2},{"f":"ginger","q":8},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.5},{"f":"salt","q":5}],"steps":["Cut the potatoes into 2cm chunks and boil in well-salted water for 8 to 10 minutes until just fork-tender but not falling apart; drain and let them steam dry for 5 minutes.","Heat the oil in your widest skillet over medium-high until it shimmers, then add the cumin and let it crackle and darken for 30 seconds.","Add the minced ginger, turmeric, and chili powder, swirl for 10 seconds, then tumble in the potatoes and toss to coat them golden.","Spread the potatoes in one layer and leave them alone for 3 to 4 minutes at a time, flipping only when the undersides are crusty and browned — about 12 minutes total.","Season with the remaining salt, squeeze the lemon over, and toss with chopped cilantro before serving hot."],"tip":"Fight the urge to stir; potatoes only crisp when you leave them alone long enough to feel neglected."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cabbage_peas_poriyal', '{"id":"cabbage_peas_poriyal","name":"Cabbage and Pea Poriyal","emoji":"🥬","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":["nuts"],"time":25,"servings":2,"ing":[{"f":"cabbage","q":0.5},{"f":"peas_frozen","q":150},{"f":"cashews","q":50},{"f":"olive_oil","q":25},{"f":"turmeric","q":3},{"f":"cumin","q":4},{"f":"ginger","q":10},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Shred the cabbage into thin ribbons no wider than your pinky so it cooks fast and stays sweet rather than sulfurous.","Heat the oil in a wok or wide skillet over medium-high, fry the cashews 2 minutes until golden, then add the cumin and minced ginger and sizzle 30 seconds.","Stir in the turmeric, then add the cabbage with the salt and toss vigorously to coat every ribbon yellow.","Stir-fry 5 to 6 minutes until the cabbage wilts and picks up light brown edges but still keeps a gentle crunch, then add the peas and cook 2 minutes more.","Kill the heat, squeeze the lemon over the pan, and finish with cilantro; serve hot as a side or heap it over rice."],"tip":"Stop cooking while the cabbage still squeaks a little — mush is the enemy of a good poriyal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_matar_sabzi', '{"id":"mushroom_matar_sabzi","name":"Mushroom Matar Sabzi","emoji":"🍄","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"mushrooms","q":400},{"f":"peas_frozen","q":200},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"coconut_milk","q":150},{"f":"olive_oil","q":20},{"f":"garam_masala","q":4},{"f":"cumin","q":3},{"f":"turmeric","q":2},{"f":"cilantro","q":0.5},{"f":"salt","q":4}],"steps":["Heat the oil in a wide skillet over high and sear the quartered mushrooms in a single layer for 5 to 6 minutes, tossing only twice, until browned and squeaky-firm; set aside.","Lower to medium, crackle the cumin 30 seconds, then cook the diced onion 6 minutes until golden before adding the garlic and ginger for 1 minute.","Add the chopped tomatoes, turmeric, and salt and fry 5 minutes, mashing as they soften, until the masala turns jammy and the oil beads at the edges.","Return the mushrooms with the peas and coconut milk and simmer 4 to 5 minutes until the sauce clings thickly rather than pooling.","Stir in the garam masala, rest the pan 2 minutes off the heat, and serve strewn with cilantro."],"tip":"Crowded mushrooms steam instead of sear, so give them elbow room even if it means two batches."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tandoori_gobi_sabzi', '{"id":"tandoori_gobi_sabzi","name":"Tandoori Roasted Gobi with Chickpeas","emoji":"🌶️","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":45,"servings":2,"ing":[{"f":"cauliflower","q":1},{"f":"chickpeas","q":240},{"f":"greek_yogurt","q":150},{"f":"olive_oil","q":30},{"f":"garam_masala","q":5},{"f":"paprika","q":4},{"f":"turmeric","q":2},{"f":"chili_powder","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Heat the oven to 220C and whisk the yogurt with half the oil, the grated garlic and ginger, garam masala, paprika, turmeric, chili powder, and salt into a thick brick-red marinade.","Cut the cauliflower into large florets, toss them in the marinade until every craggy surface is coated, and let them sit 10 minutes while the oven heats.","Spread the florets on a parchment-lined sheet pan with space between them and roast 20 minutes until the yogurt crust starts to char at the tips.","Toss the chickpeas with the remaining oil, scatter them around the cauliflower, and roast 12 to 15 minutes more until the florets are tender inside their smoky shell and the chickpeas crackle.","Squeeze the lemon over the hot pan and shower with cilantro; serve straight from the tray while the edges are still crisp."],"tip":"Charred yogurt tips are the whole point — if nothing is blackened, your oven is being too polite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('green_bean_carrot_thoran', '{"id":"green_bean_carrot_thoran","name":"Green Bean and Carrot Thoran","emoji":"🥕","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free","low-carb"],"allergens":[],"time":25,"servings":2,"ing":[{"f":"green_beans","q":300},{"f":"carrots","q":250},{"f":"coconut_milk","q":200},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"cumin","q":4},{"f":"turmeric","q":3},{"f":"black_pepper","q":1},{"f":"salt","q":4}],"steps":["Chop the green beans into 1cm pieces and dice the carrots the same size — thoran is all about small, even cuts that cook quickly and catch the coconut.","Heat the oil in a wide skillet over medium-high and sizzle the cumin for 30 seconds until fragrant and popping.","Add the diced onion and garlic and cook 3 minutes until translucent, then stir in the turmeric, beans, carrots, and salt.","Splash in 60ml water, cover, and steam 5 to 6 minutes until the vegetables are tender-crisp and vividly colored.","Uncover, pour in the coconut milk, and simmer hard for 3 to 4 minutes, stirring, until it reduces to a rich coating rather than a sauce; finish with black pepper and serve."],"tip":"Reduce the coconut milk until it clings — a thoran should be dressed, not drowning."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('palak_cottage_cheese_sabzi', '{"id":"palak_cottage_cheese_sabzi","name":"Palak Cottage Cheese Sabzi","emoji":"🌿","cuisine":"Indian","meal":["lunch","dinner"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"spinach","q":350},{"f":"cottage_cheese","q":450},{"f":"onion","q":1},{"f":"tomato","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"butter","q":25},{"f":"olive_oil","q":10},{"f":"garam_masala","q":4},{"f":"cumin","q":3},{"f":"salt","q":4}],"steps":["Wilt the spinach in a dry pot over high heat for 2 to 3 minutes, stirring, until it collapses to a fraction of its volume, then blitz it to a coarse, flecked puree with a splash of water.","Heat the olive oil with half the butter in a deep skillet over medium, crackle the cumin 30 seconds, then cook the diced onion 6 to 7 minutes until golden brown at the edges.","Add the garlic and ginger for 1 minute, then the chopped tomato and salt, frying 4 minutes until the masala turns soft and jammy.","Pour in the spinach puree and simmer 5 minutes, stirring, until it darkens and thickens enough to hold a spoon trail.","Fold in the cottage cheese and garam masala, warm gently for 2 minutes without boiling so the curds stay creamy, and finish with the remaining butter swirled on top."],"tip":"Keep the heat gentle after the cottage cheese goes in — boiled curds turn squeaky and sulk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('kung_pao_style_chicken', '{"id":"kung_pao_style_chicken","name":"Kung Pao-Style Chicken with Cashews","emoji":"🥡","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","nuts","sesame"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"rice","q":120},{"f":"cashews","q":40},{"f":"bell_pepper","q":2},{"f":"scallions","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":10},{"f":"soy_sauce","q":45},{"f":"honey","q":20},{"f":"sugar","q":5},{"f":"chili_powder","q":4},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"salt","q":2}],"steps":["Start the rice in a small pot with 300ml of salted water, cover, and simmer on low for 15 minutes while you cook everything else.","Cut the chicken into 2cm cubes, toss with half the soy sauce, and let it sit 10 minutes while you dice the peppers and stir the remaining soy sauce together with the honey, sugar, and chili powder into a glossy sauce.","Heat the olive oil in a wok or large skillet over high heat until it shimmers, then sear the chicken in a single layer for 2 minutes per side until deeply golden at the edges; transfer to a plate.","Toast the cashews, garlic, and grated ginger in the same pan for 60 seconds until fragrant and lightly bronzed, then add the peppers and stir-fry 2 minutes so they blister but stay crisp.","Return the chicken with the sauce and let it bubble hard for 90 seconds until it clings to every piece like lacquer, then kill the heat and stir in the sesame oil and sliced scallions.","Spoon over the rice and serve immediately, while the cashews still crunch."],"tip":"Get every ingredient chopped and sauced before the pan gets hot — a wok waits for no one."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_fried_rice_takeout_style', '{"id":"shrimp_fried_rice_takeout_style","name":"Takeout-Style Shrimp Fried Rice","emoji":"🍤","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":350},{"f":"rice","q":150},{"f":"eggs","q":2},{"f":"peas_frozen","q":100},{"f":"carrots","q":100},{"f":"scallions","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":8},{"f":"soy_sauce","q":40},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":20},{"f":"black_pepper","q":2}],"steps":["Cook the rice in 350ml of water for 15 minutes, then spread it on a tray to cool and dry out — dry grains fry, wet grains steam.","Heat half the olive oil in a wide skillet over high heat and sear the shrimp 90 seconds per side until pink and curled with a hint of char, then set them aside.","Add the remaining oil and scramble the eggs for 30 seconds until just barely set, pushing them to one side of the pan.","Tip in the diced carrots, garlic, and grated ginger and stir-fry 2 minutes until the carrots soften slightly and the garlic smells toasty.","Add the cooled rice and peas, pressing the rice against the hot pan in stages so it crackles and picks up golden spots, about 3 minutes.","Return the shrimp, splash in the soy sauce around the pan''s edge so it sizzles and caramelizes, then finish with sesame oil, black pepper, and sliced scallions."],"tip":"Day-old rice from the fridge is the fried-rice cheat code — cook it in the morning if you''re planning ahead."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_beef_broccoli_stirfry', '{"id":"ginger_beef_broccoli_stirfry","name":"Ginger Beef and Broccoli over Rice","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"broccoli","q":450},{"f":"rice","q":120},{"f":"soy_sauce","q":45},{"f":"honey","q":15},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"broth","q":100},{"f":"sesame_oil","q":10},{"f":"scallions","q":1},{"f":"black_pepper","q":2}],"steps":["Set the rice simmering in 300ml of water with the lid on for 15 minutes, then leave it covered off the heat to steam.","Brown the beef in a dry, screaming-hot skillet for 5 to 6 minutes, breaking it into rough crumbles and letting it sit undisturbed between stirs so it develops crusty, caramelized edges.","Push the beef aside and bloom the minced garlic and ginger in the rendered fat for 45 seconds until your kitchen smells like the good takeout place.","Add the broccoli florets and broth, cover, and steam 3 minutes until the broccoli turns vivid green and just tender at the stem.","Uncover, stir in the soy sauce and honey, and boil hard for 2 minutes until the liquid reduces to a glossy coating that clings to the florets.","Finish with sesame oil, black pepper, and scallions, and pile it all over the steamed rice."],"tip":"Resist stirring the beef constantly — the brown crust it forms while you ignore it is where all the flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_garlic_pork_stirfry', '{"id":"honey_garlic_pork_stirfry","name":"Honey-Garlic Pork Stir-Fry","emoji":"🍯","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"rice","q":140},{"f":"bell_pepper","q":1},{"f":"zucchini","q":1},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"honey","q":30},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"black_pepper","q":2}],"steps":["Get the rice going in 350ml of water, covered on low, for 15 minutes while you slice the pork into thin strips against the grain.","Whisk the honey, soy sauce, and minced garlic into a sticky sauce and set it within arm''s reach of the stove.","Heat the olive oil in a large skillet over high heat and sear the pork in two batches, 2 minutes per batch, until the strips are golden and just cooked through; crowd the pan and you''ll boil it instead.","Stir-fry the sliced onion, pepper, and half-moons of zucchini in the same pan for 3 minutes until charred in spots but still snappy.","Return the pork, pour in the sauce, and toss over high heat for 2 minutes until it bubbles down to a lacquered glaze that coats everything.","Turn off the heat, add the sesame oil and a big grind of black pepper, and serve over the rice while the glaze is still glossy."],"tip":"Freeze the pork for 20 minutes before slicing and it cuts into tidy, paper-thin strips like a butcher did it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_corn_egg_drop_soup', '{"id":"chicken_corn_egg_drop_soup","name":"Chicken and Sweet Corn Egg Drop Soup","emoji":"🥣","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"chicken_thigh","q":350},{"f":"corn_frozen","q":300},{"f":"eggs","q":3},{"f":"broth","q":1200},{"f":"rice","q":80},{"f":"ginger","q":15},{"f":"scallions","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"black_pepper","q":3},{"f":"salt","q":3}],"steps":["Bring the broth to a gentle boil with the sliced ginger, then add the chicken thighs whole and simmer 15 minutes until they''re cooked through and the broth tastes rich.","Lift out the chicken, shred it with two forks, and return it to the pot along with the rice; simmer 12 minutes more until the grains are tender and the soup thickens slightly.","Stir in the corn and soy sauce and let everything bubble for 3 minutes until the corn is sweet and hot.","Beat the eggs well, then pour them into the simmering soup in a thin stream while stirring slowly in one direction — they will bloom into silky golden ribbons.","Kill the heat, season with salt and plenty of black pepper, and finish with sesame oil and sliced scallions.","Ladle into deep bowls and serve steaming, when the egg ribbons are at their softest."],"tip":"Stir slowly and pour slower — dump the eggs in fast and you get scrambled soup instead of silk."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_lo_mein_takeout_style', '{"id":"chicken_lo_mein_takeout_style","name":"Chicken Lo Mein with Charred Cabbage","emoji":"🍜","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"spaghetti","q":180},{"f":"chicken_thigh","q":300},{"f":"cabbage","q":0.3},{"f":"carrots","q":100},{"f":"mushrooms","q":100},{"f":"scallions","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":10},{"f":"soy_sauce","q":50},{"f":"sugar","q":8},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":10}],"steps":["Boil the spaghetti 2 minutes shy of the package time, drain, and toss with a third of the sesame oil so the strands stay loose and springy.","Slice the chicken thighs into thin strips and stir the soy sauce and sugar together into a quick lo mein sauce.","Heat the olive oil in your widest skillet over high heat and sear the chicken 4 to 5 minutes until browned at the edges and cooked through, then push it to the side.","Add the shredded cabbage, carrot matchsticks, and sliced mushrooms and stir-fry 3 minutes until the cabbage picks up charred spots but keeps its crunch.","Add the garlic and ginger for 30 fragrant seconds, then tumble in the noodles and sauce and toss with tongs for 2 minutes until every strand is slick and mahogany-brown.","Finish with the remaining sesame oil and scallions and eat straight from the pan if no one is watching."],"tip":"Undercooked pasta is the secret — it finishes in the sauce and gets that chewy takeout-noodle bounce."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mapo_style_tofu_skillet', '{"id":"mapo_style_tofu_skillet","name":"Mapo-Style Tofu with Turkey over Rice","emoji":"🌶️","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"ground_turkey","q":200},{"f":"rice","q":140},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"scallions","q":1},{"f":"soy_sauce","q":40},{"f":"chili_powder","q":6},{"f":"sugar","q":5},{"f":"broth","q":200},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Simmer the rice in 350ml of water, covered, for 15 minutes, and cut the tofu into 2cm cubes while it cooks.","Heat the olive oil in a deep skillet over medium-high and brown the turkey for 4 minutes, pressing it into small crumbles until it sizzles and turns golden.","Add the minced garlic, ginger, and chili powder and fry 60 seconds until the oil turns brick-red and smells warm and spicy.","Pour in the broth, soy sauce, and sugar, slide in the tofu cubes, and simmer gently for 6 to 8 minutes so the tofu drinks up the sauce — stir by shaking the pan, not with a spoon, to keep the cubes whole.","When the sauce has reduced to a loose, spoonable gravy, turn off the heat and drizzle in the sesame oil.","Shower with scallions and ladle generously over the hot rice."],"tip":"Treat the tofu like it''s fragile china — swirl the pan instead of stirring and every cube arrives at the table intact."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('egg_foo_young_mushroom_gravy', '{"id":"egg_foo_young_mushroom_gravy","name":"Egg Foo Young with Mushroom Gravy","emoji":"🍳","cuisine":"Asian","meal":["breakfast","dinner"],"diets":["dairy-free","low-carb"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"mushrooms","q":150},{"f":"cabbage","q":0.2},{"f":"carrots","q":50},{"f":"scallions","q":1},{"f":"broth","q":250},{"f":"soy_sauce","q":20},{"f":"flour","q":12},{"f":"sesame_oil","q":5},{"f":"olive_oil","q":20},{"f":"black_pepper","q":2}],"steps":["Make the gravy first: whisk the flour into the cold broth with the soy sauce, then simmer 3 to 4 minutes, whisking, until it thickens enough to coat a spoon; stir in the sesame oil and keep warm.","Sauté half the mushrooms in a dry pan for 3 minutes until browned and add them to the gravy.","Beat the eggs in a big bowl and fold in the remaining sliced mushrooms, finely shredded cabbage, grated carrot, most of the scallions, and a good grind of pepper.","Heat the olive oil in a skillet over medium-high until it ripples, then ladle in half-cup portions of the egg mixture to form thick pancakes.","Fry each patty 2 to 3 minutes per side until puffed, golden brown, and set in the middle — they should jiggle slightly, not slosh.","Stack the patties, drown them in the hot mushroom gravy, and top with the last of the scallions."],"tip":"A slightly overcrowded egg batter is the goal here — you want pancakes that are mostly vegetables held together by sheer eggy willpower."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_egg_roll_bowls', '{"id":"turkey_egg_roll_bowls","name":"Egg Roll in a Bowl with Ground Turkey","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"cabbage","q":0.5},{"f":"carrots","q":150},{"f":"scallions","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"soy_sauce","q":45},{"f":"sugar","q":8},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":10},{"f":"black_pepper","q":2}],"steps":["Heat the olive oil in your largest skillet over high heat and brown the turkey for 5 to 6 minutes, breaking it up and letting it crisp at the edges before you stir.","Add the minced garlic and ginger and cook 60 seconds until fragrant enough to make the neighbors curious.","Pile in the shredded cabbage and carrot matchsticks — it will look like too much, and it is not — and toss for 4 to 5 minutes until the cabbage wilts to half its volume but keeps a squeak of crunch.","Stir the soy sauce and sugar together, pour it over, and toss for 1 minute more so everything glistens.","Off the heat, add the sesame oil, sliced scallions, and a heavy grind of black pepper.","Serve in deep bowls — all the flavor of an egg roll, none of the deep fryer."],"tip":"Shred the cabbage as thin as you can manage; wide ribbons steam, thin ribbons fry."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('teriyaki_style_salmon_rice_bowls', '{"id":"teriyaki_style_salmon_rice_bowls","name":"Honey-Soy Glazed Salmon Rice Bowls","emoji":"🍣","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":350},{"f":"rice","q":140},{"f":"broccoli","q":300},{"f":"soy_sauce","q":45},{"f":"honey","q":25},{"f":"ginger","q":10},{"f":"garlic","q":0.3},{"f":"sesame_oil","q":8},{"f":"scallions","q":0.5},{"f":"olive_oil","q":10}],"steps":["Cook the rice in 350ml of water, covered on low, for 15 minutes while you simmer the soy sauce, honey, grated ginger, and minced garlic in a small pan for 3 to 4 minutes until it reduces to a syrup that coats a spoon.","Pat the salmon dry and cut it into two portions — dry skin is the difference between crisp and sad.","Heat the olive oil in a nonstick skillet over medium-high and lay the salmon in skin-side down, pressing gently for the first 20 seconds so the skin sears flat; cook 4 minutes until the sides turn opaque halfway up.","Flip, add the broccoli florets around the fish with a splash of water, cover, and cook 3 minutes so the broccoli steams bright green while the salmon finishes to a blushing medium.","Brush the glaze thickly over the salmon and let it bubble in the pan for 30 seconds until sticky and lacquered.","Build bowls of rice, broccoli, and glazed salmon, drizzle any remaining sauce over the top, and finish with sesame oil and scallions."],"tip":"The glaze goes on at the very end — honey in a hot pan too early turns from lacquer to charcoal with alarming speed."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('singapore_curry_rice_noodles', '{"id":"singapore_curry_rice_noodles","name":"Singapore-Style Curry Rice Noodles","emoji":"🍛","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice_noodles","q":160},{"f":"edamame_frozen","q":200},{"f":"bell_pepper","q":1},{"f":"cabbage","q":0.2},{"f":"carrots","q":100},{"f":"onion","q":0.5},{"f":"scallions","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"curry_powder","q":8},{"f":"turmeric","q":3},{"f":"soy_sauce","q":40},{"f":"sugar","q":6},{"f":"lime","q":1},{"f":"sesame_oil","q":12},{"f":"olive_oil","q":15}],"steps":["Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still slightly firm, then drain and snip them once or twice with scissors for easier tossing.","Heat the olive oil in a wok over high heat and stir-fry the sliced onion, pepper strips, shredded cabbage, and carrot matchsticks for 3 minutes until the edges char but the centers stay crisp.","Add the garlic, ginger, curry powder, and turmeric and toast for 45 seconds, stirring constantly, until the spices bloom golden and the whole pan smells like a hawker stall.","Tip in the edamame, noodles, soy sauce, and sugar and toss vigorously with tongs for 2 to 3 minutes until every strand turns sunset-yellow and the edamame is heated through.","Turn off the heat, squeeze the lime over everything, and stir in the sesame oil and scallions.","Taste for balance — it should hit salty, tangy, and warm all at once — and serve piping hot."],"tip":"Toast the curry powder in the oil, not the sauce — 45 seconds of direct heat unlocks flavors that simmering never will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hot_sour_mushroom_tofu_soup', '{"id":"hot_sour_mushroom_tofu_soup","name":"Hot and Sour Mushroom Tofu Soup","emoji":"🍲","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":40,"servings":4,"ing":[{"f":"tofu","q":550},{"f":"mushrooms","q":300},{"f":"broth","q":1200},{"f":"rice","q":200},{"f":"eggs","q":3},{"f":"carrots","q":100},{"f":"balsamic_vinegar","q":30},{"f":"soy_sauce","q":45},{"f":"ginger","q":15},{"f":"black_pepper","q":4},{"f":"sesame_oil","q":20},{"f":"scallions","q":1}],"steps":["Bring the broth to a boil with the sliced ginger, add the rice, and simmer 12 minutes until the grains are nearly tender and the broth has body.","Add the sliced mushrooms and carrot matchsticks and simmer 5 minutes until the mushrooms turn silky and darken the broth.","Cut the tofu into thin batons, slide them in gently, and season with the soy sauce, balsamic vinegar, and an aggressive amount of black pepper — the pepper is the ''hot'' and it should tickle the back of your throat.","Simmer 3 more minutes, then stream in the beaten eggs while stirring slowly in one direction so they set into wispy ribbons.","Off the heat, stir in the sesame oil and taste: add another splash of vinegar if it doesn''t make you pucker just a little.","Serve in deep bowls buried under sliced scallions."],"tip":"Black pepper, not chili, carries this soup — grind in more than feels reasonable and then add one more twist."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('eggplant_garlic_sauce_stirfry', '{"id":"eggplant_garlic_sauce_stirfry","name":"Takeout-Style Eggplant in Garlic Sauce","emoji":"🍆","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":35,"servings":2,"ing":[{"f":"eggplant","q":1.5},{"f":"rice","q":150},{"f":"garlic","q":0.6},{"f":"ginger","q":12},{"f":"scallions","q":1},{"f":"soy_sauce","q":45},{"f":"sugar","q":12},{"f":"balsamic_vinegar","q":15},{"f":"chili_powder","q":3},{"f":"olive_oil","q":30},{"f":"sesame_oil","q":10},{"f":"salt","q":3}],"steps":["Start the rice in 350ml of salted water, covered on low, for 15 minutes while you cut the eggplant into fat 3cm wedges and salt them for 10 minutes to draw out moisture; pat them very dry.","Stir the soy sauce, sugar, balsamic vinegar, chili powder, and 60ml of water into a sweet-savory sauce.","Heat the olive oil in a wide skillet over medium-high until shimmering and fry the eggplant in a single layer, turning every 2 minutes, for 8 to 10 minutes total until deeply browned, collapsed, and custardy inside.","Clear a space in the pan and sizzle the minced garlic and ginger for 45 seconds until golden and heady.","Pour in the sauce and simmer 2 minutes, turning the eggplant gently, until the liquid reduces to a dark, sticky glaze that clings to every wedge.","Finish with sesame oil and scallions and serve over the rice, spooning any stray glaze on top."],"tip":"Salting and drying the eggplant first means it fries instead of drinking the entire bottle of oil — your wedges and your wallet will thank you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_chicken_satay_skillet', '{"id":"peanut_chicken_satay_skillet","name":"Skillet Chicken Satay with Peanut Sauce","emoji":"🍗","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["nuts","gluten","soy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":300},{"f":"peanut_butter","q":40},{"f":"coconut_milk","q":120},{"f":"soy_sauce","q":20},{"f":"honey","q":10},{"f":"lime","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":8},{"f":"rice","q":110},{"f":"cucumber","q":0.5},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10}],"steps":["Slice the chicken into long, thumb-width strips and toss them with half the soy sauce, the grated ginger, and one minced garlic clove; let them sit for 10 minutes while the rice simmers in salted water for 15 minutes until tender.","Whisk the peanut butter, coconut milk, remaining soy sauce, honey, remaining garlic, and the juice of half the lime in a small saucepan over low heat until the sauce is glossy and coats a spoon, about 3 minutes.","Heat the olive oil in a large skillet over medium-high heat until it shimmers, then lay the chicken strips in a single layer and cook undisturbed for 3 minutes until deeply golden on the first side.","Flip and cook 2 to 3 minutes more until the strips are firm and cooked through, then pull the pan off the heat.","Pile the rice into bowls, fan the chicken over the top, spoon on the warm peanut sauce, and finish with thin cucumber half-moons, torn cilantro, and the remaining lime cut into wedges."],"tip":"If your peanut sauce seizes into paste, whisk in warm water a spoonful at a time — it forgives faster than a group chat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('thai_peanut_chicken_curry', '{"id":"thai_peanut_chicken_curry","name":"Peanut Coconut Chicken Thigh Curry","emoji":"🍛","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","gluten-free","high-protein"],"allergens":["nuts"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":280},{"f":"coconut_milk","q":150},{"f":"peanut_butter","q":25},{"f":"curry_powder","q":8},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"rice","q":100},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":3}],"steps":["Start the rice in simmering salted water and set a timer for 15 minutes, then cut the chicken thighs into bite-size chunks and season them with salt.","Heat the oil in a deep skillet over medium-high heat and brown the chicken hard for 4 minutes per side until the edges caramelize, then push it aside and soften the sliced onion and bell pepper for 3 minutes.","Stir in the minced garlic, grated ginger, and curry powder and toast for 30 seconds until the pan smells like a spice market.","Pour in the coconut milk, whisk in the peanut butter, and simmer gently for 8 to 10 minutes until the sauce thickens enough to leave a trail behind a spoon and the chicken is cooked through.","Squeeze in half the lime, taste for salt, and serve over the rice with cilantro leaves and lime wedges."],"tip":"Brown the thighs like you mean it — pale chicken makes a curry that tastes apologetic."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_shrimp_noodle_soup', '{"id":"coconut_lime_shrimp_noodle_soup","name":"Coconut-Lime Shrimp Noodle Soup","emoji":"🍜","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free","gluten-free"],"allergens":["shellfish"],"time":35,"servings":4,"ing":[{"f":"shrimp","q":450},{"f":"coconut_milk","q":400},{"f":"broth","q":750},{"f":"rice_noodles","q":150},{"f":"mushrooms","q":200},{"f":"ginger","q":20},{"f":"garlic","q":0.3},{"f":"lime","q":2},{"f":"scallions","q":1},{"f":"cilantro","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":4}],"steps":["Warm the oil in a soup pot over medium heat and sizzle the sliced ginger and smashed garlic for 1 minute until fragrant but not browned.","Add the sliced mushrooms and cook for 4 minutes until they release their liquid and start to squeak against the spoon, then pour in the broth and coconut milk and bring to a bare simmer.","Season with salt and let the broth steep for 10 minutes at a gentle bubble so the ginger perfumes every drop; do not boil hard or the coconut milk will look curdled.","Slide in the shrimp and simmer 2 to 3 minutes, just until they curl into loose commas and turn opaque pink.","Meanwhile soak the rice noodles in boiling water for 5 minutes until pliable, drain, and divide among four bowls, then ladle the soup over and finish with lime juice, sliced scallions, and a generous handful of cilantro."],"tip":"Add the lime juice off the heat — boiled lime goes bitter and sulky, like anyone forced to work in a hot kitchen."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_peanut_stirfry', '{"id":"crispy_tofu_peanut_stirfry","name":"Crispy Tofu Stir-Fry with Peanut-Maple Glaze","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts","gluten","soy","sesame"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"broccoli","q":300},{"f":"carrots","q":100},{"f":"peanut_butter","q":40},{"f":"soy_sauce","q":25},{"f":"maple_syrup","q":15},{"f":"sesame_oil","q":10},{"f":"rice","q":110},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":15}],"steps":["Press the tofu between paper towels under a heavy pan for 10 minutes, then tear it into rough chunks — ragged edges crisp better than neat cubes — while the rice cooks in salted water for 15 minutes.","Whisk the peanut butter, soy sauce, maple syrup, sesame oil, and the juice of half the lime with 3 tablespoons of warm water until pourable and smooth.","Heat the olive oil in a wide skillet over medium-high heat and fry the tofu without moving it for 4 minutes per side until the crust is deep golden and crackles when nudged; transfer to a plate.","Add the broccoli florets and sliced carrots with a splash of water, cover for 3 minutes to steam them bright green, then uncover and stir-fry with the minced garlic and ginger for 2 minutes more.","Return the tofu, pour in the peanut glaze, and toss for 1 minute until everything is lacquered, then serve over rice with sliced scallions and the remaining lime."],"tip":"Torn tofu shrugs off sogginess; cubed tofu files a complaint."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_peanut_rice_noodle_salad', '{"id":"shrimp_peanut_rice_noodle_salad","name":"Chilled Peanut Shrimp Rice Noodle Salad","emoji":"🥗","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","nuts","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice_noodles","q":130},{"f":"shrimp","q":300},{"f":"peanut_butter","q":35},{"f":"soy_sauce","q":20},{"f":"lime","q":2},{"f":"sugar","q":8},{"f":"garlic","q":0.2},{"f":"cucumber","q":1},{"f":"carrots","q":100},{"f":"cashews","q":30},{"f":"cilantro","q":0.5},{"f":"scallions","q":1},{"f":"sesame_oil","q":10}],"steps":["Soak the rice noodles in just-boiled water for 6 to 8 minutes until tender but still springy, then rinse under cold water until fully chilled and drain well.","Whisk the peanut butter, soy sauce, sugar, minced garlic, sesame oil, and the juice of both limes with 2 tablespoons of warm water into a dressing the texture of heavy cream.","Sear the shrimp in a hot dry nonstick skillet for 90 seconds per side until they blush pink with a few char spots, then slide them onto the noodles to cool slightly.","Toss the noodles and shrimp with the dressing, thin cucumber ribbons, coarsely grated carrot, and most of the cilantro until every strand is coated.","Mound onto plates and shower with chopped cashews, sliced scallions, and the last of the cilantro just before serving."],"tip":"Rinse those noodles cold and mean it — lukewarm noodle salad is just soup that gave up."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('thai_peanut_pork_noodles', '{"id":"thai_peanut_pork_noodles","name":"Peanut Pork and Cabbage Rice Noodles","emoji":"🍝","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["nuts","gluten","soy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":300},{"f":"rice_noodles","q":130},{"f":"peanut_butter","q":30},{"f":"coconut_milk","q":100},{"f":"soy_sauce","q":25},{"f":"cabbage","q":0.3},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Slice the pork loin into thin strips across the grain and toss with a spoonful of the soy sauce; soak the rice noodles in boiling water for 6 minutes until just tender, then drain.","Stir the peanut butter, coconut milk, remaining soy sauce, and the juice of half the lime into a smooth sauce and set it within arm''s reach of the stove.","Get the oil ripping hot in your largest skillet over high heat and sear the pork in a single layer for 2 minutes per side until browned at the edges; transfer to a plate.","Throw the shredded cabbage, minced garlic, and grated ginger into the same pan and stir-fry for 3 minutes until the cabbage wilts but keeps a little crunch.","Return the pork with the noodles and sauce and toss over the heat for 1 to 2 minutes until everything is slick and steaming, then top with scallions and the remaining lime in wedges."],"tip":"Slice the pork while it''s still fridge-cold — floppy room-temperature loin cuts like a rumor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lime_salmon_curry', '{"id":"coconut_lime_salmon_curry","name":"Coconut-Lime Salmon Curry with Spinach","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","gluten-free","high-protein"],"allergens":["fish"],"time":35,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"coconut_milk","q":200},{"f":"curry_powder","q":6},{"f":"turmeric","q":2},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"spinach","q":100},{"f":"rice","q":100},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":3}],"steps":["Simmer the rice in salted water for 15 minutes while you cut the salmon into large 5-centimeter chunks and season them with salt.","Soften the diced onion in the oil over medium heat for 4 minutes until translucent, then add the garlic, ginger, curry powder, and turmeric and stir for 30 seconds until the spices bloom and darken slightly.","Pour in the coconut milk with a splash of water, bring to a gentle simmer, and let it thicken for 5 minutes until it coats the back of a spoon.","Nestle the salmon chunks into the sauce, cover, and poach at the barest bubble for 5 to 6 minutes until the fish flakes at a fork''s suggestion — resist the urge to stir or it will shred.","Fold in the spinach until it collapses, brighten with lime juice, and spoon over rice with a scatter of cilantro."],"tip":"Poach the salmon like it owes you nothing — a violent boil turns silky fish into coconut-flavored erasers."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_turkey_lettuce_wraps', '{"id":"peanut_turkey_lettuce_wraps","name":"Peanut-Ginger Turkey Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["nuts","gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"romaine","q":1},{"f":"peanut_butter","q":30},{"f":"soy_sauce","q":20},{"f":"sugar","q":8},{"f":"ginger","q":12},{"f":"garlic","q":0.3},{"f":"carrots","q":80},{"f":"scallions","q":1},{"f":"lime","q":1},{"f":"sesame_oil","q":8},{"f":"olive_oil","q":10}],"steps":["Whisk the peanut butter, soy sauce, sugar, sesame oil, and the juice of half the lime with a tablespoon of warm water into a spoonable sauce.","Heat the olive oil in a large skillet over medium-high heat and brown the ground turkey for 6 to 7 minutes, breaking it into small crumbles and letting it sit long enough between stirs to pick up golden crusty bits.","Add the grated ginger and minced garlic and cook 1 minute until fragrant, then pour in the peanut sauce and toss until the turkey glistens and the pan sizzles quietly.","Stir in the grated carrot and most of the scallions off the heat so they stay crisp.","Separate the romaine into sturdy cup-shaped leaves, spoon in the warm filling, and finish with the remaining scallions and lime wedges for squeezing at the table."],"tip":"Use the romaine''s inner leaves as cups and shred the floppy outer ones into the filling — no leaf left behind."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_sweet_potato_chickpea_curry', '{"id":"peanut_sweet_potato_chickpea_curry","name":"Peanut Sweet Potato and Chickpea Curry","emoji":"🍠","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":45,"servings":4,"ing":[{"f":"sweet_potatoes","q":600},{"f":"chickpeas","q":350},{"f":"coconut_milk","q":300},{"f":"peanut_butter","q":45},{"f":"crushed_tomatoes","q":300},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"curry_powder","q":10},{"f":"spinach","q":100},{"f":"rice","q":180},{"f":"lime","q":1},{"f":"olive_oil","q":15},{"f":"salt","q":5}],"steps":["Sweat the diced onion in the oil in a Dutch oven over medium heat for 5 minutes until soft and sweet, then stir in the garlic, ginger, and curry powder and toast for 45 seconds until the bottom of the pot looks rusty and smells intense.","Add the sweet potatoes in 3-centimeter chunks, the crushed tomatoes, coconut milk, and 250 ml of water, season with salt, and bring to a simmer.","Cover and cook for 15 minutes, then whisk the peanut butter into a ladleful of the hot liquid and stir it back in along with the chickpeas.","Simmer uncovered for 8 to 10 minutes more until the sweet potato yields to a fork and the sauce has thickened to a lazy blip-blip bubble.","Fold in the spinach until just wilted, wake the whole pot up with lime juice, and serve over rice cooked in salted water for 15 minutes."],"tip":"Temper the peanut butter in a ladleful of the hot sauce first — dropped in cold, it clings to the spoon like a toddler at daycare drop-off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('thai_coconut_chicken_rice_soup', '{"id":"thai_coconut_chicken_rice_soup","name":"Gingery Coconut Chicken and Rice Soup","emoji":"🍲","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free","gluten-free","high-protein"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":400},{"f":"rice","q":120},{"f":"coconut_milk","q":300},{"f":"broth","q":1000},{"f":"ginger","q":20},{"f":"garlic","q":0.4},{"f":"carrots","q":150},{"f":"mushrooms","q":150},{"f":"lime","q":2},{"f":"cilantro","q":0.5},{"f":"scallions","q":1},{"f":"olive_oil","q":15},{"f":"salt","q":4}],"steps":["Warm the oil in a soup pot over medium heat and cook the sliced ginger, minced garlic, and sliced carrots for 3 minutes until the kitchen smells sharp and warm.","Pour in the broth and rice, bring to a boil, then drop to a simmer and lay the whole chicken breasts into the liquid.","Poach gently for 15 minutes until the chicken registers firm and the rice grains have swollen and softened, then lift the chicken onto a cutting board and shred it with two forks.","Stir the sliced mushrooms and coconut milk into the pot and simmer 5 minutes more until the broth turns ivory and the mushrooms are tender.","Return the shredded chicken, season with salt and the juice of one lime, and ladle into bowls topped with cilantro, scallions, and extra lime wedges."],"tip":"Shred the chicken while it''s warm — cold chicken fights the fork, and you have soup to eat."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('thai_peanut_fried_rice', '{"id":"thai_peanut_fried_rice","name":"Peanut and Cashew Fried Rice with Eggs","emoji":"🍳","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","nuts","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice","q":150},{"f":"eggs","q":3},{"f":"peanut_butter","q":25},{"f":"soy_sauce","q":25},{"f":"peas_frozen","q":100},{"f":"carrots","q":100},{"f":"cashews","q":30},{"f":"scallions","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":8},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"lime","q":1}],"steps":["Cook the rice in salted water for 15 minutes, then spread it on a plate to steam dry for 10 minutes — dry, cooled grains fry into distinct nuggets instead of paste.","Whisk the peanut butter with the soy sauce, sesame oil, and 2 tablespoons of warm water into a thin, pourable sauce.","Heat half the olive oil in your widest skillet over high heat, scramble the eggs into soft, glossy curds in about 45 seconds, and scoop them out just shy of set.","Add the remaining oil with the diced carrots, garlic, and ginger and stir-fry for 2 minutes, then add the rice and press it flat, letting it sizzle untouched for 90 seconds to pick up toasty spots.","Toss in the peas, peanut sauce, eggs, and cashews and fry for 2 minutes more until everything is hot and coated, then finish with scallions and lime wedges."],"tip":"Yesterday''s cold rice is this dish''s dream candidate — freshly cooked rice needs that plate-drying intermission or it clumps like wet snow."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('peanut_beef_green_bean_stirfry', '{"id":"peanut_beef_green_bean_stirfry","name":"Peanut-Basil Beef and Green Bean Stir-Fry","emoji":"🥩","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["nuts","gluten","soy"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"green_beans","q":300},{"f":"peanut_butter","q":30},{"f":"coconut_milk","q":100},{"f":"soy_sauce","q":20},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"basil","q":0.5},{"f":"lime","q":1},{"f":"olive_oil","q":10}],"steps":["Stir the peanut butter, coconut milk, soy sauce, and the juice of half the lime into a smooth sauce and keep it by the stove.","Heat the oil in a large skillet over high heat and add the trimmed green beans in a single layer, letting them blister and char in spots for 4 to 5 minutes with only occasional tossing, then move them to a plate.","Brown the ground beef in the same screaming-hot pan for 5 minutes, breaking it into rough crumbles and pouring off excess fat once it''s deeply seared.","Add the minced garlic and grated ginger and cook 1 minute, then return the beans, pour in the peanut sauce, and toss until it bubbles and clings, about 2 minutes.","Kill the heat, tear in the basil leaves so they wilt in the residual steam, and serve with the remaining lime in wedges."],"tip":"Blistered beans need a hot, crowded-free pan — give them elbow room or they steam into sadness."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_banana_rice_porridge', '{"id":"coconut_banana_rice_porridge","name":"Coconut Rice Porridge with Banana and Peanut Butter","emoji":"🍌","cuisine":"Asian","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":30,"servings":2,"ing":[{"f":"rice","q":100},{"f":"coconut_milk","q":250},{"f":"banana","q":2},{"f":"peanut_butter","q":30},{"f":"maple_syrup","q":20},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Combine the rice, coconut milk, 300 ml of water, and the salt in a small saucepan and bring to a boil, then drop to the lowest simmer.","Cook uncovered for 20 to 25 minutes, stirring every few minutes and scraping the bottom, until the grains burst open and the porridge turns thick and creamy enough to hold a spoon trail for a second.","Mash one banana and stir it in with the maple syrup and cinnamon, letting it melt into the porridge for a final 2 minutes of gentle heat.","Ladle into bowls and top with the second banana in coins and a generous swirl of peanut butter loosened with a teaspoon of warm water.","Rest the bowls for 2 minutes before eating — the porridge thickens as it cools and the peanut butter swirl goes pleasantly fudgy."],"tip":"The spottier the banana, the sweeter the porridge — save the pristine yellow ones for people who like disappointment."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_honey_chicken_donburi', '{"id":"soy_honey_chicken_donburi","name":"Soy-Honey Glazed Chicken Donburi","emoji":"🍱","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":35,"servings":2,"ing":[{"f":"chicken_thigh","q":400},{"f":"rice","q":160},{"f":"soy_sauce","q":45},{"f":"honey","q":30},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Rinse the rice until the water runs nearly clear, then simmer it covered with 400ml water for 15 minutes and let it rest off the heat while you cook.","Slice the cucumber into thin coins, toss with the sugar, half the salt, and the sesame oil, and let it sit until the slices go floppy and glassy, about 15 minutes.","Pat the chicken thighs bone-dry, season with the remaining salt, and sear them skin-side down in olive oil over medium-high heat until deeply bronzed, 6 to 7 minutes per side.","Stir the soy sauce, honey, grated ginger, and minced garlic together, pour it over the chicken, and let it bubble and reduce for 2 to 3 minutes until it coats the meat like lacquer.","Slice the chicken against the grain, fan it over bowls of rice, spoon on every drop of glaze, and finish with the pickled cucumber and a flurry of sliced scallions."],"tip":"The glaze goes from lacquer to charcoal in about 30 seconds, so stand guard with your spatula."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('glazed_salmon_pickle_bowl', '{"id":"glazed_salmon_pickle_bowl","name":"Honey-Soy Salmon Bowl with Quick Pickles","emoji":"🍣","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"rice","q":160},{"f":"soy_sauce","q":40},{"f":"honey","q":25},{"f":"ginger","q":10},{"f":"garlic","q":0.1},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"scallions","q":0.5},{"f":"sesame_oil","q":10}],"steps":["Start the rice first: rinse 160g well, simmer covered with 400ml water for 15 minutes, then rest it off the heat with the lid on.","Shave the cucumber into ribbons with a peeler, massage with sugar and salt, and set aside until it weeps and turns translucent, about 10 minutes.","Whisk the soy sauce, honey, grated ginger, and minced garlic into a glaze, then brush half of it over the salmon fillets.","Sear the salmon skin-side down in sesame oil over medium heat for 4 minutes until the skin crackles, flip, pour in the remaining glaze, and baste for 2 more minutes until the fish flakes at a nudge but stays blush-pink inside.","Pile the rice into bowls, break the salmon over the top in big glossy shards, drain and add the cucumber ribbons, and shower with sliced scallions."],"tip":"If the salmon skin sticks to the pan, it just needs 30 more seconds — it releases itself when it''s properly crisp."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tofu_maple_soy_bowl', '{"id":"crispy_tofu_maple_soy_bowl","name":"Crispy Tofu Bowl with Maple-Soy Glaze","emoji":"🥢","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":40,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice","q":160},{"f":"broccoli","q":300},{"f":"soy_sauce","q":45},{"f":"maple_syrup","q":30},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15},{"f":"scallions","q":0.5}],"steps":["Press the tofu between paper towels under a heavy skillet for 15 minutes while the rinsed rice simmers, covered, in 400ml water for 15 minutes.","Slice the cucumber thin, toss with sugar and salt, and let it soften into crunchy-tart pickles while everything else cooks.","Tear the pressed tofu into ragged bite-size chunks — the craggy edges crisp better than neat cubes — and pan-fry in olive oil over medium-high heat, undisturbed for 3 minutes per side, until deeply golden.","Push the tofu aside, add the broccoli florets with a splash of water, and steam-sear for 3 minutes until the stems turn vivid green but still snap.","Pour in the soy sauce, maple syrup, grated ginger, and minced garlic, and toss for 90 seconds until the glaze bubbles thick and clings to every craggy edge.","Serve over rice with the drained pickles, a drizzle of sesame oil, and sliced scallions on top."],"tip":"Torn tofu has three times the surface area of cubed tofu, and surface area is where the crunch lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_shrimp_rice_bowl', '{"id":"sesame_shrimp_rice_bowl","name":"Sesame Shrimp Rice Bowl","emoji":"🍤","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["shellfish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":400},{"f":"rice","q":160},{"f":"peas_frozen","q":150},{"f":"soy_sauce","q":40},{"f":"honey","q":20},{"f":"garlic","q":0.2},{"f":"ginger","q":8},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"sesame_oil","q":15},{"f":"scallions","q":0.5}],"steps":["Get the rinsed rice simmering, covered, with 400ml water for 15 minutes, then leave it to steam off the heat.","Slice the cucumber into half-moons, scrunch with sugar and salt, and set aside to pickle — it should taste bright and sweet-salty by serving time.","Pat the shrimp very dry and sear them in sesame oil over high heat for 90 seconds per side, just until they curl into loose commas and blush pink.","Add the minced garlic and grated ginger for 30 fragrant seconds, then pour in the soy sauce and honey and let it reduce to a syrup that coats the shrimp, about 1 minute.","Stir the frozen peas straight into the hot pan to warm through, then spoon everything over the rice and top with pickles and scallions."],"tip":"A shrimp curled into a tight O is overcooked; you want a relaxed C that still has somewhere to be."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_pork_rice_bowl', '{"id":"ginger_pork_rice_bowl","name":"Ginger-Soy Pork Rice Bowl","emoji":"🍚","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy"],"time":35,"servings":2,"ing":[{"f":"pork_loin","q":400},{"f":"rice","q":160},{"f":"onion","q":1},{"f":"cabbage","q":0.3},{"f":"ginger","q":20},{"f":"soy_sauce","q":45},{"f":"honey","q":15},{"f":"garlic","q":0.2},{"f":"olive_oil","q":15},{"f":"black_pepper","q":1}],"steps":["Simmer the rinsed rice, covered, in 400ml water for 15 minutes, and shred the cabbage into fine, feathery threads for a cool raw nest on the side.","Freeze the pork loin for 10 minutes, then slice it into whisper-thin sheets — the thinner the slice, the more glaze each piece carries.","Whisk the soy sauce, honey, and a full 20 grams of grated ginger into a punchy, throat-warming sauce.","Sear the pork and thinly sliced onion in olive oil over high heat for 3 to 4 minutes until the edges catch and caramelize, then add the minced garlic for 30 seconds.","Pour in the sauce and toss for 2 minutes until it bubbles down to a glossy coat and the onions turn amber and slumped.","Mound the rice into bowls, lean the shredded cabbage against one side, pile on the pork, and grind black pepper over everything."],"tip":"Ten minutes in the freezer turns pork loin from wobbly to sliceable — patience here is basically a knife skill."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_soboro_rice_bowl', '{"id":"beef_soboro_rice_bowl","name":"Beef Soboro Bowl with Green Beans","emoji":"🥩","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"rice","q":160},{"f":"green_beans","q":200},{"f":"soy_sauce","q":40},{"f":"sugar","q":15},{"f":"ginger","q":12},{"f":"garlic","q":0.1},{"f":"cucumber","q":1},{"f":"lime","q":0.5},{"f":"salt","q":3},{"f":"scallions","q":0.5}],"steps":["Set the rinsed rice to simmer, covered, in 400ml water for 15 minutes while you slice the cucumber thin and toss it with lime juice, a pinch of the sugar, and salt to pickle.","Trim the green beans, blanch them in salted boiling water for 2 minutes until squeaky-crisp, and shock them under cold water.","Crumble the ground beef into a dry skillet over medium-high heat and cook, chopping constantly with your spatula, until it breaks into fine, sandy crumbles and browns at the edges, about 5 minutes.","Add the soy sauce, remaining sugar, grated ginger, and minced garlic, and simmer for 3 minutes, stirring, until the liquid vanishes and every crumble is dark and lacquered.","Spoon the soboro over one half of each rice bowl, arrange the green beans and drained pickles over the other, and finish with sliced scallions."],"tip":"Two forks held side by side chop the beef into finer soboro crumbles than any spatula ever will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_tsukune_glaze_bowl', '{"id":"turkey_tsukune_glaze_bowl","name":"Turkey Meatball Bowl with Soy-Honey Lacquer","emoji":"🍡","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["eggs","gluten","soy"],"time":40,"servings":2,"ing":[{"f":"ground_turkey","q":400},{"f":"eggs","q":1},{"f":"rice","q":160},{"f":"scallions","q":1},{"f":"ginger","q":12},{"f":"garlic","q":0.2},{"f":"soy_sauce","q":40},{"f":"honey","q":30},{"f":"cucumber","q":1},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"olive_oil","q":15}],"steps":["Start the rinsed rice simmering, covered, in 400ml water for 15 minutes, and quick-pickle thin cucumber coins with the sugar and half the salt.","Mix the ground turkey with the egg, half the sliced scallions, half the grated ginger, one minced garlic clove, and the remaining salt, then knead for a full minute until the mixture turns tacky — that stickiness is what keeps the meatballs plush.","With wet hands, roll the mixture into 12 golf-ball meatballs and brown them in olive oil over medium heat, turning every 2 minutes, until golden all over and cooked through, about 10 minutes.","Add the soy sauce, honey, and remaining ginger and garlic to the pan and roll the meatballs through the bubbling glaze for 2 minutes until they gleam like polished amber.","Serve five to six meatballs per rice bowl, spoon over the extra glaze, and top with the pickles and the rest of the scallions."],"tip":"Wet hands are the difference between rolling meatballs and wearing them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mushroom_egg_donburi', '{"id":"mushroom_egg_donburi","name":"Soft-Scrambled Mushroom Donburi","emoji":"🍄","cuisine":"Asian","meal":["breakfast","lunch","dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"mushrooms","q":300},{"f":"onion","q":1},{"f":"rice","q":160},{"f":"soy_sauce","q":30},{"f":"honey","q":10},{"f":"sugar","q":5},{"f":"scallions","q":0.5},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Simmer the rinsed rice, covered, in 400ml water for 15 minutes and keep it warm under the lid.","Sear the thickly sliced mushrooms in olive oil over high heat without stirring for 3 minutes, until their cut faces turn mahogany, then add the sliced onion and cook 4 more minutes until soft and sweet.","Pour in the soy sauce, honey, sugar, and 60ml of water, and simmer for 2 minutes so the mushrooms drink up the savory-sweet broth.","Beat the eggs just until the whites and yolks marble together, drizzle them over the simmering pan in a spiral, cover, and cook for 90 seconds — the eggs should be barely set on top, trembling like custard.","Slide the whole silky mixture over bowls of hot rice, drizzle with sesame oil, and finish with scallions."],"tip":"Under-beaten eggs give you ribbons of white and gold; over-beaten eggs give you a uniform yellow blanket, and where''s the drama in that?"}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_soy_edamame_sweet_potato_bowl', '{"id":"maple_soy_edamame_sweet_potato_bowl","name":"Maple-Soy Sweet Potato and Edamame Bowl","emoji":"🍠","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten","soy","sesame"],"time":45,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"edamame_frozen","q":300},{"f":"rice","q":150},{"f":"soy_sauce","q":40},{"f":"maple_syrup","q":25},{"f":"sesame_oil","q":15},{"f":"garlic","q":0.2},{"f":"ginger","q":8},{"f":"cucumber","q":1},{"f":"lime","q":0.5},{"f":"sugar","q":5},{"f":"salt","q":3},{"f":"scallions","q":0.5}],"steps":["Heat the oven to 220C, cube the sweet potatoes into 2cm chunks, toss with half the sesame oil and a pinch of salt, and roast for 25 minutes until the edges caramelize and the centers yield to a fork.","Meanwhile, simmer the rinsed rice, covered, in 375ml water for 15 minutes, and pickle thin cucumber slices in lime juice, sugar, and the remaining salt.","Whisk the soy sauce, maple syrup, grated ginger, minced garlic, and remaining sesame oil into a glossy dressing.","Boil the edamame for 4 minutes, drain well, and toss the hot beans and roasted sweet potatoes with two-thirds of the dressing so they soak it up while steaming.","Build the bowls on a bed of rice, spoon over the remaining dressing, and top with drained pickles and scallions."],"tip":"Crowded sweet potatoes steam and sulk; give them space on the pan and they''ll caramelize like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_avocado_sesame_donburi', '{"id":"tuna_avocado_sesame_donburi","name":"Tuna and Avocado Sesame Rice Bowl","emoji":"🥑","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"tuna_canned","q":280},{"f":"avocado","q":1},{"f":"rice","q":160},{"f":"soy_sauce","q":30},{"f":"honey","q":10},{"f":"sesame_oil","q":15},{"f":"cucumber","q":1},{"f":"lime","q":1},{"f":"sugar","q":5},{"f":"salt","q":2},{"f":"scallions","q":0.5},{"f":"ginger","q":5}],"steps":["Simmer the rinsed rice, covered, in 400ml water for 15 minutes, then fluff it with a fork and let the steam escape for 2 minutes so it isn''t gummy under the toppings.","Slice the cucumber into thin half-moons and toss with sugar, salt, and the juice of half the lime; it should taste like a bright, crunchy counterpoint in 10 minutes.","Whisk the soy sauce, honey, sesame oil, grated ginger, and remaining lime juice into a dressing that tastes sweet, salty, and sharp all at once.","Drain the tuna thoroughly, break it into large flakes, and fold it gently through half the dressing without mashing it to paste.","Fan thin slices of avocado over each bowl of warm rice, mound the tuna alongside, add the drained pickles, and finish with the rest of the dressing and a scattering of scallions."],"tip":"Warm rice plus cold toppings is the whole point — do not refrigerate the assembled bowl into sad uniformity."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('ginger_scallion_chicken_noodle_soup', '{"id":"ginger_scallion_chicken_noodle_soup","name":"Ginger-Scallion Chicken and Rice Noodle Soup","emoji":"🍜","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":45,"servings":4,"ing":[{"f":"chicken_breast","q":500},{"f":"broth","q":1500},{"f":"rice_noodles","q":240},{"f":"ginger","q":25},{"f":"garlic","q":0.3},{"f":"scallions","q":1},{"f":"carrots","q":200},{"f":"mushrooms","q":200},{"f":"spinach","q":150},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"salt","q":3}],"steps":["Slice the ginger into coins and smash them, then simmer with the broth, minced garlic, and the white halves of the scallions for 10 minutes until the kitchen smells like a noodle shop.","Slide in the whole chicken breasts, lower the heat until the surface barely shivers, and poach for 12 to 14 minutes; gentle heat is what keeps them silky instead of stringy.","Lift out the chicken to rest, then add the carrot coins and sliced mushrooms to the broth and simmer for 5 minutes until just tender.","Soak the rice noodles in boiling water for 4 to 6 minutes until pliable but still springy, then drain and divide among four deep bowls.","Shred the chicken with two forks, stir it back into the pot with the soy sauce and spinach, and simmer for 1 minute until the leaves collapse into emerald ribbons.","Ladle the soup over the noodles, drizzle each bowl with sesame oil, and shower with the sliced green scallion tops."],"tip":"If the broth is boiling hard enough to watch, it''s boiling hard enough to ruin the chicken — aim for a lazy shimmer."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('veggie_yakisoba_rice_noodles', '{"id":"veggie_yakisoba_rice_noodles","name":"Vegetable Yakisoba-Style Rice Noodles","emoji":"🥡","cuisine":"Asian","meal":["lunch","dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice_noodles","q":200},{"f":"eggs","q":3},{"f":"cabbage","q":0.3},{"f":"carrots","q":150},{"f":"bell_pepper","q":1},{"f":"scallions","q":1},{"f":"soy_sauce","q":45},{"f":"honey","q":15},{"f":"ginger","q":10},{"f":"garlic","q":0.2},{"f":"sesame_oil","q":15},{"f":"olive_oil","q":15}],"steps":["Soak the rice noodles in boiling water for 4 minutes until bendy but still a touch firm, then drain and toss with the sesame oil so they don''t weld together.","Stir the soy sauce, honey, grated ginger, and minced garlic into a sauce and keep it within arm''s reach — stir-frying waits for no one.","Scramble the beaten eggs in half the olive oil over medium-high heat until just set in soft, glossy curds, about 1 minute, and slide them out onto a plate.","Crank the heat to high, add the remaining oil, and stir-fry the shredded cabbage, carrot matchsticks, and sliced bell pepper for 3 to 4 minutes until charred at the edges but still crunchy.","Add the noodles and sauce and toss with tongs for 2 minutes until every strand is glossed and the sauce sizzles at the pan''s edge, then fold the eggs back in.","Pile into bowls and bury under a generous handful of sliced scallions."],"tip":"Chop everything before the pan gets hot, because a smoking wok has zero respect for your knife skills."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_chicken_cabbage_salad', '{"id":"sesame_chicken_cabbage_salad","name":"Sesame-Soy Chicken and Cabbage Salad","emoji":"🥗","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame","nuts"],"time":30,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"cabbage","q":0.5},{"f":"carrots","q":150},{"f":"cucumber","q":1},{"f":"cashews","q":60},{"f":"scallions","q":0.5},{"f":"cilantro","q":0.5},{"f":"soy_sauce","q":30},{"f":"honey","q":15},{"f":"sesame_oil","q":20},{"f":"lime","q":1},{"f":"ginger","q":8},{"f":"salt","q":3}],"steps":["Poach the chicken breasts in barely simmering salted water for 14 minutes, then rest them for 5 minutes and shred into long, juicy strands with two forks.","Toast the cashews in a dry skillet over medium heat, shaking often, for 3 to 4 minutes until they smell buttery and turn freckled gold, then roughly chop.","Shred the cabbage into fine ribbons, cut the carrots into matchsticks, and slice the cucumber into thin half-moons; toss all three with a pinch of salt and let them sit 5 minutes to season and soften slightly.","Whisk the soy sauce, honey, sesame oil, lime juice, and grated ginger into a dressing that tastes assertively sweet-sharp — the mountain of cabbage will mellow it.","Toss the vegetables, chicken, and dressing together until everything glistens, then fold in the torn cilantro and top with cashews and sliced scallions just before serving."],"tip":"Dress this salad a full 10 minutes before eating — cabbage is the rare green that gets better as it sits and marinates."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_bulgogi_rice_bowls', '{"id":"beef_bulgogi_rice_bowls","name":"Bulgogi-Style Beef Rice Bowls","emoji":"🍚","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":350},{"f":"rice","q":150},{"f":"soy_sauce","q":45},{"f":"honey","q":25},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"onion","q":0.5},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"sesame_oil","q":10}],"steps":["Rinse the rice until the water runs nearly clear, then simmer it covered with 300ml water over low heat for 15 minutes and let it steam off the heat while you cook the beef.","Whisk the soy sauce, honey, grated ginger, and minced garlic into a glossy sauce that coats the back of a spoon.","Set a large skillet over high heat, brown the ground beef with the sliced onion for 6 to 7 minutes, and resist stirring until the bottom crisps into dark, lacy edges.","Pour in the sauce and let it bubble hard for 2 minutes until it reduces to a sticky glaze that clings to every crumble of beef.","Stir in the sesame oil off the heat, then pile the beef over the rice with ribbons of shaved carrot and thin cucumber half-moons.","Serve while the glaze is still shiny and the cucumber is cold for that hot-cold contrast that makes the bowl sing."],"tip":"Let the beef sit untouched in the pan longer than feels polite — those crusty bits are where the flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('soy_ginger_beef_lettuce_wraps', '{"id":"soy_ginger_beef_lettuce_wraps","name":"Soy-Ginger Beef Lettuce Wraps","emoji":"🥬","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"romaine","q":1},{"f":"soy_sauce","q":40},{"f":"honey","q":20},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"onion","q":0.5},{"f":"carrots","q":80},{"f":"cucumber","q":0.5},{"f":"sesame_oil","q":10}],"steps":["Separate the romaine into whole leaves, rinse them, and chill them in ice water so they turn crackling-crisp while you cook.","Brown the ground beef with the diced onion in a dry skillet over medium-high heat for 7 to 8 minutes, breaking it into small crumbles that pick up color on every side.","Stir together the soy sauce, honey, grated ginger, and minced garlic, then pour it over the beef and simmer for 2 minutes until it turns dark and syrupy.","Kill the heat and stir in the sesame oil so its aroma blooms without burning off.","Dry the lettuce leaves, spoon in the glazed beef, and top each cup with matchstick carrots and thin cucumber slices for crunch.","Eat immediately, folded taco-style, over a plate to catch the inevitable drips."],"tip":"The ice-water bath is non-negotiable — limp lettuce turns a wrap into a sad, warm handshake."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_beef_broccoli_stir_fry', '{"id":"korean_beef_broccoli_stir_fry","name":"Sticky Soy-Honey Beef and Broccoli Stir-Fry","emoji":"🥦","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"broccoli","q":400},{"f":"soy_sauce","q":40},{"f":"honey","q":20},{"f":"garlic","q":0.4},{"f":"ginger","q":12},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Cut the broccoli into small florets and steam them in a covered skillet with a splash of water for 3 minutes until bright green but still snappy, then set aside.","Wipe the pan dry, add the olive oil over high heat, and brown the ground beef for 6 to 7 minutes, pressing it flat like a giant patty so it develops a proper crust before you break it up.","Add the minced garlic and grated ginger to the beef and stir for 30 seconds until your kitchen smells like the best takeout place in town.","Return the broccoli, pour in the whisked soy sauce and honey, and toss over high heat for 2 minutes until the sauce reduces to a sticky sheen on every floret.","Drizzle with sesame oil off the heat and serve straight from the skillet while everything still crackles."],"tip":"The smash-then-break-up beef trick doubles your browning — patience for four minutes, chaos afterward."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_beef_fried_rice', '{"id":"korean_beef_fried_rice","name":"Soy-Honey Beef Fried Rice","emoji":"🍳","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame","eggs"],"time":30,"servings":2,"ing":[{"f":"rice","q":130},{"f":"ground_beef","q":250},{"f":"eggs","q":2},{"f":"soy_sauce","q":35},{"f":"honey","q":10},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"carrots","q":100},{"f":"edamame_frozen","q":100},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10}],"steps":["Cook the rice in 260ml water, then spread it on a plate to cool and dry for 10 minutes — slightly stale-feeling rice fries, wet rice smears.","Brown the ground beef in a large skillet over high heat for 5 to 6 minutes until crisp-edged, then push it to one side.","Add the olive oil, diced carrots, and edamame, and stir-fry for 3 minutes until the carrots lose their raw crunch.","Scrape everything aside, crack the eggs into the empty side, and scramble them hard for 30 seconds until just set in soft curds.","Add the rice, breaking clumps with the back of your spoon, then pour the soy sauce, honey, garlic, and ginger over the top and toss for 2 minutes until every grain is glossy and lightly toasted.","Kill the heat, stir through the sesame oil, and taste — the rice should crackle faintly at the bottom of the pan."],"tip":"Day-old rice from the fridge is the fried-rice cheat code; plan tonight''s leftovers like tomorrow''s victory."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_ginger_beef_meatballs', '{"id":"honey_ginger_beef_meatballs","name":"Honey-Ginger Glazed Beef Meatballs","emoji":"🧆","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame","eggs"],"time":40,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"eggs","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"soy_sauce","q":40},{"f":"honey","q":30},{"f":"rice","q":130},{"f":"broccoli","q":200},{"f":"sesame_oil","q":8}],"steps":["Mix the ground beef with the egg, half the grated ginger, and half the minced garlic, working the mixture just until it holds together — overmixing makes meatballs bounce.","Roll into 12 golf-ball-sized meatballs with damp hands and chill them for 10 minutes while the rice simmers in 260ml of water.","Sear the meatballs in a hot, lightly oiled skillet for 8 minutes, turning to brown three sides until they are burnished and crusty.","Add the broccoli florets and a splash of water, cover for 3 minutes, then pour in the soy sauce, honey, and remaining ginger and garlic.","Roll the meatballs through the bubbling glaze for 2 to 3 minutes until it thickens enough to leave a trail when you drag a spoon across the pan.","Finish with sesame oil and serve the meatballs and broccoli heaped over the steamed rice."],"tip":"Damp hands are the difference between rolling meatballs and wearing them."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_beef_rice_soup', '{"id":"korean_beef_rice_soup","name":"Gingery Beef and Rice Soup","emoji":"🍲","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free"],"allergens":["gluten","soy","sesame"],"time":45,"servings":4,"ing":[{"f":"ground_beef","q":500},{"f":"broth","q":1500},{"f":"rice","q":120},{"f":"spinach","q":150},{"f":"carrots","q":150},{"f":"onion","q":1},{"f":"garlic","q":0.5},{"f":"ginger","q":20},{"f":"soy_sauce","q":50},{"f":"sesame_oil","q":15}],"steps":["Brown the ground beef in a large pot over medium-high heat for 6 to 7 minutes until deeply crusted, then spoon off all but a tablespoon of fat.","Add the diced onion, sliced carrots, minced garlic, and grated ginger, and cook for 4 minutes until the onion turns translucent and the ginger perfumes the whole pot.","Pour in the broth and soy sauce, scrape up the browned bits from the bottom, and bring everything to a rolling boil.","Stir in the rice, drop to a gentle simmer, and cook uncovered for 18 to 20 minutes until the grains are tender and the broth turns silky from their starch.","Fold in the spinach off the heat so it wilts into emerald ribbons, then finish each bowl with a drizzle of sesame oil.","Serve steaming, when the broth is savory-sweet and the ginger warms the back of your throat."],"tip":"The soup thickens overnight as the rice keeps drinking — thin leftovers with a splash of water and nobody will know."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('korean_beef_stuffed_peppers', '{"id":"korean_beef_stuffed_peppers","name":"Soy-Glazed Beef Stuffed Peppers","emoji":"🫑","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["gluten","soy","sesame"],"time":50,"servings":2,"ing":[{"f":"bell_pepper","q":3},{"f":"ground_beef","q":350},{"f":"rice","q":100},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"soy_sauce","q":35},{"f":"honey","q":15},{"f":"spinach","q":100},{"f":"sesame_oil","q":8}],"steps":["Heat the oven to 200C, halve the peppers through the stem, scoop out the seeds, and roast the empty shells cut-side up for 10 minutes to give them a head start.","Meanwhile, simmer the rice in 200ml water for 15 minutes, and brown the beef with the diced onion in a hot skillet for 6 minutes until crumbly and crusted.","Stir the soy sauce, honey, garlic, and ginger into the beef and let it bubble for 2 minutes into a dark glaze, then fold in the cooked rice and spinach until the leaves collapse.","Mound the filling generously into the pepper halves, pressing it in so each one is heaped like a small hill.","Bake for 15 to 18 minutes until the peppers slump slightly and the tops of the filling turn crisp and burnished.","Drizzle with sesame oil and rest 5 minutes before serving — the peppers are lava straight from the oven."],"tip":"Pre-roasting the empty peppers means no more biting into a stuffed pepper that crunches like a raw apple."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_ginger_beef_romaine_salad', '{"id":"crispy_ginger_beef_romaine_salad","name":"Crispy Ginger Beef Romaine Salad","emoji":"🥗","cuisine":"Asian","meal":["lunch","dinner"],"diets":["dairy-free","high-protein","low-carb"],"allergens":["gluten","soy","sesame"],"time":25,"servings":2,"ing":[{"f":"ground_beef","q":400},{"f":"romaine","q":1.5},{"f":"cucumber","q":1},{"f":"carrots","q":80},{"f":"onion","q":0.3},{"f":"soy_sauce","q":35},{"f":"sesame_oil","q":12},{"f":"garlic","q":0.3},{"f":"ginger","q":12},{"f":"olive_oil","q":10}],"steps":["Chop the romaine into wide ribbons, slice the cucumber thin, shave the carrots into strips, and sliver the onion, then chill the whole pile while you cook.","Heat a large skillet over high heat until a drop of water skitters, then brown the ground beef for 7 to 8 minutes, undisturbed at first, until it crisps into dark, crunchy nuggets.","Add the minced garlic and grated ginger for the final minute, stirring constantly so they toast without scorching.","Splash in the soy sauce and let it sizzle and evaporate for 30 seconds, seasoning the beef down to the crumb.","Whisk the sesame oil and olive oil with a spoonful of the warm pan juices to make a quick dressing, and toss it with the cold vegetables.","Top the dressed salad with the hot crispy beef and eat immediately, while the contrast between sizzling and icy is at its peak."],"tip":"Hot beef on cold lettuce waits for no one — dress, top, and eat in that order, fast."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka_skillet_eggs', '{"id":"shakshuka_skillet_eggs","name":"Smoky Skillet Shakshuka","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"tomato","q":4},{"f":"eggs","q":4},{"f":"feta","q":60},{"f":"pita","q":2}],"steps":["Warm the olive oil in a wide skillet over medium heat and cook the sliced onion and bell pepper for 8 minutes, until soft and starting to catch color at the edges.","Stir in the minced garlic with a pinch of paprika and cumin, and cook for 60 seconds until fragrant.","Add the chopped tomatoes, season with salt, and simmer for 10 to 12 minutes, until the sauce thickens enough that a spoon dragged through it leaves a brief trail.","Nestle four wells into the sauce with the back of a spoon, crack an egg into each, cover, and cook 5 to 7 minutes until the whites are set but the yolks still wobble.","Crumble the feta over the top, let it soften for a minute, and serve straight from the pan with warm pita for dragging through the sauce."],"tip":"Pull the pan off the heat when the whites look barely underdone — carryover heat finishes eggs faster than your confidence suggests."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mediterranean_hummus_egg_pita', '{"id":"mediterranean_hummus_egg_pita","name":"Fried Egg and Hummus Breakfast Pitas","emoji":"🥙","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten","sesame"],"time":20,"servings":2,"ing":[{"f":"pita","q":2},{"f":"hummus","q":120},{"f":"eggs","q":4},{"f":"olive_oil","q":15},{"f":"tomato","q":1},{"f":"spinach","q":60},{"f":"feta","q":40}],"steps":["Toast the pitas in a dry skillet over medium heat for about a minute per side, until warm, puffed, and freckled brown, then split them open into pockets.","Swipe a thick layer of hummus inside each pita and tuck in the spinach leaves so the heat starts wilting them.","Heat the olive oil in the same skillet over medium-high until it shimmers, crack in the eggs, and fry 2 to 3 minutes until the edges are lacy and crisp while the yolks stay soft.","Slide two eggs into each pita, then pile in the chopped tomato and crumbled feta.","Season with black pepper and a pinch of oregano, and eat immediately over a plate — the yolk will run, and that is the point."],"tip":"Warm the hummus-side of the pita first so it acts like edible glue instead of cold spackle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_mushroom_frittata', '{"id":"spinach_mushroom_frittata","name":"Spinach and Mushroom Frittata","emoji":"🍄","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":35,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"milk","q":60},{"f":"parmesan","q":40},{"f":"mushrooms","q":200},{"f":"spinach","q":150},{"f":"olive_oil","q":20},{"f":"onion","q":0.5},{"f":"garlic","q":0.2}],"steps":["Heat the oven to 190C and whisk the eggs with the milk, half the parmesan, salt, and plenty of black pepper until no streaks remain.","Heat the olive oil in a 25cm ovenproof skillet over medium-high and cook the sliced mushrooms undisturbed for 4 minutes, until browned and squeaking has given way to sizzling.","Add the diced onion and garlic and cook 3 minutes more, then pile in the spinach and stir until it collapses and any liquid evaporates.","Pour in the egg mixture, drag a spatula through it for 30 seconds to form soft curds, then scatter the remaining parmesan on top.","Transfer to the oven and bake 10 to 12 minutes, until the center is just set and puffed at the edges, then rest 5 minutes before slicing into wedges."],"tip":"A frittata that browns on top has already overcooked underneath — pull it while the center still jiggles like it has somewhere to be."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('baked_eggs_florentine_ramekins', '{"id":"baked_eggs_florentine_ramekins","name":"Baked Eggs Florentine","emoji":"🥚","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"spinach","q":200},{"f":"butter","q":15},{"f":"garlic","q":0.2},{"f":"milk","q":80},{"f":"parmesan","q":30},{"f":"bread","q":2}],"steps":["Heat the oven to 180C and butter two ramekins or small gratin dishes generously.","Melt the butter in a skillet over medium heat, sizzle the sliced garlic for 30 seconds, then wilt the spinach in big handfuls until it is glossy and reduced to a fraction of its bravado.","Stir in the milk and half the parmesan, simmer 2 minutes until creamy, then divide the spinach between the ramekins.","Make two hollows in each dish, crack in the eggs, dust with the remaining parmesan, and bake 12 to 15 minutes until the whites are opaque but the yolks still shine.","Meanwhile toast the bread until deeply golden, cut into soldiers, and serve alongside for dunking into the molten centers."],"tip":"Set the ramekins on a preheated baking sheet so the bottoms cook at the same speed as the tops."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('diner_cheddar_omelet', '{"id":"diner_cheddar_omelet","name":"Diner-Style Cheddar Omelet","emoji":"🧀","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":20,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"cheddar","q":80},{"f":"butter","q":20},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"mushrooms","q":100}],"steps":["Melt half the butter in a nonstick skillet over medium-high heat and saute the diced pepper, onion, and mushrooms for 5 minutes, until browned and dry, then scrape onto a plate.","Whisk three eggs with a pinch of salt until completely uniform and slightly frothy — about 30 vigorous seconds.","Melt half the remaining butter over medium heat, pour in the eggs, and pull the setting edges toward the center with a spatula, tilting so raw egg floods the gaps.","When the surface is glossy but no longer liquid, scatter half the cheddar and half the vegetables over one side and fold the omelet over itself.","Slide onto a warm plate, then repeat with the remaining butter, eggs, cheese, and filling for the second omelet."],"tip":"Low confidence and high heat ruin omelets equally — commit to the fold and forgive the wrinkles."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('fried_egg_avocado_sandwich', '{"id":"fried_egg_avocado_sandwich","name":"Crispy Fried Egg and Avocado Sandwich","emoji":"🥪","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"eggs","q":4},{"f":"cheddar","q":50},{"f":"butter","q":15},{"f":"avocado","q":1},{"f":"spinach","q":40}],"steps":["Toast the bread until golden and sturdy, then mash the avocado onto two slices with salt, pepper, and a squeeze of anything acidic you have on hand.","Melt the butter in a skillet over medium-high heat until it foams and just starts to smell nutty.","Crack in the eggs and fry 2 to 3 minutes, spooning butter over the whites, until the edges are shatteringly crisp and browned like lace.","Lay the cheddar over the eggs for the last 30 seconds so it slumps and melts from the residual heat.","Stack spinach, then the cheesy eggs, onto the avocado toast, crown with the remaining slices, press gently, and halve on the diagonal."],"tip":"Mash the avocado all the way to the crust — every under-appointed bite is a small betrayal."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_potato_breakfast_hash', '{"id":"crispy_potato_breakfast_hash","name":"Crispy Potato Hash with Fried Eggs","emoji":"🥔","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"potatoes","q":500},{"f":"olive_oil","q":30},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.2},{"f":"eggs","q":4}],"steps":["Dice the potatoes into 1cm cubes, rinse, and pat thoroughly dry — wet potatoes steam, and steamed potatoes never crisp.","Heat two-thirds of the oil in a heavy skillet over medium-high, add the potatoes in one layer, and leave them alone for 5 full minutes before turning; repeat until deeply golden on most sides, about 15 minutes total.","Add the diced onion, bell pepper, and garlic with a big pinch of salt and paprika, and cook 5 minutes more until the vegetables soften and the pan smells sweet.","Push the hash to the edges, add the remaining oil to the center, and crack in the eggs.","Cover and cook 3 to 4 minutes, until the whites are set and the yolks tremble, then serve straight from the skillet with plenty of black pepper."],"tip":"The spatula is the enemy of crispness — stir half as often as you want to."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('scrambled_egg_breakfast_tacos', '{"id":"scrambled_egg_breakfast_tacos","name":"Soft Scramble Breakfast Tacos","emoji":"🌮","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"eggs","q":4},{"f":"black_beans","q":120},{"f":"cheddar","q":40},{"f":"avocado","q":1},{"f":"olive_oil","q":10}],"steps":["Warm the black beans in a small pan with a splash of water, a pinch of cumin, and salt, mashing a few against the side until they turn saucy.","Char the tortillas directly over a flame or in a dry skillet for 30 seconds per side, until blistered and pliable, then wrap in a towel to stay warm.","Whisk the eggs with salt, heat the oil in a nonstick skillet over medium-low, and stir slowly with a spatula for 3 to 4 minutes until large, custardy curds form — pull the pan off while they still look slightly wet.","Spread beans down the center of each tortilla and top with the soft scramble.","Finish with grated cheddar so it melts on contact, sliced avocado, and a shake of hot sauce if your morning needs the encouragement."],"tip":"Scrambled eggs keep cooking on the tortilla, so undercook them slightly and let physics do the rest."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('potato_egg_breakfast_burrito', '{"id":"potato_egg_breakfast_burrito","name":"Potato and Egg Breakfast Burritos","emoji":"🌯","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"tortillas","q":2},{"f":"eggs","q":4},{"f":"potatoes","q":250},{"f":"cheddar","q":60},{"f":"greek_yogurt","q":60},{"f":"olive_oil","q":15},{"f":"onion","q":0.5}],"steps":["Dice the potatoes small, about 1cm, and fry in the olive oil over medium-high heat with the diced onion, salt, and a pinch of chili powder for 12 minutes, until golden and crisp-edged.","Beat the eggs with a pinch of salt, pour them over the potatoes, and stir gently for 2 minutes until just set into soft curds.","Warm the tortillas in a dry skillet until floppy and lightly speckled, then spread each with a swipe of greek yogurt.","Divide the potato-egg filling and the grated cheddar between the tortillas, fold in the sides, and roll tightly away from you.","Return the burritos seam-side down to the hot skillet for 1 to 2 minutes per side, until golden and sealed, then halve and serve while the cheese still stretches."],"tip":"Toasting the seam first welds the burrito shut — skip it and breakfast becomes a hand-held landslide."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('indian_egg_bhurji', '{"id":"indian_egg_bhurji","name":"Masala Egg Bhurji with Toast","emoji":"🍛","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian"],"allergens":["eggs","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"butter","q":20},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"bread","q":2}],"steps":["Melt the butter in a skillet over medium heat and fry the finely chopped onion with a pinch of salt for 6 minutes, until golden at the edges and sweet-smelling.","Add the minced garlic, a half teaspoon each of turmeric and cumin, and a pinch of chili flakes, and toast for 30 seconds until the spices bloom in the fat.","Stir in the chopped tomatoes and cook 4 to 5 minutes, until they slump into a thick, jammy masala that pulls away from the pan.","Pour in the beaten eggs and scramble briskly, breaking them into small, spice-stained curds — about 2 minutes, stopping while they still glisten.","Shower with fresh black pepper and serve piled onto hot buttered toast in place of roti."],"tip":"Bhurji curds should be small and chaotic, not fluffy and polite — keep the spatula moving."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('punjabi_style_egg_curry', '{"id":"punjabi_style_egg_curry","name":"Weekend Egg Curry with Rice","emoji":"🥘","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"onion","q":1},{"f":"tomato","q":3},{"f":"garlic","q":0.4},{"f":"olive_oil","q":25},{"f":"rice","q":140}],"steps":["Simmer the rice in salted water according to its stubbornness, usually 12 to 15 minutes, then drain and keep covered.","Meanwhile boil the eggs for 9 minutes, shock them in cold water, peel, and score each one lightly so the sauce can get in.","Heat the oil in a deep skillet over medium and fry the sliced onion for 8 minutes until deeply browned, then add the garlic, a teaspoon of garam masala, half a teaspoon of turmeric, and chili to taste, stirring for 30 seconds.","Add the chopped tomatoes and a splash of water and simmer 10 minutes, until the sauce thickens and the oil beads at the edges — the classic sign the masala is done.","Halve the eggs, slide them into the sauce cut-side up for 2 minutes to warm through, and serve ladled over the rice."],"tip":"Browning the onions past your comfort zone is where the entire curry''s flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('breakfast_egg_fried_rice', '{"id":"breakfast_egg_fried_rice","name":"Morning Egg Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["breakfast"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":20,"servings":2,"ing":[{"f":"rice","q":150},{"f":"eggs","q":4},{"f":"edamame_frozen","q":100},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15},{"f":"onion","q":0.5},{"f":"garlic","q":0.2}],"steps":["Cook the rice ahead if you can and chill it — day-old grains fry into separate, chewy pieces instead of clumping into porridge.","Heat half the olive oil in a wok or large skillet over high heat, pour in the beaten eggs, and scramble for 45 seconds into big soft folds, then scoop them out.","Add the remaining oil with the diced onion and garlic and stir-fry 2 minutes, until fragrant and just golden.","Add the rice and edamame, pressing the rice against the hot metal and tossing every 30 seconds for about 4 minutes, until you hear it crackle and see toasted spots.","Return the eggs, splash in the soy sauce around the rim of the pan so it sizzles and caramelizes, toss once more, and finish off the heat with the sesame oil."],"tip":"Soy sauce poured down the hot side of the wok toasts into something smoky; poured on the rice it just makes it soggy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('silky_steamed_eggs_rice_bowl', '{"id":"silky_steamed_eggs_rice_bowl","name":"Silky Steamed Egg Rice Bowls","emoji":"🥣","cuisine":"Asian","meal":["breakfast"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"eggs","q":4},{"f":"rice","q":130},{"f":"soy_sauce","q":15},{"f":"sesame_oil","q":8},{"f":"spinach","q":100},{"f":"garlic","q":0.1}],"steps":["Start the rice in salted water and simmer, covered, for 12 to 15 minutes until tender, then let it rest off the heat.","Whisk the eggs with one and a half times their volume of warm water and a pinch of salt, then pour through a fine strainer into two heatproof bowls to remove every bubble and streak.","Cover each bowl tightly with foil and steam over gently simmering water for 10 to 12 minutes, until the custard is set but quivers like fresh tofu when nudged.","While the eggs steam, wilt the spinach with the sliced garlic and a few drops of sesame oil in a hot pan for about a minute.","Spoon rice into bowls, slide the trembling custard on top with the spinach alongside, and finish with the soy sauce and remaining sesame oil drizzled over the surface."],"tip":"A raging boil turns silk into sponge — the steamer should whisper, not roar."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_ricotta_pancakes_2', '{"id":"lemon_ricotta_pancakes_2","name":"Lemon Ricotta Pancakes","emoji":"🥞","cuisine":"Italian","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":30,"servings":2,"ing":[{"f":"ricotta","q":200},{"f":"flour","q":120},{"f":"eggs","q":2},{"f":"milk","q":120},{"f":"sugar","q":25},{"f":"lemon","q":1},{"f":"butter","q":20},{"f":"maple_syrup","q":60},{"f":"berries","q":100},{"f":"salt","q":2}],"steps":["Separate the eggs, then whisk the yolks with the ricotta, milk, all the lemon zest, and the juice of half the lemon until smooth and creamy.","Stir in the flour, sugar, and salt just until no dry streaks remain — a few small lumps are the sign of a tender pancake.","Beat the egg whites to soft, droopy peaks and fold them in gently in two additions to keep the batter cloud-light.","Melt a sliver of butter in a nonstick skillet over medium heat and drop in quarter-cup rounds; cook 2 to 3 minutes until the edges look dry and the undersides are deep golden.","Flip carefully and cook 2 minutes more until the centers spring back when pressed, then serve warm with berries and maple syrup."],"tip":"Those whipped whites are your only leavening, so fold like you are handling a sleeping baby."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cinnamon_berry_french_toast', '{"id":"cinnamon_berry_french_toast","name":"Cinnamon Berry French Toast","emoji":"🍞","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":25,"servings":2,"ing":[{"f":"bread","q":6},{"f":"eggs","q":3},{"f":"milk","q":150},{"f":"sugar","q":15},{"f":"cinnamon","q":3},{"f":"butter","q":25},{"f":"berries","q":150},{"f":"maple_syrup","q":60},{"f":"salt","q":1}],"steps":["Whisk the eggs, milk, sugar, cinnamon, and a pinch of salt in a shallow dish until no ribbons of white remain.","Meanwhile, warm the berries with a tablespoon of the maple syrup in a small saucepan over low heat for 5 minutes, mashing a few, until they slump into a loose, glossy compote.","Soak each slice of bread 20 to 30 seconds per side — it should feel saturated but still hold its shape when lifted.","Melt half the butter in a large skillet over medium heat and cook the slices 2 to 3 minutes per side until burnished golden with crisp edges, adding more butter for the second batch.","Stack the slices, spoon over the warm berries, and finish with the remaining maple syrup while everything is still steaming."],"tip":"Slightly stale bread drinks up custard without collapsing; fresh squishy slices turn to pudding on the griddle."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_walnut_baked_oatmeal', '{"id":"banana_walnut_baked_oatmeal","name":"Banana Walnut Baked Oatmeal","emoji":"🍌","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","eggs","nuts"],"time":50,"servings":2,"ing":[{"f":"oats","q":140},{"f":"banana","q":2},{"f":"eggs","q":2},{"f":"milk","q":250},{"f":"maple_syrup","q":45},{"f":"walnuts","q":40},{"f":"butter","q":15},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Heat the oven to 375 F and butter a small baking dish generously, corners included.","Mash one and a half bananas in a large bowl until nearly smooth, then whisk in the eggs, milk, maple syrup, cinnamon, and salt.","Stir in the oats and most of the walnuts, pour the mixture into the dish, and shingle the remaining half banana in slices over the top with the last of the nuts.","Bake 30 to 35 minutes until the top is puffed and golden and the center barely jiggles when you nudge the dish.","Rest 5 minutes so it sets sliceable, then scoop into bowls with a splash of cold milk if you like the hot-cold contrast."],"tip":"Bananas with leopard-spotted peels bake up twice as sweet as the pristine yellow ones."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('apple_pie_oatmeal', '{"id":"apple_pie_oatmeal","name":"Apple Pie Stovetop Oatmeal","emoji":"🍎","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":20,"servings":2,"ing":[{"f":"oats","q":120},{"f":"apple","q":2},{"f":"coconut_milk","q":100},{"f":"maple_syrup","q":45},{"f":"almonds","q":30},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Dice the apples small and simmer them in a saucepan with the maple syrup, cinnamon, and a splash of water for 5 minutes until they smell like pie filling and yield to a fork.","Scoop out half the apples and set them aside for topping, then add the oats, coconut milk, a good pinch of salt, and 350 ml of water to the pot.","Simmer over medium-low for 8 to 10 minutes, stirring often, until the oats are plump and the porridge falls lazily off the spoon.","While it cooks, toast the almonds in a dry skillet over medium heat for 3 to 4 minutes, shaking the pan, until they crackle and turn fragrant; chop roughly.","Ladle into bowls and crown with the reserved apples and toasted almonds while the steam still carries the cinnamon."],"tip":"Cooking half the apples into the oats and saving half for the top gives you both jammy and crisp in every bite."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berries_and_cream_overnight_oats', '{"id":"berries_and_cream_overnight_oats","name":"Berries and Cream Overnight Oats","emoji":"🫐","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":10,"servings":2,"ing":[{"f":"oats","q":100},{"f":"greek_yogurt","q":200},{"f":"milk","q":200},{"f":"berries","q":200},{"f":"honey","q":40},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Stir the oats, yogurt, milk, honey, cinnamon, and a small pinch of salt together in a bowl until every oat is coated and the mixture looks like loose cake batter.","Fold in half the berries, crushing a few against the side of the bowl so violet streaks ripple through.","Divide between two jars, press plastic or lids on top, and chill at least 6 hours or overnight until the oats are soft and the mixture is spoonably thick.","In the morning, loosen with a splash of milk if needed and pile the remaining fresh berries on top for a juicy, cold-on-cold finish."],"tip":"The pinch of salt is not optional — it is the difference between dessert and wet cardboard."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_almond_berry_parfait', '{"id":"honey_almond_berry_parfait","name":"Honey Almond Berry Parfait","emoji":"🍯","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":15,"servings":2,"ing":[{"f":"greek_yogurt","q":400},{"f":"oats","q":60},{"f":"almonds","q":40},{"f":"olive_oil","q":10},{"f":"honey","q":50},{"f":"berries","q":200},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Toast the oats and roughly chopped almonds in the olive oil with a pinch of salt in a skillet over medium heat for 4 to 5 minutes, stirring constantly, until golden and smelling like fresh granola.","Stir a tablespoon of the honey into the hot pan so it bubbles and coats the mixture, then spread it on a plate to cool crisp.","Whisk the yogurt with half the remaining honey and the cinnamon until glossy.","Build the parfaits in two glasses: a thick layer of yogurt, a handful of berries, a scatter of the honeyed crunch, then repeat until the glass is full.","Finish with a final drizzle of honey and serve within 15 minutes while the top layer still shatters."],"tip":"Layer the crunch between yogurt strata, not just on top, so the last spoonful is as good as the first."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_banana_rice_porridge_2', '{"id":"coconut_banana_rice_porridge_2","name":"Coconut Banana Rice Porridge","emoji":"🥥","cuisine":"Asian","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":35,"servings":2,"ing":[{"f":"rice","q":130},{"f":"coconut_milk","q":250},{"f":"maple_syrup","q":45},{"f":"banana","q":2},{"f":"cashews","q":30},{"f":"lime","q":1},{"f":"ginger","q":5},{"f":"salt","q":1}],"steps":["Rinse the rice until the water runs mostly clear, then simmer it in a saucepan with 400 ml of water and the thinly sliced ginger for 10 minutes.","Pour in the coconut milk and a pinch of salt and cook over low heat for 15 to 20 minutes more, stirring often, until the grains slump into a thick, creamy porridge.","Stir in the maple syrup and one sliced banana, letting the fruit soften into the heat for a minute.","Toast the cashews in a dry skillet over medium heat for 3 minutes until golden at the edges, then chop them roughly.","Serve in deep bowls topped with the second sliced banana, the cashews, lime zest, and a bright squeeze of lime juice to cut the richness."],"tip":"Stir like you mean it during the last five minutes — the released starch is the creaminess, and the pot bottom knows when you slack."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berry_yogurt_breakfast_crepes', '{"id":"berry_yogurt_breakfast_crepes","name":"Berry Yogurt Breakfast Crepes","emoji":"🍓","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":35,"servings":2,"ing":[{"f":"flour","q":100},{"f":"eggs","q":2},{"f":"milk","q":250},{"f":"butter","q":20},{"f":"sugar","q":20},{"f":"greek_yogurt","q":200},{"f":"honey","q":30},{"f":"berries","q":200},{"f":"lemon","q":0.5},{"f":"salt","q":1}],"steps":["Whisk the flour, eggs, milk, half the sugar, a pinch of salt, and half the butter, melted, into a batter the texture of heavy cream; let it rest 10 minutes so the flour hydrates.","While it rests, simmer the berries with the remaining sugar and a squeeze of lemon over medium-low heat for 5 to 6 minutes until jammy but still holding some whole fruit.","Heat a nonstick skillet over medium, slick it with butter, and swirl in a thin ladle of batter; cook 60 to 90 seconds until the edges lace and lift, then flip for 30 seconds more.","Stack the finished crepes under a towel and repeat, re-buttering every second crepe.","Stir the honey into the yogurt, spread a ribbon down each crepe, fold into quarters, and spoon the warm berry compote over the top."],"tip":"The first crepe is a sacrifice to the pan gods — eat the evidence and carry on."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sweet_potato_pb_breakfast_bowls', '{"id":"sweet_potato_pb_breakfast_bowls","name":"Maple Peanut Butter Sweet Potato Bowls","emoji":"🍠","cuisine":"American","meal":["breakfast"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":["nuts"],"time":55,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"peanut_butter","q":50},{"f":"maple_syrup","q":30},{"f":"banana","q":1},{"f":"coconut_milk","q":60},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Heat the oven to 400 F, prick the sweet potatoes all over with a fork, and roast them directly on the rack for 45 to 50 minutes until they hiss, wrinkle, and give completely when squeezed.","Split them open and scoop the molten flesh into two bowls, mashing it roughly with the coconut milk, cinnamon, and a pinch of salt until creamy but not baby-smooth.","Warm the peanut butter with the maple syrup in a small pan or microwave for 20 seconds until it pours in ribbons.","Slice the banana over the bowls, drizzle generously with the peanut-maple sauce, and finish with one more dusting of cinnamon.","Serve hot, when the caramelized sugars at the skin edges are still sticky."],"tip":"Roast a tray of sweet potatoes on Sunday and this becomes a five-minute weekday breakfast all week."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('whipped_honey_cottage_cheese_bowls', '{"id":"whipped_honey_cottage_cheese_bowls","name":"Whipped Honey Cottage Cheese Bowls","emoji":"🥣","cuisine":"Mediterranean","meal":["breakfast"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":10,"servings":2,"ing":[{"f":"cottage_cheese","q":400},{"f":"honey","q":40},{"f":"berries","q":200},{"f":"walnuts","q":40},{"f":"lemon","q":0.5},{"f":"cinnamon","q":1}],"steps":["Blend the cottage cheese in a food processor or blender for a full 60 to 90 seconds, scraping down once, until the curds vanish into a silky, mousse-like cream.","Fold in half the honey and a shower of lemon zest, tasting as you go — it should be gently sweet with a bright edge.","Toast the walnuts in a dry skillet over medium heat for 3 to 4 minutes until they smell warm and woodsy, then crush them lightly in your fist.","Swoosh the whipped cheese into two shallow bowls, pile on the berries and walnuts, and finish with the remaining honey and a whisper of cinnamon.","Eat immediately, dragging every spoonful through all three layers."],"tip":"The blender is what converts cottage-cheese skeptics — nobody has to know what the mousse used to look like."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cinnamon_tortilla_crisps_with_berries', '{"id":"cinnamon_tortilla_crisps_with_berries","name":"Cinnamon Tortilla Crisps with Honeyed Yogurt","emoji":"🍪","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"butter","q":30},{"f":"sugar","q":30},{"f":"cinnamon","q":4},{"f":"greek_yogurt","q":200},{"f":"honey","q":20},{"f":"berries","q":150},{"f":"lime","q":0.5}],"steps":["Stir the sugar and cinnamon together on a wide plate and cut each tortilla into eight wedges.","Melt half the butter in a large skillet over medium heat and fry the wedges in a single layer for 1 to 2 minutes per side until they blister, stiffen, and turn deep gold, adding butter as the pan dries.","Toss the hot wedges immediately in the cinnamon sugar so it clings like a buñuelo''s jacket, then let them cool for 2 minutes to crisp fully.","Whisk the yogurt with the honey and a squeeze of lime until pourable and tangy-sweet.","Pile the crisps onto plates with the yogurt for dipping and scatter the berries over everything."],"tip":"Sugar the wedges the second they leave the pan — cold crisps shrug the cinnamon sugar right off."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cashew_quinoa_kheer', '{"id":"cashew_quinoa_kheer","name":"Cashew Quinoa Kheer","emoji":"🍚","cuisine":"Indian","meal":["breakfast"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","nuts"],"time":35,"servings":2,"ing":[{"f":"quinoa","q":120},{"f":"milk","q":500},{"f":"honey","q":40},{"f":"cashews","q":40},{"f":"butter","q":10},{"f":"ginger","q":5},{"f":"cinnamon","q":2},{"f":"salt","q":1}],"steps":["Rinse the quinoa thoroughly in a fine sieve to wash off its bitter coating, then toast it in half the butter in a saucepan over medium heat for 2 minutes until it smells nutty and begins to pop.","Pour in the milk with the grated ginger and a pinch of salt, bring to a bare simmer, and cook gently for 20 to 22 minutes, stirring often so the bottom never catches, until the grains uncurl and the milk thickens to a spoon-coating custard.","Meanwhile, fry the cashews in the remaining butter in a small pan for 2 to 3 minutes until evenly golden, and set them aside on a paper towel.","Take the kheer off the heat and stir in the honey and cinnamon — off-heat sweetening keeps the honey''s floral edge intact.","Ladle into bowls, top with the buttery cashews, and serve warm, or chill it for a thicker pudding-style breakfast."],"tip":"Kheer thickens dramatically as it cools, so pull it from the stove one shade looser than you want to eat it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('apple_cinnamon_breakfast_quesadillas', '{"id":"apple_cinnamon_breakfast_quesadillas","name":"Apple Cinnamon Breakfast Quesadillas","emoji":"🫓","cuisine":"Mexican","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"apple","q":2},{"f":"ricotta","q":150},{"f":"butter","q":20},{"f":"honey","q":25},{"f":"cinnamon","q":3},{"f":"salt","q":1}],"steps":["Slice the apples thin and saute them in half the butter over medium-high heat with the cinnamon, a pinch of salt, and a tablespoon of the honey for 4 to 5 minutes until their edges caramelize and they bend without breaking.","Stir the ricotta with the remaining honey until it loosens into a sweet, spreadable cream.","Spread the ricotta over half of each tortilla, shingle the caramelized apples on top, and fold the tortillas into half-moons, pressing gently to seal.","Wipe out the skillet, melt the remaining butter over medium heat, and toast the quesadillas 2 to 3 minutes per side until the outsides are crackly gold and the filling is warmed through.","Rest 1 minute so molten filling does not ambush anyone, then cut into wedges and serve."],"tip":"Keep the apple layer to a single shingle — overstuffed quesadillas leak, and caramelized honey is basically lava."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('banana_maple_pancakes', '{"id":"banana_maple_pancakes","name":"Banana Maple Pancakes","emoji":"🥞","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":25,"servings":2,"ing":[{"f":"flour","q":150},{"f":"sugar","q":15},{"f":"cinnamon","q":2},{"f":"salt","q":2},{"f":"eggs","q":2},{"f":"milk","q":200},{"f":"butter","q":30},{"f":"banana","q":2},{"f":"maple_syrup","q":60}],"steps":["Whisk the flour, sugar, cinnamon, and salt in a large bowl, then mash one very ripe banana in a second bowl until nearly smooth.","Beat the eggs and milk into the mashed banana along with half the melted butter, then fold the wet mixture into the dry with about ten lazy strokes, stopping while a few streaks of flour remain.","Let the batter rest for 5 minutes while a nonstick skillet heats over medium until a drop of water skitters across the surface.","Grease the pan with a little of the remaining butter and ladle in batter to form 10-centimeter rounds, cooking 2 to 3 minutes until the edges look dry and the bubbles on top pop and hold their shape.","Flip once and cook 90 seconds more until the undersides are deep golden brown, then stack the pancakes on warm plates.","Top with the second banana in coins, the last of the butter, and a generous flood of maple syrup."],"tip":"A rested batter and an unbothered flipping hand make fluffier pancakes than any amount of frantic whisking ever will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('berry_french_toast', '{"id":"berry_french_toast","name":"Cinnamon Berry French Toast","emoji":"🍓","cuisine":"American","meal":["breakfast"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":20,"servings":2,"ing":[{"f":"bread","q":6},{"f":"eggs","q":3},{"f":"milk","q":120},{"f":"cinnamon","q":2},{"f":"sugar","q":10},{"f":"butter","q":20},{"f":"berries","q":150},{"f":"maple_syrup","q":45}],"steps":["Whisk the eggs, milk, cinnamon, and sugar in a wide, shallow dish until no streaks of white remain and the custard smells like a bakery.","Soak each slice of bread for about 20 seconds per side, long enough to saturate the crumb but not so long that it slumps when you lift it.","Melt half the butter in a large skillet over medium heat until the foam subsides, then lay in three slices without crowding.","Cook 2 to 3 minutes per side until each face is burnished mahogany and the centers spring back when pressed, then repeat with the remaining butter and bread.","While the second batch cooks, warm the berries in a small saucepan over low heat for 3 to 4 minutes until they slump and release glossy purple juice.","Shingle the toast on plates, spoon over the warm berries, and finish with maple syrup."],"tip":"Day-old bread drinks custard like a champ; fresh squishy bread turns into a sad omelet sandwich."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shakshuka_brunch_skillet', '{"id":"shakshuka_brunch_skillet","name":"Feta Shakshuka with Toast Soldiers","emoji":"🍳","cuisine":"Mediterranean","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":30,"servings":2,"ing":[{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.3},{"f":"cumin","q":2},{"f":"paprika","q":3},{"f":"chili_powder","q":1},{"f":"crushed_tomatoes","q":400},{"f":"eggs","q":4},{"f":"feta","q":80},{"f":"parsley","q":0.3},{"f":"bread","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Warm the olive oil in a heavy skillet over medium heat and cook the sliced onion and bell pepper with a pinch of salt for 8 minutes, until soft and sweet at the edges.","Stir in the minced garlic, cumin, paprika, and chili powder and toast for 30 seconds until the spices bloom and the kitchen smells faintly smoky.","Pour in the crushed tomatoes, season with the remaining salt and pepper, and simmer 8 to 10 minutes until the sauce thickens enough that a spoon leaves a brief trail.","Make four wells with the back of the spoon, crack an egg into each, then cover and cook 5 to 7 minutes until the whites are set but the yolks still wobble like custard.","Scatter over the crumbled feta and chopped parsley, letting the cheese soften in the residual heat.","Serve straight from the pan with toasted bread cut into strips for dredging through sauce and yolk."],"tip":"The eggs keep cooking after you kill the heat, so pull the pan when the yolks still scare you a little."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('asparagus_parmesan_frittata', '{"id":"asparagus_parmesan_frittata","name":"Asparagus Parmesan Frittata","emoji":"🥚","cuisine":"Italian","meal":["breakfast","lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"milk","q":30},{"f":"parmesan","q":50},{"f":"asparagus","q":250},{"f":"scallions","q":0.5},{"f":"olive_oil","q":15},{"f":"lemon","q":0.5},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 190 degrees Celsius and whisk the eggs, milk, most of the grated parmesan, salt, and pepper until uniformly pale yellow.","Snap the woody ends off the asparagus, cut the spears into 3-centimeter lengths, and saute them with the sliced scallions in olive oil in an ovenproof skillet over medium heat for 4 minutes, until bright green and just tender.","Pour the egg mixture over the vegetables and cook undisturbed for 2 minutes, until the edges begin to set and pull away from the pan.","Slide the skillet into the oven and bake 10 to 12 minutes, until the center is puffed and barely jiggles when you nudge the handle.","Shower the top with the reserved parmesan and a squeeze of lemon, then rest 3 minutes before cutting into wedges; the frittata will settle into a tender, sliceable custard."],"tip":"An overbaked frittata bounces like a gym mat, so trust the jiggle and get out of the oven early."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('avocado_toast_poached_eggs', '{"id":"avocado_toast_poached_eggs","name":"Smashed Avocado Toast with Poached Eggs","emoji":"🥑","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian","dairy-free"],"allergens":["gluten","eggs"],"time":15,"servings":2,"ing":[{"f":"bread","q":4},{"f":"avocado","q":1.5},{"f":"eggs","q":4},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10},{"f":"chili_powder","q":1},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Bring a wide saucepan of water to a bare simmer where small bubbles cling to the bottom but the surface barely trembles.","Crack each egg into a small cup and slide them gently into the water one at a time, poaching 3 to 4 minutes until the whites are opaque and set but the yolks still feel soft when lifted with a slotted spoon.","While the eggs poach, toast the bread until deeply golden and crisp enough to knock on.","Mash the avocado with the lemon juice, salt, and pepper, keeping it chunky rather than smooth, and spread it thickly over the hot toast.","Set a drained poached egg on each slice, drizzle with olive oil, and dust with chili powder and more black pepper.","Cut one open immediately and let the yolk run into the avocado, because that is the entire point."],"tip":"The freshest eggs hold together in the water; save the elderly ones in your carton for hard-boiling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('bacon_egg_breakfast_burritos', '{"id":"bacon_egg_breakfast_burritos","name":"Bacon and Egg Breakfast Burritos","emoji":"🌯","cuisine":"Mexican","meal":["breakfast"],"diets":[],"allergens":["dairy","gluten","eggs"],"time":30,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"bacon","q":80},{"f":"eggs","q":4},{"f":"cheddar","q":40},{"f":"salsa","q":100},{"f":"avocado","q":0.5},{"f":"scallions","q":0.3},{"f":"black_pepper","q":1}],"steps":["Cook the chopped bacon in a cold skillet set over medium heat for 8 to 10 minutes, stirring occasionally, until the fat renders and the pieces are crisp and bronzed; lift them out and pour off all but a thin film of fat.","Whisk the eggs with black pepper, pour them into the same skillet over medium-low heat, and scramble slowly with a spatula for 2 to 3 minutes until they form soft, glossy curds that are just barely set.","Warm the tortillas directly over a burner flame or in a dry pan for 15 seconds per side until pliable and lightly blistered.","Lay each tortilla flat and stack eggs, bacon, grated cheddar, sliced avocado, sliced scallions, and a spoonful of salsa slightly below center.","Fold in the sides, roll each burrito tightly away from you, then sear seam-side down in the hot skillet for a minute until the seal is golden and crackly.","Halve on a diagonal and serve with the remaining salsa for dunking."],"tip":"Starting bacon in a cold pan renders the fat evenly, and that fat is the only cooking oil this recipe respects."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_salmon_potato_hash', '{"id":"crispy_salmon_potato_hash","name":"Crispy Salmon and Potato Hash with Fried Eggs","emoji":"🐟","cuisine":"American","meal":["breakfast","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish","eggs"],"time":35,"servings":2,"ing":[{"f":"salmon","q":250},{"f":"potatoes","q":350},{"f":"olive_oil","q":20},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"eggs","q":2},{"f":"paprika","q":2},{"f":"lemon","q":0.5},{"f":"parsley","q":0.3},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Dice the potatoes into 1-centimeter cubes, simmer them in salted water for 6 minutes until just tender, and drain them well so they crisp instead of steam.","Heat most of the olive oil in a large cast-iron skillet over medium-high heat and spread the potatoes in a single layer, leaving them alone for 4 minutes until the undersides turn deep golden and release from the pan.","Add the diced onion and bell pepper with the paprika, salt, and pepper and cook 5 minutes more, tossing occasionally, until the vegetables soften and the edges char lightly.","Nestle in the salmon, cut into large chunks, and cook 3 to 4 minutes, turning once, until the fish flakes at the touch of a spatula but still looks blush in the center.","Push the hash aside, add the last of the oil, and fry the eggs 2 to 3 minutes until the whites are lacy and crisp at the edges and the yolks glow.","Finish with lemon juice and chopped parsley and serve directly from the skillet."],"tip":"Resist the urge to stir the potatoes early; crust only happens to potatoes you ignore."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('salsa_chilaquiles_with_eggs', '{"id":"salsa_chilaquiles_with_eggs","name":"Skillet Chilaquiles with Fried Eggs","emoji":"🌶️","cuisine":"Mexican","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"olive_oil","q":20},{"f":"salsa","q":250},{"f":"eggs","q":4},{"f":"cheddar","q":40},{"f":"sour_cream","q":40},{"f":"onion","q":0.5},{"f":"cilantro","q":0.3},{"f":"lime","q":0.5},{"f":"salt","q":2}],"steps":["Cut the tortillas into eighths and fry them in the olive oil in a large skillet over medium-high heat for 5 to 6 minutes, tossing now and then, until they are golden, rigid, and audibly crisp.","Pour the salsa over the chips with a splash of water and a pinch of salt, and simmer 2 to 3 minutes, folding gently, until the sauce clings and the chips soften at the edges while keeping some crunch in the middle.","Meanwhile, fry the eggs in a second pan over medium heat for 2 to 3 minutes until the whites are set with frilly brown edges and the yolks remain molten.","Slide the eggs on top of the saucy chips and scatter over the grated cheddar so it melts on contact.","Finish with dollops of sour cream, thinly sliced onion, torn cilantro, and a hard squeeze of lime, then serve immediately while the textures are still arguing."],"tip":"Chilaquiles wait for no one; the gap between saucy-crisp and soggy is roughly the length of one good story."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_turkey_sausage_plate', '{"id":"maple_turkey_sausage_plate","name":"Maple Turkey Sausage Brunch Plate","emoji":"🍁","cuisine":"American","meal":["breakfast"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["eggs"],"time":35,"servings":2,"ing":[{"f":"ground_turkey","q":350},{"f":"maple_syrup","q":20},{"f":"oregano","q":2},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":2},{"f":"sweet_potatoes","q":300},{"f":"olive_oil","q":20},{"f":"eggs","q":4},{"f":"scallions","q":0.3}],"steps":["Mix the ground turkey with half the maple syrup, the oregano, paprika, half the salt, and a generous grind of pepper, then shape it into six thin patties with damp hands.","Dice the sweet potatoes into 1-centimeter cubes, toss with half the olive oil and the remaining salt, and roast at 220 degrees Celsius for 20 to 25 minutes until caramelized at the corners and creamy inside.","Sear the patties in the remaining oil in a skillet over medium heat for 3 to 4 minutes per side, until deeply browned and the centers register 74 degrees Celsius.","Brush the patties with the last of the maple syrup in the final minute so it bubbles into a sticky lacquer.","Fry the eggs in the same glossy pan for 2 to 3 minutes until the whites set and the edges crisp in the sausage drippings.","Plate the patties, sweet potatoes, and eggs together and shower with sliced scallions."],"tip":"Thin patties cook through before they dry out, which is the whole trick to turkey sausage that people actually finish."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('honey_berry_yogurt_parfaits', '{"id":"honey_berry_yogurt_parfaits","name":"Honey Berry Parfaits with Toasted Oat Clusters","emoji":"🍯","cuisine":"American","meal":["breakfast"],"diets":["vegetarian","gluten-free","high-protein"],"allergens":["dairy","nuts"],"time":15,"servings":2,"ing":[{"f":"greek_yogurt","q":400},{"f":"oats","q":60},{"f":"walnuts","q":30},{"f":"butter","q":10},{"f":"honey","q":40},{"f":"berries","q":200},{"f":"cinnamon","q":1},{"f":"salt","q":1}],"steps":["Melt the butter in a skillet over medium heat and add the oats, chopped walnuts, cinnamon, and salt, stirring constantly for 4 to 5 minutes until the oats turn tawny and smell like baking cookies.","Drizzle in half the honey and stir 30 seconds more so the mixture clumps into sticky clusters, then scrape it onto a plate to cool and crisp.","Warm half the berries in the same pan for 2 minutes, crushing a few with the spoon, until they collapse into a loose, jammy sauce.","Layer the glasses: a thick spoonful of Greek yogurt, a ribbon of berry sauce, a handful of fresh berries, and a scattering of oat clusters, then repeat.","Finish each parfait with the remaining honey and serve while the clusters still crackle against the cold yogurt."],"tip":"Assemble at the last second, because granola submerged in yogurt has the shelf life of a snowman in July."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('zucchini_corn_brunch_fritters', '{"id":"zucchini_corn_brunch_fritters","name":"Zucchini Corn Fritters with Lemony Sour Cream","emoji":"🌽","cuisine":"American","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten","eggs"],"time":30,"servings":2,"ing":[{"f":"zucchini","q":2},{"f":"corn_frozen","q":150},{"f":"flour","q":80},{"f":"eggs","q":2},{"f":"parmesan","q":30},{"f":"scallions","q":0.5},{"f":"olive_oil","q":30},{"f":"sour_cream","q":60},{"f":"lemon","q":0.5},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Grate the zucchini on the coarse holes of a box grater, toss with half the salt, and let it sit in a colander for 10 minutes before squeezing it in a clean towel until no more liquid weeps out.","Stir together the wrung-out zucchini, thawed corn, flour, eggs, grated parmesan, sliced scallions, remaining salt, and pepper into a thick, scoopable batter.","Heat the olive oil in a wide skillet over medium heat until it shimmers, then drop in heaping spoonfuls of batter and flatten each into a rough disk.","Fry 3 to 4 minutes per side, resisting the flip until the edges brown and the underside releases cleanly with a lacy golden crust.","Drain the fritters briefly on a rack, then serve hot with sour cream whisked with lemon juice and a pinch of salt for swiping."],"tip":"Squeeze the zucchini like it owes you money; watery squash is the number one cause of fritter heartbreak."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('brunch_cobb_salad', '{"id":"brunch_cobb_salad","name":"Brunch Cobb Salad with Jammy Eggs","emoji":"🥗","cuisine":"American","meal":["lunch"],"diets":["gluten-free","low-carb"],"allergens":["dairy","eggs"],"time":25,"servings":2,"ing":[{"f":"romaine","q":1},{"f":"eggs","q":4},{"f":"bacon","q":70},{"f":"avocado","q":1},{"f":"cherry_tomatoes","q":150},{"f":"cheddar","q":40},{"f":"olive_oil","q":20},{"f":"balsamic_vinegar","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Lower the eggs into boiling water and cook exactly 7 minutes, then plunge them into ice water so the yolks set jammy and golden rather than chalky.","Cook the chopped bacon in a skillet over medium heat for 8 minutes until crisp, and drain it on a paper towel while it crackles.","Whisk the olive oil, balsamic vinegar, salt, and pepper into a dressing that tastes slightly too sharp on its own; the lettuce will mellow it.","Chop the romaine into ribbons, toss with half the dressing, and spread it over a platter as the base.","Arrange the halved eggs, bacon, sliced avocado, halved cherry tomatoes, and diced cheddar in neat rows across the greens.","Drizzle with the remaining dressing, grind over more pepper, and toss at the table for maximum drama."],"tip":"The tidy rows are for the photo; the violent toss immediately afterward is for the flavor."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spinach_mushroom_quesadillas_2', '{"id":"spinach_mushroom_quesadillas_2","name":"Spinach and Mushroom Melt Quesadillas","emoji":"🍄","cuisine":"Mexican","meal":["breakfast","lunch"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"tortillas","q":4},{"f":"mushrooms","q":200},{"f":"spinach","q":150},{"f":"mozzarella","q":120},{"f":"garlic","q":0.2},{"f":"onion","q":0.5},{"f":"olive_oil","q":15},{"f":"salt","q":2},{"f":"black_pepper","q":1}],"steps":["Heat most of the olive oil in a large skillet over medium-high heat and cook the sliced mushrooms undisturbed for 3 minutes, until browned on one side, before adding the sliced onion and cooking 3 minutes more.","Stir in the minced garlic, salt, and pepper, then pile in the spinach and toss for a minute until it wilts to a glossy tangle; tip everything into a bowl and let the excess moisture steam off.","Wipe the skillet, film it with the remaining oil, and lay in a tortilla over medium heat.","Scatter half the mozzarella and half the vegetable mixture over the tortilla, cap with a second tortilla, and cook 2 to 3 minutes per side, pressing gently, until each face is spotted deep gold and the cheese oozes at the seam.","Repeat with the remaining tortillas and filling, then rest each quesadilla for one minute before slicing into wedges so the molten interior does not stage an escape."],"tip":"Cook the vegetables until their liquid is gone, because steam trapped between tortillas is how quesadillas turn to laundry."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_parmesan_chicken_bites', '{"id":"crispy_parmesan_chicken_bites","name":"Crispy Parmesan Chicken Bites with Charred Broccoli","emoji":"🍗","cuisine":"American","meal":["dinner"],"diets":["high-protein","low-carb"],"allergens":["dairy","gluten","eggs"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":350},{"f":"flour","q":30},{"f":"eggs","q":1},{"f":"parmesan","q":40},{"f":"olive_oil","q":20},{"f":"broccoli","q":300},{"f":"lemon","q":0.5},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Heat the oven to 220C and line a sheet pan with foil, leaving room for the broccoli on one side.","Cut the chicken into bite-size chunks, season with salt, pepper, and paprika, then run each piece through flour, beaten egg, and finely grated parmesan so every side wears a thin, even crust.","Arrange the bites with space between them, drizzle with half the olive oil, and bake 15 to 18 minutes until deeply golden and an instant-read thermometer hits 74C.","Toss the broccoli florets with the remaining oil and a pinch of salt, spread them on the empty side of the pan, and roast until the edges char and frizzle.","Squeeze the lemon over everything while it is still sizzling and serve the bites hot, when the crust crackles loudest."],"tip":"A pale nugget is a crowded nugget — give them elbow room on the pan and they will brown like they mean it."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheeseburger_pasta_skillet', '{"id":"cheeseburger_pasta_skillet","name":"One-Pan Cheeseburger Penne Skillet","emoji":"🍔","cuisine":"American","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":225},{"f":"penne","q":150},{"f":"cheddar","q":70},{"f":"onion","q":0.5},{"f":"garlic","q":0.2},{"f":"crushed_tomatoes","q":250},{"f":"broth","q":300},{"f":"sour_cream","q":40},{"f":"paprika","q":2},{"f":"salt","q":3},{"f":"black_pepper","q":1}],"steps":["Brown the beef in a wide skillet over medium-high heat, pressing it flat and leaving it alone for 3 minutes so it develops a crusty, burger-like sear before you break it up.","Stir in the diced onion and garlic and cook until the onion turns translucent and the pan smells like a diner griddle, about 4 minutes.","Add the crushed tomatoes, broth, paprika, salt, and dry penne, scrape up the browned bits, and simmer with a lid ajar for 12 to 14 minutes, stirring now and then so nothing sticks.","When the pasta is tender and the sauce has thickened to coat the noodles, pull the pan off the heat and stir in the cheddar until it melts into glossy ribbons.","Finish each bowl with a spoonful of sour cream and a grind of black pepper."],"tip":"Resist draining every drop of beef fat — that is where the cheeseburger flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('turkey_meatball_pastina_soup', '{"id":"turkey_meatball_pastina_soup","name":"Little Turkey Meatball and Broken Noodle Soup","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten","eggs"],"time":45,"servings":4,"ing":[{"f":"ground_turkey","q":450},{"f":"eggs","q":1},{"f":"parmesan","q":40},{"f":"bread","q":1},{"f":"spaghetti","q":120},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"broth","q":1250},{"f":"spinach","q":100},{"f":"olive_oil","q":15},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Tear the bread into crumbs, moisten it with a splash of the broth, and knead it into the turkey with the egg, half the parmesan, oregano, salt, and pepper until just combined.","Roll the mixture into marble-size meatballs with damp hands — small enough to fit on a kid''s spoon — and chill them while you start the soup.","Warm the olive oil in a soup pot over medium heat and sweat the diced carrots, celery, and onion until they smell sweet and the onion goes glassy, about 6 minutes, adding the garlic for the last minute.","Pour in the broth, bring it to a lively simmer, and gently lower in the meatballs; let them poach undisturbed for 8 minutes until they float and firm up.","Snap the spaghetti into thumb-length pieces, stir it in, and cook until al dente, then wilt in the spinach and shower each bowl with the remaining parmesan."],"tip":"Roll the meatballs tiny even if it feels fussy — spoon-sized meatballs are the difference between a soup kids eat and a soup kids excavate."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sticky_honey_soy_salmon_rice', '{"id":"sticky_honey_soy_salmon_rice","name":"Sticky Honey-Soy Salmon Rice Bowls","emoji":"🐟","cuisine":"Asian","meal":["dinner"],"diets":["high-protein","dairy-free"],"allergens":["fish","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"salmon","q":300},{"f":"rice","q":140},{"f":"soy_sauce","q":45},{"f":"honey","q":25},{"f":"garlic","q":0.2},{"f":"ginger","q":10},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":10},{"f":"broccoli","q":250},{"f":"scallions","q":0.5}],"steps":["Rinse the rice until the water runs nearly clear, then cook it while you prep everything else so it lands fluffy and hot.","Whisk the soy sauce, honey, grated garlic, and grated ginger into a glaze and cut the salmon into large cubes, patting them very dry so they sear instead of steam.","Heat the olive oil in a nonstick skillet over medium-high and sear the salmon cubes 2 minutes per side until the edges crisp and turn mahogany.","Add the broccoli florets and a splash of water, cover for 2 minutes to steam them bright green, then pour in the glaze and let it bubble until it thickens enough to coat the back of a spoon.","Spoon everything over the rice, drizzle with sesame oil, and scatter the sliced scallions on top while the glaze is still glossy."],"tip":"The glaze goes from sticky to scorched in about 30 seconds, so keep your nose on duty once it starts bubbling."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('creamy_lime_shrimp_tacos', '{"id":"creamy_lime_shrimp_tacos","name":"Creamy Lime Shrimp Tacos with Crunchy Slaw","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["shellfish","dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"tortillas","q":4},{"f":"sour_cream","q":60},{"f":"lime","q":1},{"f":"avocado","q":1},{"f":"cabbage","q":0.2},{"f":"cilantro","q":0.3},{"f":"garlic","q":0.1},{"f":"chili_powder","q":3},{"f":"cumin","q":2},{"f":"olive_oil","q":15},{"f":"salt","q":3}],"steps":["Stir the sour cream with half the lime''s juice, the grated garlic, and a pinch of salt, then shred the cabbage fine and toss it with a spoonful of the crema so it softens slightly.","Pat the shrimp bone-dry and toss them with chili powder, cumin, and salt — the mild dusting seasons without setting off any spice alarms.","Sear the shrimp in hot olive oil for 1 to 2 minutes per side, just until they blush pink and curl into loose commas; pull them the moment they are opaque.","Warm the tortillas directly over a low flame or in a dry skillet until they puff and pick up a few toasty freckles.","Pile each tortilla with slaw, shrimp, and sliced avocado, drizzle with the remaining crema, and finish with cilantro and the rest of the lime."],"tip":"A shrimp curled into a tight O is overcooked — pull them at the relaxed-comma stage and they stay juicy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('cheesy_chicken_quesadillas', '{"id":"cheesy_chicken_quesadillas","name":"Golden Chicken and Pepper Quesadillas","emoji":"🧀","cuisine":"Mexican","meal":["dinner"],"diets":["high-protein"],"allergens":["dairy","gluten"],"time":25,"servings":2,"ing":[{"f":"chicken_thigh","q":225},{"f":"tortillas","q":3},{"f":"cheddar","q":80},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"salsa","q":120},{"f":"sour_cream","q":40},{"f":"olive_oil","q":10},{"f":"cumin","q":2},{"f":"chili_powder","q":2},{"f":"salt","q":3}],"steps":["Dice the chicken thighs small and cook them in olive oil over medium-high heat with cumin, chili powder, and salt until browned at the edges and cooked through, about 6 minutes.","Add the sliced bell pepper and onion to the same pan and cook until they slump and pick up a little char, then scrape everything into a bowl.","Scatter cheddar over half of each tortilla, top with the chicken mixture and a little more cheese — the double layer is the glue that holds the whole operation together.","Fold and toast each quesadilla in the dry skillet over medium heat, 2 to 3 minutes per side, pressing gently until the outside is deep golden and audibly crisp.","Rest them 2 minutes so the cheese sets, then cut into wedges and serve with salsa and sour cream for dunking."],"tip":"Cheese on both sides of the filling is not indulgence, it is structural engineering."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_nuggets_rice', '{"id":"sesame_tofu_nuggets_rice","name":"Sticky Sesame Tofu Nuggets with Rice","emoji":"🥢","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":35,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice","q":140},{"f":"flour","q":30},{"f":"soy_sauce","q":30},{"f":"maple_syrup","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":25},{"f":"garlic","q":0.2},{"f":"ginger","q":8},{"f":"green_beans","q":250},{"f":"scallions","q":0.5},{"f":"salt","q":2}],"steps":["Press the tofu between paper towels under a heavy pan for 10 minutes while the rice cooks, then tear it into rough nuggets — the craggy edges fry up far crispier than neat cubes.","Toss the nuggets with flour and a pinch of salt and pan-fry them in olive oil over medium-high heat, turning until every side is golden and crunchy, about 8 minutes total.","Push the tofu aside, briefly sizzle the grated garlic and ginger until fragrant, then pour in the soy sauce and maple syrup whisked together.","Let the sauce bubble for a minute until it turns glossy and clings to the nuggets like lacquer, then kill the heat and add the sesame oil.","Steam the green beans until snappy-tender, pile everything over rice, and top with sliced scallions."],"tip":"Torn tofu is ugly on the cutting board and gorgeous in the pan — trust the rags."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('hidden_veggie_penne_marinara', '{"id":"hidden_veggie_penne_marinara","name":"Hidden-Veggie Penne Marinara","emoji":"🍝","cuisine":"Italian","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":35,"servings":2,"ing":[{"f":"penne","q":160},{"f":"crushed_tomatoes","q":400},{"f":"carrots","q":100},{"f":"zucchini","q":0.5},{"f":"onion","q":0.5},{"f":"garlic","q":0.3},{"f":"olive_oil","q":20},{"f":"mozzarella","q":80},{"f":"parmesan","q":20},{"f":"basil","q":0.3},{"f":"oregano","q":2},{"f":"sugar","q":5},{"f":"salt","q":4}],"steps":["Grate the carrots and zucchini on the fine side of a box grater so they can vanish into the sauce without a trace.","Warm the olive oil in a deep skillet over medium heat and cook the grated vegetables with the diced onion and a pinch of salt until they nearly melt, 8 to 10 minutes, adding the garlic for the last minute.","Stir in the crushed tomatoes, oregano, and sugar and simmer gently for 15 minutes until the sauce darkens and thickens to a spoon-coating consistency; blend it smooth if your table has vegetable detectives.","Boil the penne in well-salted water until just shy of al dente, then drag it into the sauce with a splash of pasta water and toss over the heat for a minute so the sauce grips every tube.","Tear the mozzarella over the top, let it soften into molten pockets, and finish with parmesan and basil leaves."],"tip":"Blend the sauce silky and the carrots become a rumor no one can prove."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gentle_butter_chicken_curry', '{"id":"gentle_butter_chicken_curry","name":"Gentle Butter Chicken Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":40,"servings":2,"ing":[{"f":"chicken_thigh","q":250},{"f":"butter","q":15},{"f":"crushed_tomatoes","q":250},{"f":"coconut_milk","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"garam_masala","q":4},{"f":"turmeric","q":2},{"f":"cumin","q":2},{"f":"honey","q":8},{"f":"rice","q":120},{"f":"cilantro","q":0.2},{"f":"salt","q":4}],"steps":["Start the rice, then melt the butter in a saucepan over medium heat and cook the finely diced onion until soft and golden at the edges, about 6 minutes.","Add the grated garlic and ginger, then the garam masala, turmeric, and cumin, and stir for 30 seconds until the spices smell toasty and bloom in the butter.","Pour in the crushed tomatoes with a good pinch of salt and simmer for 10 minutes until the sauce darkens to brick red and the raw tomato edge cooks off.","Stir in the coconut milk and honey, nestle in the bite-size chicken thigh pieces, and simmer gently for 12 to 15 minutes until the chicken is tender and the sauce is velvety.","Taste for salt, spoon over the rice, and scatter with cilantro — the sauce should be fragrant and warming, never sharp."],"tip":"The honey is not cheating, it is diplomacy — a teaspoon buys the spices safe passage past small skeptics."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_pork_sweet_potato_sheet_pan', '{"id":"maple_pork_sweet_potato_sheet_pan","name":"Maple-Glazed Pork and Sweet Potato Sheet Pan","emoji":"🍁","cuisine":"American","meal":["dinner"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"pork_loin","q":350},{"f":"sweet_potatoes","q":400},{"f":"green_beans","q":200},{"f":"maple_syrup","q":30},{"f":"olive_oil","q":20},{"f":"garlic","q":0.2},{"f":"paprika","q":3},{"f":"cinnamon","q":1},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Heat the oven to 200C and cube the sweet potatoes into even, dice-size pieces so they cook at the same pace.","Toss the sweet potatoes with half the olive oil, the paprika, cinnamon, and a pinch of salt, spread them on a sheet pan, and give them a 15-minute head start until the edges begin to caramelize.","Season the pork loin all over with salt and pepper, whisk the maple syrup with the remaining oil and grated garlic, and brush the pork generously.","Push the potatoes aside, add the pork and the green beans, and roast 18 to 20 minutes, brushing once more with glaze, until the pork reads 63C at its thickest point.","Rest the pork for 5 minutes under foil — the juices redistribute and the glaze sets to a lacquered sheen — then slice thin against the grain."],"tip":"That 5-minute rest is not optional; carve early and you will watch your juiciness run onto the cutting board."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('mini_greek_beef_meatball_pitas', '{"id":"mini_greek_beef_meatball_pitas","name":"Mini Greek Beef Meatball Pitas with Quick Tzatziki","emoji":"🥙","cuisine":"Mediterranean","meal":["dinner"],"diets":["high-protein"],"allergens":["gluten","dairy"],"time":35,"servings":2,"ing":[{"f":"ground_beef","q":250},{"f":"pita","q":2},{"f":"greek_yogurt","q":100},{"f":"cucumber","q":0.5},{"f":"garlic","q":0.2},{"f":"oregano","q":3},{"f":"cumin","q":2},{"f":"onion","q":0.3},{"f":"tomato","q":1},{"f":"romaine","q":0.2},{"f":"lemon","q":0.5},{"f":"olive_oil","q":10},{"f":"salt","q":4},{"f":"black_pepper","q":1}],"steps":["Grate the onion straight into the beef — grating, not chopping, keeps the meatballs juicy — and knead in half the grated garlic, the oregano, cumin, salt, and pepper.","Roll the mixture into walnut-size meatballs and let them sit 5 minutes so the seasoning settles in.","Meanwhile, grate the cucumber, squeeze it hard in your fist to wring out the water, and stir it into the yogurt with the remaining grated garlic, lemon juice, and a pinch of salt.","Sear the meatballs in olive oil over medium-high heat, turning until deeply browned on all sides and cooked through, about 8 minutes; they should smell like a street-corner grill.","Warm the pitas until soft and puffed, then stuff them with shredded romaine, diced tomato, meatballs, and generous spoonfuls of tzatziki."],"tip":"Squeeze the cucumber like it owes you money, or your tzatziki becomes soup by dinnertime."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tortilla_pizza_night', '{"id":"tortilla_pizza_night","name":"Crispy Tortilla Pizza Night","emoji":"🍕","cuisine":"American","meal":["dinner"],"diets":["vegetarian"],"allergens":["dairy","gluten"],"time":20,"servings":2,"ing":[{"f":"tortillas","q":3},{"f":"crushed_tomatoes","q":150},{"f":"mozzarella","q":120},{"f":"parmesan","q":15},{"f":"bell_pepper","q":0.5},{"f":"mushrooms","q":80},{"f":"olives","q":30},{"f":"garlic","q":0.1},{"f":"oregano","q":2},{"f":"basil","q":0.3},{"f":"olive_oil","q":10},{"f":"salt","q":2}],"steps":["Heat the oven to 230C and bake the bare tortillas on a sheet pan for 3 minutes so they crisp into sturdy, cracker-thin crusts.","Stir the crushed tomatoes with grated garlic, oregano, olive oil, and a pinch of salt, then spread a thin layer on each tortilla — go light, or the crust surrenders.","Scatter on the mozzarella, then let everyone rig their own with sliced bell pepper, thin mushrooms, and olive rounds.","Bake 6 to 8 minutes until the cheese bubbles and blisters and the tortilla edges turn deep brown and crackly.","Shave parmesan over the top, tear on the basil, and cut into wedges while the cheese still stretches."],"tip":"Sauce is where tortilla pizzas go to die — one thin smear keeps the crust crisp and the critics quiet."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('warm_peanut_noodles_edamame', '{"id":"warm_peanut_noodles_edamame","name":"Warm Peanut Butter Noodles with Edamame","emoji":"🥜","cuisine":"Asian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["nuts","soy","gluten","sesame"],"time":25,"servings":2,"ing":[{"f":"spaghetti","q":160},{"f":"peanut_butter","q":50},{"f":"soy_sauce","q":30},{"f":"maple_syrup","q":15},{"f":"sesame_oil","q":10},{"f":"lime","q":1},{"f":"garlic","q":0.2},{"f":"ginger","q":8},{"f":"edamame_frozen","q":150},{"f":"carrots","q":100},{"f":"cucumber","q":0.5},{"f":"scallions","q":0.5}],"steps":["Boil the spaghetti in salted water, dropping the edamame into the pot for the final 2 minutes so both finish together.","While it cooks, whisk the peanut butter, soy sauce, maple syrup, sesame oil, lime juice, grated garlic, and grated ginger in a large bowl until smooth.","Thin the sauce with hot pasta water, a spoonful at a time, until it pours like heavy cream — it will seize and look broken first, then come back silky if you keep whisking.","Drain the noodles and edamame, tumble them into the bowl with the coarsely grated carrot, and toss until every strand is slicked and glossy.","Top with thin cucumber half-moons and sliced scallions and serve warm, when the sauce clings best."],"tip":"When the sauce turns to cement mid-whisk, do not panic — one more splash of hot pasta water and it forgives you."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_tuna_potato_cakes', '{"id":"crispy_tuna_potato_cakes","name":"Crispy Tuna Potato Cakes","emoji":"🐟","cuisine":"American","meal":["dinner","lunch"],"diets":["dairy-free","high-protein"],"allergens":["fish","eggs","gluten"],"time":40,"servings":2,"ing":[{"f":"potatoes","q":450},{"f":"tuna_canned","q":200},{"f":"eggs","q":1},{"f":"flour","q":30},{"f":"scallions","q":0.5},{"f":"parsley","q":0.3},{"f":"lemon","q":0.5},{"f":"olive_oil","q":30},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Peel and chunk the potatoes, then boil them in well-salted water for 12 to 15 minutes until a fork slides in with no resistance.","Drain thoroughly and mash while still steaming, then let the mash cool for 5 minutes so it doesn''t scramble the egg.","Fold in the drained tuna, beaten egg, sliced scallions, chopped parsley, salt, and pepper until the mixture just holds together when squeezed.","Shape into six thick patties, dust each side lightly with flour, and chill them for 10 minutes to firm up.","Heat the olive oil in a heavy skillet over medium heat until it shimmers, then fry the cakes 4 minutes per side until deeply golden and crackly at the edges.","Squeeze the lemon over the hot cakes just before serving so the juice sizzles into the crust."],"tip":"Wet your hands before shaping the patties, or you will end up wearing more tuna mash than you fry."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_nicoise_potato_salad_2', '{"id":"tuna_nicoise_potato_salad_2","name":"Tuna Nicoise Potato Salad","emoji":"🥗","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["gluten-free","dairy-free","high-protein"],"allergens":["fish","eggs"],"time":35,"servings":2,"ing":[{"f":"potatoes","q":400},{"f":"green_beans","q":200},{"f":"eggs","q":2},{"f":"tuna_canned","q":160},{"f":"cherry_tomatoes","q":150},{"f":"olives","q":40},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"oregano","q":1},{"f":"salt","q":3},{"f":"black_pepper","q":2}],"steps":["Cut the potatoes into bite-size chunks and simmer them in salted water for 10 minutes, then drop the green beans into the same pot for the final 3 minutes until both are just tender.","Meanwhile, lower the eggs into boiling water for exactly 8 minutes, then shock them in ice water so the yolks stay fudgy at the center.","Whisk the lemon juice with the olive oil, oregano, salt, and plenty of black pepper until the dressing looks cloudy and thick.","Toss the warm potatoes and beans with half the dressing so they drink it in while they cool.","Arrange the vegetables on plates with halved cherry tomatoes, olives, flaked tuna, and quartered eggs, then spoon the remaining dressing over everything."],"tip":"Dress the potatoes while they are still warm; cold potatoes are stubborn and refuse to absorb anything."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuna_cabbage_fried_rice', '{"id":"tuna_cabbage_fried_rice","name":"Tuna and Cabbage Fried Rice","emoji":"🍚","cuisine":"Asian","meal":["dinner"],"diets":["dairy-free","high-protein"],"allergens":["fish","eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"rice","q":150},{"f":"cabbage","q":0.3},{"f":"tuna_canned","q":140},{"f":"eggs","q":2},{"f":"peas_frozen","q":100},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"scallions","q":1},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":10},{"f":"olive_oil","q":15}],"steps":["Cook the rice, spread it on a plate, and let it cool completely so the grains dry out and separate; day-old rice is even better.","Heat the olive oil in your largest skillet over high heat until it just smokes, then scramble the eggs for 30 seconds until barely set and push them to one side.","Add the shredded cabbage, minced garlic, and grated ginger and stir-fry for 3 to 4 minutes until the cabbage chars lightly at the edges but keeps some crunch.","Tumble in the rice and press it flat against the pan, letting it sizzle undisturbed for a full minute to build crispy bottom bits.","Fold in the drained tuna, peas, and soy sauce, tossing until everything is glossy and steaming, about 2 minutes more.","Kill the heat, drizzle with sesame oil, and shower with sliced scallions before serving straight from the pan."],"tip":"Resist the urge to stir constantly; fried rice earns its name from sitting still in a screaming-hot pan."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gingery_egg_drop_cabbage_soup', '{"id":"gingery_egg_drop_cabbage_soup","name":"Gingery Egg Drop Cabbage Soup","emoji":"🍜","cuisine":"Asian","meal":["dinner","lunch"],"diets":["dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":25,"servings":4,"ing":[{"f":"broth","q":1500},{"f":"cabbage","q":0.4},{"f":"eggs","q":5},{"f":"rice_noodles","q":200},{"f":"mushrooms","q":150},{"f":"ginger","q":15},{"f":"garlic","q":0.2},{"f":"scallions","q":1},{"f":"soy_sauce","q":20},{"f":"sesame_oil","q":15},{"f":"black_pepper","q":2}],"steps":["Bring the broth to a simmer with the sliced ginger and smashed garlic, and let it steep for 5 minutes until the kitchen smells sharp and warm.","Add the sliced mushrooms and shredded cabbage and simmer for 5 to 6 minutes until the cabbage turns silky but not slumped.","Stir in the rice noodles and soy sauce and cook for 3 to 4 minutes until the noodles are tender and slippery.","Beat the eggs well, then pour them into the pot in a thin stream while stirring the soup slowly in one direction so long golden ribbons form.","Turn off the heat the moment the egg sets, then season generously with black pepper and finish with sesame oil and sliced scallions."],"tip":"Stir slowly when the eggs go in; frantic whisking gets you cloudy soup instead of those pretty silk ribbons."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('okonomiyaki_style_cabbage_pancakes', '{"id":"okonomiyaki_style_cabbage_pancakes","name":"Okonomiyaki-Style Cabbage Pancakes","emoji":"🥞","cuisine":"Asian","meal":["dinner"],"diets":["vegetarian","dairy-free"],"allergens":["eggs","gluten","soy","sesame"],"time":30,"servings":2,"ing":[{"f":"cabbage","q":0.5},{"f":"eggs","q":3},{"f":"flour","q":100},{"f":"scallions","q":1},{"f":"soy_sauce","q":20},{"f":"honey","q":10},{"f":"sesame_oil","q":5},{"f":"olive_oil","q":30},{"f":"salt","q":3}],"steps":["Shred the cabbage as finely as you can manage, then toss it with the salt in a big bowl and let it sit for 10 minutes to soften and release a little water.","Whisk the eggs with the flour and 60 milliliters of water until you have a thick, smooth batter with no dry pockets.","Fold the cabbage and most of the sliced scallions into the batter; it should look like far too much cabbage held together by far too little batter, which is exactly right.","Heat half the olive oil in a nonstick skillet over medium heat, add half the mixture, and press it into a thick 2-centimeter cake.","Cook 5 to 6 minutes per side until deeply browned and crisp, pressing occasionally with a spatula, then repeat with the second pancake.","Stir the soy sauce, honey, and sesame oil together and drizzle this glossy sauce over the hot pancakes with the reserved scallions."],"tip":"Flip with confidence and one decisive motion; a hesitant flip is how cabbage pancakes become cabbage scramble."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('spanish_potato_onion_tortilla_2', '{"id":"spanish_potato_onion_tortilla_2","name":"Spanish Potato and Onion Tortilla","emoji":"🍳","cuisine":"Mediterranean","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"potatoes","q":450},{"f":"eggs","q":6},{"f":"onion","q":1},{"f":"olive_oil","q":45},{"f":"parsley","q":0.3},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Slice the potatoes into thin half-moons and the onion into slivers, then cook them gently in the olive oil in a nonstick skillet over medium-low heat for 15 to 18 minutes, stirring now and then, until tender but not browned.","Beat the eggs with the salt and pepper in a large bowl, then tip in the warm potatoes and onions and let them soak for 5 minutes so every slice gets coated.","Pour off all but a slick of oil from the skillet, return it to medium heat, and add the egg mixture, shaking the pan gently as the edges begin to set.","Cook for 4 to 5 minutes until the bottom is golden and the top is still wobbly, then place a large plate over the pan and flip the whole thing in one brave motion.","Slide the tortilla back into the pan and cook 3 minutes more, until the center is just set but still slightly creamy inside.","Rest it for 5 minutes, then scatter with chopped parsley and cut into fat wedges."],"tip":"A slightly runny center is the sign of a proper tortilla, not an undercooked one, so stop cooking sooner than your nerves suggest."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('colcannon_with_fried_eggs', '{"id":"colcannon_with_fried_eggs","name":"Colcannon with Crispy Fried Eggs","emoji":"🥔","cuisine":"American","meal":["dinner"],"diets":["vegetarian","gluten-free"],"allergens":["dairy","eggs"],"time":35,"servings":2,"ing":[{"f":"potatoes","q":600},{"f":"cabbage","q":0.4},{"f":"butter","q":40},{"f":"milk","q":100},{"f":"eggs","q":4},{"f":"scallions","q":1},{"f":"olive_oil","q":10},{"f":"salt","q":4},{"f":"black_pepper","q":2}],"steps":["Boil the peeled, chunked potatoes in salted water for 15 minutes until completely tender, then drain and let them steam dry in the colander for 2 minutes.","While the potatoes cook, melt half the butter in a wide pan and cook the shredded cabbage with a pinch of salt over medium heat for 6 to 8 minutes until sweet, tender, and browning at the edges.","Warm the milk with the remaining butter, then mash it into the potatoes until fluffy, seasoning boldly with salt and pepper.","Fold the cabbage and most of the sliced scallions through the mash and keep it warm.","Heat the olive oil in a skillet over medium-high until it ripples, crack in the eggs, and fry 2 to 3 minutes until the whites are crisp and lacy at the edges but the yolks still tremble.","Pile the colcannon into bowls, top each with fried eggs, and finish with the last of the scallions and a grind of pepper."],"tip":"The broken yolk is the sauce here, so aggressively runny eggs are not optional."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('tuscan_cabbage_white_bean_stew', '{"id":"tuscan_cabbage_white_bean_stew","name":"Tuscan Cabbage and White Bean Stew","emoji":"🍲","cuisine":"Italian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"white_beans","q":500},{"f":"cabbage","q":0.5},{"f":"potatoes","q":300},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"carrots","q":150},{"f":"celery","q":100},{"f":"garlic","q":0.4},{"f":"olive_oil","q":45},{"f":"oregano","q":2},{"f":"salt","q":5},{"f":"black_pepper","q":2}],"steps":["Warm the olive oil in a heavy pot over medium heat and cook the diced onion, carrots, and celery with a pinch of salt for 8 minutes until soft and fragrant.","Stir in the sliced garlic and oregano and cook for 1 minute more, just until the garlic smells toasty rather than raw.","Add the crushed tomatoes, diced potatoes, and 750 milliliters of water, bring to a lively simmer, and cook for 10 minutes.","Pile in the chopped cabbage; it will look like too much, but press it down and let it collapse into the broth over the next 10 minutes.","Add the white beans and simmer gently for 10 minutes more, mashing a spoonful of beans against the side of the pot to thicken the broth to a velvety body.","Season generously with salt and black pepper, and rest the stew off the heat for 5 minutes before ladling into bowls."],"tip":"This stew is one of those dishes that tastes noticeably better tomorrow, so make peace with leftovers."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('crispy_potato_black_bean_tacos', '{"id":"crispy_potato_black_bean_tacos","name":"Crispy Potato and Black Bean Tacos","emoji":"🌮","cuisine":"Mexican","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["gluten"],"time":35,"servings":2,"ing":[{"f":"potatoes","q":350},{"f":"black_beans","q":250},{"f":"tortillas","q":4},{"f":"salsa","q":120},{"f":"avocado","q":0.5},{"f":"lime","q":1},{"f":"cilantro","q":0.3},{"f":"olive_oil","q":20},{"f":"cumin","q":3},{"f":"chili_powder","q":4},{"f":"salt","q":4}],"steps":["Dice the potatoes into small 1-centimeter cubes, toss them with the olive oil, cumin, chili powder, and salt, and roast at 220C for 25 minutes, flipping once, until crusty and golden on all sides.","While the potatoes roast, warm the black beans in a small pan with a splash of water and a squeeze of lime, mashing about half of them into a rough, creamy base.","Char the tortillas directly over a gas flame or in a dry skillet for 30 seconds per side until blistered and pliable.","Spread each tortilla with the mashed beans, then pile on the crispy potatoes while they are still crackling hot.","Top with salsa, sliced avocado, torn cilantro, and a final squeeze of lime, and eat immediately while the contrast of crisp and creamy is at its peak."],"tip":"Crowd the potatoes on the baking sheet and they will steam into sadness; give every cube its personal space."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_black_bean_lime_soup', '{"id":"smoky_black_bean_lime_soup","name":"Smoky Black Bean Lime Soup","emoji":"🫘","cuisine":"Mexican","meal":["dinner","lunch"],"diets":["vegetarian","gluten-free"],"allergens":["dairy"],"time":40,"servings":4,"ing":[{"f":"black_beans","q":800},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"bell_pepper","q":1},{"f":"carrots","q":100},{"f":"crushed_tomatoes","q":200},{"f":"cumin","q":5},{"f":"chili_powder","q":6},{"f":"paprika","q":4},{"f":"olive_oil","q":45},{"f":"lime","q":1},{"f":"cilantro","q":0.5},{"f":"sour_cream","q":100},{"f":"salt","q":5}],"steps":["Heat the olive oil in a soup pot over medium heat and sweat the diced onion, bell pepper, and carrots with a pinch of salt for 7 to 8 minutes until softened and sweet.","Add the minced garlic, cumin, chili powder, and paprika and toast for 1 minute, stirring constantly, until the spices darken and bloom in the oil.","Stir in the black beans, crushed tomatoes, and 900 milliliters of water, then simmer uncovered for 20 minutes so the flavors knit together.","Blend about a third of the soup right in the pot with an immersion blender, or mash vigorously with a potato masher, until the broth turns thick and inky while plenty of whole beans remain.","Season with salt and the juice of the lime, tasting until the soup goes from flat to bright.","Ladle into bowls and finish each with a swirl of sour cream and a flurry of chopped cilantro."],"tip":"The lime at the end is doing salt''s job in disguise, so do not skip it even if you think the soup tastes done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('gingery_cabbage_chickpea_skillet', '{"id":"gingery_cabbage_chickpea_skillet","name":"Gingery Cabbage and Chickpea Skillet","emoji":"🥘","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":30,"servings":2,"ing":[{"f":"chickpeas","q":300},{"f":"cabbage","q":0.4},{"f":"rice","q":130},{"f":"onion","q":1},{"f":"tomato","q":2},{"f":"garlic","q":0.3},{"f":"ginger","q":10},{"f":"turmeric","q":2},{"f":"cumin","q":4},{"f":"garam_masala","q":3},{"f":"olive_oil","q":30},{"f":"lemon","q":0.5},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Start the rice cooking so it finishes as the skillet does, about 15 minutes of gentle simmering under a tight lid.","Heat the olive oil in a wide skillet over medium-high heat and sizzle the cumin for 30 seconds until it crackles and smells nutty.","Add the sliced onion and cook 5 minutes until golden at the edges, then stir in the garlic, grated ginger, and turmeric for 1 fragrant minute.","Add the chopped tomatoes and cook them down for 3 to 4 minutes until they slump into a jammy base that pulls away from the pan.","Tumble in the shredded cabbage and chickpeas with the salt, toss to coat, and cook for 8 to 10 minutes until the cabbage is tender-crisp and stained golden.","Finish with garam masala, a big squeeze of lemon, and chopped cilantro, then serve heaped over the steaming rice."],"tip":"Let the cabbage catch a little on the pan bottom; those browned wisps are where the flavor lives."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('coconut_lentil_potato_curry', '{"id":"coconut_lentil_potato_curry","name":"Coconut Lentil and Potato Curry","emoji":"🍛","cuisine":"Indian","meal":["dinner"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":250},{"f":"potatoes","q":400},{"f":"coconut_milk","q":400},{"f":"crushed_tomatoes","q":200},{"f":"spinach","q":100},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"curry_powder","q":8},{"f":"turmeric","q":2},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"salt","q":5}],"steps":["Warm the olive oil in a large pot over medium heat and cook the diced onion for 6 minutes until translucent and lightly golden.","Add the minced garlic, grated ginger, curry powder, and turmeric and stir for 1 minute until the spices coat the onion in a fragrant paste.","Stir in the rinsed lentils, diced potatoes, crushed tomatoes, and 800 milliliters of water, then simmer with the lid ajar for 25 minutes, stirring occasionally so nothing sticks.","When the lentils are collapsing and the potatoes yield easily to a spoon, pour in the coconut milk and simmer 5 minutes more until the curry turns thick and golden.","Wilt in the spinach off the heat, then season with salt and the juice of the lime until the richness snaps into focus.","Rest for 5 minutes before serving; the curry thickens to a spoon-coating body as it sits."],"tip":"If the curry looks too loose at minute 25, walk away for five more; lentils thicken on their own schedule, not yours."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('punjabi_style_egg_curry_2', '{"id":"punjabi_style_egg_curry_2","name":"Punjabi-Style Egg Curry","emoji":"🥚","cuisine":"Indian","meal":["dinner"],"diets":["vegetarian","gluten-free","dairy-free"],"allergens":["eggs"],"time":40,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"rice","q":140},{"f":"onion","q":1},{"f":"tomato","q":3},{"f":"garlic","q":0.4},{"f":"ginger","q":15},{"f":"cumin","q":3},{"f":"turmeric","q":2},{"f":"chili_powder","q":2},{"f":"garam_masala","q":4},{"f":"olive_oil","q":30},{"f":"cilantro","q":0.3},{"f":"salt","q":4}],"steps":["Boil the eggs for 9 minutes, cool them in ice water, peel, and set aside; start the rice simmering now so it lands with the curry.","Heat the olive oil in a deep skillet over medium heat and fry the finely chopped onion for 8 to 10 minutes, stirring often, until it turns a deep amber brown; this patience is the backbone of the gravy.","Add the minced garlic, grated ginger, cumin, turmeric, and chili powder and cook for 1 minute until the raw edge burns off.","Stir in the chopped tomatoes with the salt and cook 6 to 8 minutes, mashing as they soften, until the oil separates and pools at the edges of a thick masala.","Pour in 250 milliliters of water, simmer for 5 minutes, then nestle in the halved eggs yolk-side up and spoon gravy over them for 2 minutes to warm through.","Dust with garam masala, scatter with cilantro, and serve over the rice."],"tip":"The gravy is done when the oil visibly breaks away from the tomatoes; stop early and the curry tastes like hurried ketchup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chicken_burrito_bowl_meal_prep', '{"id":"chicken_burrito_bowl_meal_prep","name":"Lime-Charred Chicken Burrito Bowls","emoji":"🍗","cuisine":"Mexican","meal":["lunch"],"diets":["high-protein","gluten-free"],"allergens":["dairy"],"time":35,"servings":2,"ing":[{"f":"chicken_breast","q":2},{"f":"rice","q":140},{"f":"black_beans","q":240},{"f":"bell_pepper","q":1},{"f":"onion","q":1},{"f":"olive_oil","q":20},{"f":"lime","q":1},{"f":"cheddar","q":40}],"steps":["Simmer the rice in a covered pot over low heat for 15 minutes, then let it steam off the heat for 5 more so the grains turn fluffy, not gummy.","Meanwhile, pat the chicken breasts dry, season generously with salt, cumin, and chili powder, and sear in half the olive oil over medium-high heat for 6 to 7 minutes per side until deeply browned and cooked to 165F at the thickest point.","Rest the chicken 5 minutes, then slice against the grain; while it rests, char the sliced pepper and onion in the same skillet until their edges blacken and they smell sweet, about 5 minutes.","Warm the black beans with a splash of water and a pinch of salt, mashing a few against the pan for a creamier texture.","Divide rice, beans, chicken, and peppers between two containers, squeeze lime juice over everything while it is still warm, and scatter the cheddar in a corner so it stays distinct.","Cool uncovered for 20 minutes before lidding to keep condensation from turning the rice soggy."],"tip":"Squeeze the lime on day one but save the cheese-melting microwave blast for day four — acid keeps, texture doesn''t."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('sesame_tofu_rice_noodle_jars', '{"id":"sesame_tofu_rice_noodle_jars","name":"Sesame-Glazed Tofu Noodle Jars","emoji":"🥢","cuisine":"Asian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"tofu","q":400},{"f":"rice_noodles","q":150},{"f":"broccoli","q":300},{"f":"carrots","q":150},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":20},{"f":"maple_syrup","q":15},{"f":"garlic","q":0.2},{"f":"lime","q":1}],"steps":["Press the tofu between paper towels under a heavy skillet for 10 minutes, then cut into 2-centimeter cubes and sear in a dry nonstick pan over medium-high heat until every side is golden and crackly, about 8 minutes total.","Whisk the soy sauce, maple syrup, half the sesame oil, grated garlic, and the juice of the lime into a glossy dressing, then pour a third of it over the hot tofu and toss until it clings like lacquer.","Soak the rice noodles in just-boiled water for 6 to 8 minutes until pliable but still springy, then rinse under cold water and toss with the remaining sesame oil to prevent clumping.","Blanch the broccoli florets in salted boiling water for 90 seconds until bright green, then shock in cold water and drain thoroughly.","Layer each container with noodles, shredded carrots, broccoli, and tofu, and pack the remaining dressing in small cups on the side.","Dress each jar the morning you eat it so the noodles slurp instead of sulk."],"tip":"A dry pan and patience brown tofu better than a puddle of oil ever will."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('chickpea_couscous_tabbouleh_bowls', '{"id":"chickpea_couscous_tabbouleh_bowls","name":"Herbed Chickpea Couscous Bowls","emoji":"🥗","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegetarian"],"allergens":["gluten","dairy"],"time":25,"servings":2,"ing":[{"f":"couscous","q":140},{"f":"chickpeas","q":240},{"f":"cucumber","q":1},{"f":"tomato","q":2},{"f":"feta","q":80},{"f":"olive_oil","q":30},{"f":"lemon","q":1},{"f":"onion","q":0.5}],"steps":["Pour boiling salted water over the couscous in a bowl, cover with a plate, and let it steam for 5 minutes before fluffing with a fork until every grain separates.","While it steams, dice the cucumber and tomatoes small, mince the half onion, and soak the onion in the lemon juice for 5 minutes to tame its bite.","Toast the drained chickpeas in the olive oil over medium heat for 6 to 8 minutes, shaking the pan until they blister and pop like tiny drums.","Toss the couscous with the vegetables, lemony onion, warm chickpeas, and a generous pinch of dried oregano and black pepper, tasting for salt as feta will add more.","Divide between containers and crumble the feta over the top in big craggy chunks rather than stirring it through.","Chill fully before sealing; the flavors deepen by day two like a good marinade should."],"tip":"Salt the tomatoes and let them drain in a sieve for 5 minutes, or day three''s lunch will be couscous soup."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_tuna_chickpea_crunch_salad', '{"id":"lemon_tuna_chickpea_crunch_salad","name":"Lemon Tuna and Chickpea Crunch Salad","emoji":"🐟","cuisine":"American","meal":["lunch"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["fish"],"time":15,"servings":2,"ing":[{"f":"tuna_canned","q":2},{"f":"chickpeas","q":240},{"f":"cucumber","q":1},{"f":"onion","q":0.5},{"f":"spinach","q":80},{"f":"olive_oil","q":30},{"f":"lemon","q":1}],"steps":["Drain the tuna well and flake it into a large bowl in chunky pieces rather than shredding it to paste.","Rinse the chickpeas until the water runs clear, shake them dry, and lightly crush a quarter of them with a fork so they soak up dressing like sponges.","Dice the cucumber, slice the half onion paper-thin, and whisk the olive oil with the lemon juice, a pinch of salt, and plenty of cracked black pepper.","Fold the tuna, chickpeas, cucumber, and onion together with the dressing until everything glistens.","Pack the spinach in the bottom of each container and pile the tuna mixture on top so the leaves stay crisp until you shake it all together at your desk.","Refrigerate up to four days; the flavor peaks around day two when the onion mellows."],"tip":"Buy tuna packed in oil, not water — flavor insurance costs about fifty cents a can."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('smoky_turkey_black_bean_chili', '{"id":"smoky_turkey_black_bean_chili","name":"Smoky Turkey and Black Bean Chili","emoji":"🌶️","cuisine":"American","meal":["lunch"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":[],"time":50,"servings":4,"ing":[{"f":"ground_turkey","q":500},{"f":"black_beans","q":480},{"f":"crushed_tomatoes","q":500},{"f":"onion","q":1},{"f":"bell_pepper","q":1},{"f":"garlic","q":0.4},{"f":"broth","q":500},{"f":"olive_oil","q":15}],"steps":["Heat the olive oil in a heavy pot over medium-high heat and brown the ground turkey hard for 6 to 8 minutes, leaving it undisturbed in patches so it develops crusty, savory edges.","Add the diced onion, bell pepper, and garlic and cook until the onion turns translucent and the bottom of the pot collects a brown film, about 5 minutes.","Stir in a heaping tablespoon of chili powder, a teaspoon of paprika, and a teaspoon of cumin, toasting the spices for 30 seconds until they smell like a campfire.","Add the crushed tomatoes, drained black beans, and broth, scraping up every browned bit, then simmer uncovered for 25 to 30 minutes until the chili thickens enough to mound on a spoon.","Season with salt and a splash of anything acidic you have on hand, then ladle into four containers and cool before sealing.","Reheat gently with a spoonful of water, as the chili tightens up in the fridge like a fist."],"tip":"Chili is the rare coworker that actually improves after three days in the office fridge."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemon_salmon_quinoa_power_bowls', '{"id":"lemon_salmon_quinoa_power_bowls","name":"Lemon-Roasted Salmon Quinoa Bowls","emoji":"🍋","cuisine":"Mediterranean","meal":["lunch"],"diets":["high-protein","gluten-free","dairy-free"],"allergens":["fish"],"time":35,"servings":2,"ing":[{"f":"salmon","q":340},{"f":"quinoa","q":150},{"f":"spinach","q":150},{"f":"cucumber","q":1},{"f":"olive_oil","q":30},{"f":"lemon","q":1}],"steps":["Rinse the quinoa in a fine sieve until the water runs clear, then simmer it in double its volume of salted water for 15 minutes and rest it covered for 5 so it uncoils into little spirals.","Heat the oven to 220C, rub the salmon with half the olive oil, salt, pepper, and the zest of the lemon, and roast for 10 to 12 minutes until it flakes at the nudge of a fork but still looks blushing in the center.","Wilt the spinach in a hot pan with a teaspoon of oil for 60 seconds, just until it collapses and turns glossy, then squeeze out the excess liquid.","Dice the cucumber and whisk the remaining oil with the lemon''s juice and a pinch of salt for a bright dressing.","Fluff the quinoa into two containers, top with spinach, cucumber, and big flakes of salmon, and drizzle the dressing over everything.","Eat cold or barely warmed; blasting salmon in a microwave is how office feuds begin."],"tip":"Pull the salmon at 50C in the center — carryover heat finishes the job and the fridge forgives nothing overcooked."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('shrimp_edamame_fried_rice', '{"id":"shrimp_edamame_fried_rice","name":"Shrimp and Edamame Fried Rice Boxes","emoji":"🍤","cuisine":"Asian","meal":["lunch"],"diets":["high-protein","dairy-free"],"allergens":["shellfish","eggs","soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"shrimp","q":300},{"f":"rice","q":160},{"f":"eggs","q":2},{"f":"edamame_frozen","q":150},{"f":"carrots","q":100},{"f":"garlic","q":0.3},{"f":"soy_sauce","q":30},{"f":"sesame_oil","q":15}],"steps":["Cook the rice, spread it on a tray, and chill it for at least 20 minutes so the grains firm up and fry instead of steam.","Sear the shrimp in a screaming-hot wok with a third of the sesame oil for about 90 seconds per side until they curl into loose commas and turn pink, then set them aside.","Scramble the eggs in the same wok until just set into soft curds, push them to one side, and stir-fry the diced carrots, edamame, and minced garlic for 2 minutes until fragrant.","Add the cold rice, pressing it against the hot metal in a thin layer and letting it sizzle for a full minute before tossing, repeating until you hear steady crackling.","Return the shrimp, pour the soy sauce and remaining sesame oil around the rim of the wok so they toast on contact, and toss everything for a final minute.","Cool quickly in shallow containers and refrigerate; the rice reheats to nearly wok-fresh with a 90-second microwave blast."],"tip":"Yesterday''s rice makes today''s fried rice — freshly cooked grains just steam themselves into mush."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('garden_parmesan_frittata_squares', '{"id":"garden_parmesan_frittata_squares","name":"Garden Parmesan Frittata Squares","emoji":"🍳","cuisine":"Italian","meal":["lunch"],"diets":["vegetarian","gluten-free","low-carb","high-protein"],"allergens":["eggs","dairy"],"time":30,"servings":2,"ing":[{"f":"eggs","q":6},{"f":"spinach","q":100},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"parmesan","q":40},{"f":"olive_oil","q":15}],"steps":["Heat the oven to 190C and warm the olive oil in an ovenproof skillet over medium heat.","Soften the diced bell pepper and onion for 5 minutes until sweet and just golden at the edges, then add the spinach and stir until it wilts and its water cooks off completely.","Whisk the eggs with half the parmesan, a good pinch of salt, and black pepper until uniformly pale yellow, then pour them over the vegetables and drag a spatula through twice to distribute everything.","Cook undisturbed on the stove for 3 minutes until the edges set, then scatter the remaining parmesan on top and transfer to the oven for 10 to 12 minutes until the center is puffed and barely jiggles.","Cool in the pan for 10 minutes, cut into squares, and pack two per container with a handful of anything green you have left over.","Eat cold, at room temperature, or gently rewarmed; frittata is agreeable like that for four solid days."],"tip":"Pull it while the middle still wobbles slightly — residual heat sets it, and rubbery eggs have no fridge redemption arc."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('weeknight_chana_masala_rice', '{"id":"weeknight_chana_masala_rice","name":"Weeknight Chana Masala with Rice","emoji":"🍛","cuisine":"Indian","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":35,"servings":2,"ing":[{"f":"chickpeas","q":400},{"f":"crushed_tomatoes","q":400},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"rice","q":150},{"f":"olive_oil","q":20},{"f":"lemon","q":0.5}],"steps":["Start the rice simmering in salted water so it finishes just as the curry does.","Cook the finely diced onion in the oil over medium heat for a patient 8 to 10 minutes until it turns deep amber, because pale onions make a flat masala.","Add the minced garlic with a tablespoon of curry powder, a teaspoon of cumin, and a pinch of cayenne, frying for 45 seconds until the spices darken a shade and bloom fragrantly in the oil.","Stir in the crushed tomatoes and simmer for 8 minutes, stirring until the sauce thickens and the oil separates at the edges in glossy pools.","Add the drained chickpeas with a splash of water, mash a spoonful against the pot to thicken, and simmer 10 minutes more before finishing with salt and the lemon''s juice.","Pack over rice and refrigerate; day three of this curry tastes like it hired a better chef overnight."],"tip":"The oil pooling at the edges is not a mistake — it is the masala announcing it is done."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('beef_and_broccoli_rice_boxes', '{"id":"beef_and_broccoli_rice_boxes","name":"Honey-Garlic Beef and Broccoli Boxes","emoji":"🥦","cuisine":"Asian","meal":["lunch"],"diets":["high-protein","dairy-free"],"allergens":["soy","gluten","sesame"],"time":30,"servings":2,"ing":[{"f":"ground_beef","q":300},{"f":"broccoli","q":400},{"f":"rice","q":150},{"f":"soy_sauce","q":45},{"f":"sesame_oil","q":15},{"f":"honey","q":20},{"f":"garlic","q":0.3}],"steps":["Get the rice simmering first, covered and on low, for 15 minutes plus a 5-minute rest.","Brown the ground beef in a dry hot skillet, breaking it into rough crumbles and letting it sit untouched for 2-minute stretches so it crisps instead of stews, about 8 minutes total.","Spoon off all but a slick of fat, add the minced garlic, and cook 30 seconds until it smells sharp and toasty.","Whisk the soy sauce and honey together, pour it over the beef, and simmer 2 minutes until the sauce reduces to a sticky glaze that coats every crumble.","Steam the broccoli florets in a covered pan with a splash of water for 3 minutes until vivid green with a slight crunch, then toss with the sesame oil and a pinch of salt.","Box the rice, beef, and broccoli in neat thirds and cool before sealing; the glaze keeps the beef juicy through day four."],"tip":"Undercook the broccoli on purpose — the microwave will finish what you started whether you like it or not."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('golden_lentil_spinach_soup', '{"id":"golden_lentil_spinach_soup","name":"Golden Lentil and Spinach Soup","emoji":"🥣","cuisine":"Mediterranean","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":45,"servings":4,"ing":[{"f":"lentils_dry","q":300},{"f":"carrots","q":200},{"f":"onion","q":1},{"f":"garlic","q":0.4},{"f":"crushed_tomatoes","q":300},{"f":"spinach","q":150},{"f":"olive_oil","q":30},{"f":"lemon","q":1}],"steps":["Sweat the diced onion and carrots in the olive oil over medium heat for 6 to 8 minutes until the onion is translucent and the carrots smell sweet.","Add the minced garlic, a tablespoon of ground turmeric and cumin, and a pinch of chili flakes, stirring for 30 seconds until the pot turns golden and fragrant.","Stir in the rinsed lentils, crushed tomatoes, and 1.2 liters of water, then bring to a boil and simmer uncovered for 25 minutes until the lentils slump and begin to break apart.","Season assertively with salt only now, as salting early keeps lentils stubbornly firm.","Stir in the spinach until it wilts into silky ribbons, then finish with the juice of the lemon to wake the whole pot up.","Portion into four containers and cool before refrigerating; the soup thickens overnight, so loosen with water when reheating."],"tip":"Lemon at the end is the difference between soup and Soup — never skip the acid."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('lemony_chicken_salad_pita_kits', '{"id":"lemony_chicken_salad_pita_kits","name":"Lemony Chicken Salad Pita Kits","emoji":"🥙","cuisine":"American","meal":["lunch"],"diets":["high-protein"],"allergens":["dairy","gluten","nuts"],"time":25,"servings":2,"ing":[{"f":"chicken_breast","q":2},{"f":"greek_yogurt","q":150},{"f":"pita","q":2},{"f":"cucumber","q":0.5},{"f":"onion","q":0.3},{"f":"walnuts","q":40},{"f":"lemon","q":1},{"f":"romaine","q":0.5}],"steps":["Poach the chicken breasts in barely simmering salted water for 12 to 14 minutes until they reach 165F, then rest them 5 minutes and shred into bite-sized pieces while still warm.","Toast the walnuts in a dry pan for 3 to 4 minutes, shaking often, until they smell rich and darken a shade, then chop roughly.","Stir the greek yogurt with the lemon''s zest and juice, a pinch of salt, and plenty of black pepper until smooth and tangy.","Fold the shredded chicken, finely diced cucumber, minced onion, and walnuts into the dressing until every piece is coated.","Pack the chicken salad in containers with the pitas and washed romaine leaves stored separately so nothing goes limp.","Assemble at lunchtime by stuffing each pita with leaves and a generous scoop of salad."],"tip":"The pita rides shotgun, never in the container — soggy bread has ended better lunches than yours."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
insert into public.recipes (id, doc, status) values ('maple_sweet_potato_black_bean_bowls', '{"id":"maple_sweet_potato_black_bean_bowls","name":"Maple-Roasted Sweet Potato and Black Bean Bowls","emoji":"🍠","cuisine":"Mexican","meal":["lunch"],"diets":["vegan","vegetarian","dairy-free","gluten-free"],"allergens":[],"time":40,"servings":2,"ing":[{"f":"sweet_potatoes","q":500},{"f":"black_beans","q":360},{"f":"quinoa","q":120},{"f":"bell_pepper","q":1},{"f":"onion","q":0.5},{"f":"olive_oil","q":30},{"f":"maple_syrup","q":15},{"f":"lime","q":1}],"steps":["Heat the oven to 220C and cut the sweet potatoes into 2-centimeter cubes so they roast through evenly.","Toss the cubes and sliced bell pepper with most of the olive oil, the maple syrup, a teaspoon of paprika, and salt, then roast on a single-layer sheet pan for 25 minutes, flipping once, until the edges caramelize to a deep bronze.","Meanwhile, simmer the rinsed quinoa in double its volume of salted water for 15 minutes, then rest it covered until its little tails uncurl.","Warm the black beans with the minced onion, the remaining oil, and a pinch of cumin, simmering with a splash of water for 5 minutes until saucy.","Layer quinoa, beans, and roasted vegetables into two containers and squeeze the lime over everything while warm so it soaks in.","Cool uncovered for 15 minutes before sealing, and eat within four days at your desk with unearned smugness."],"tip":"Crowd the sheet pan and you get steamed potatoes — give every cube its personal space and you get candy."}'::jsonb, 'approved')
  on conflict (id) do update set doc = excluded.doc, status = 'approved', updated_at = now();
